// src/app/buscar/page.tsx
'use client'

import { useState, useEffect, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import { Search, X, Users, Trophy, Film, TrendingUp } from 'lucide-react'
import { supabase } from '@/lib/supabase'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { PartidoCard } from '@/components/PartidoCard'
import { LIGAS } from '@/lib/constants'
import type { Partido, Profile, MatchLog } from '@/types'
import { MatchLogCard } from '@/components/MatchLogCard'
import { SearchSkeleton } from '@/components/SearchSkeleton'
import { FollowButton } from '@/components/FollowButton'

type SearchTab = 'partidos' | 'usuarios' | 'resenas' | 'jugadores'

const COMMON_TEAMS = [
    'River Plate', 'Boca Juniors', 'Racing Club', 'Independiente', 'San Lorenzo',
    'Talleres', 'Belgrano', 'Estudiantes', 'Gimnasia', 'Rosario Central',
    "Newell's Old Boys", 'Argentinos Juniors', 'Velez Sarsfield', 'Huracán',
    'River', 'Boca', 'Racing', 'Ciclón', 'Lanús', 'Banfield', 'Godoy Cruz', 'Unión'
]

export default function BuscarPage() {
    const router = useRouter()
    const [query, setQuery] = useState('')
    const [tab, setTab] = useState<SearchTab>('partidos')
    const [filterLiga, setFilterLiga] = useState('')
    const [partidos, setPartidos] = useState<Partido[]>([])
    const [usuarios, setUsuarios] = useState<(Profile & { logs_count?: number })[]>([])
    const [resenas, setResenas] = useState<MatchLog[]>([])
    const [jugadores, setJugadores] = useState<{
      player_name: string
      avg_rating: number
      total_ratings: number
      best_log_id?: string
    }[]>([])
    const [loading, setLoading] = useState(false)
    const [hasSearched, setHasSearched] = useState(false)
    const [showSuggestions, setShowSuggestions] = useState(false)

    const autocompleteSuggestions = (() => {
        if (!query || query.length < 2 || tab !== 'partidos') return []
        const lowerQ = query.toLowerCase()
        const ligasMatch = LIGAS.filter(l => l !== 'Todos' && l.toLowerCase().includes(lowerQ))
        const equiposMatch = COMMON_TEAMS.filter(t => t.toLowerCase().includes(lowerQ))
        return [...ligasMatch, ...equiposMatch].slice(0, 5)
    })()

    const [trendingTags, setTrendingTags] = useState<string[]>([])

    useEffect(() => {
        // Fetch real trending tags from Supabase
        const fetchTrendingTags = async () => {
            const { data, error } = await supabase
                .from('match_log_tags')
                .select('tag')

            if (data && data.length > 0) {
                // Count tag occurrences
                const tagCounts = data.reduce((acc, curr) => {
                    acc[curr.tag] = (acc[curr.tag] || 0) + 1
                    return acc
                }, {} as Record<string, number>)

                // Sort by occurrence and take top 6
                const sortedTags = Object.entries(tagCounts)
                    .sort(([, a], [, b]) => b - a)
                    .slice(0, 6)
                    .map(([tag]) => tag)

                if (sortedTags.length >= 3) {
                    setTrendingTags(sortedTags)
                } else {
                    setTrendingTags(['clasico', 'goles', 'Libertadores'])
                }
            } else {
                setTrendingTags(['clasico', 'goles', 'Libertadores'])
            }
        }
        fetchTrendingTags()
    }, [])

    const searchPartidos = useCallback(async (q: string) => {
        let queryBuilder = supabase
            .from('partidos')
            .select('*')
            .order('fecha_inicio', { ascending: false })
            .limit(20)

        if (q) {
            queryBuilder = queryBuilder.or(`equipo_local.ilike.%${q}%,equipo_visitante.ilike.%${q}%`)
        }

        if (filterLiga) {
            queryBuilder = queryBuilder.eq('liga', filterLiga)
        }

        const { data } = await queryBuilder
        setPartidos(data || [])
    }, [filterLiga])

    const searchUsuarios = useCallback(async (q: string) => {
        if (!q || q.length < 2) {
            setUsuarios([])
            return
        }

        const { data } = await supabase
            .from('profiles')
            .select('*')
            .ilike('username', `%${q}%`)
            .limit(20)

        setUsuarios(data || [])
    }, [])

    const searchResenas = useCallback(async (q: string) => {
        if (!q || q.length < 2) {
            setResenas([])
            return
        }

        const { data } = await supabase
            .from('match_logs')
            .select(`
                *,
                profile:profiles!match_logs_user_id_fkey(id, username, avatar_url),
                tags:match_log_tags(tag),
                likes_count:match_log_likes(count)
            `)
            .or(`review_text.ilike.%${q}%,review_title.ilike.%${q}%`)
            .eq('is_private', false)
            .order('created_at', { ascending: false })
            .limit(20)

        // Process data formatting tags correctly
        const processedResenas = (data || []).map((log: any) => ({
            ...log,
            tags: (log.tags || []).map((t: any) => t.tag),
            likes_count: log.likes_count?.[0]?.count || 0
        }))

        setResenas(processedResenas)
    }, [])

    const searchJugadores = useCallback(async (q: string) => {
        if (!q || q.length < 2) { setJugadores([]); return }

        const { data } = await supabase
            .from('match_log_player_ratings')
            .select('player_name, rating, match_log_id')
            .ilike('player_name', `%${q}%`)

        if (!data) return

        const playerMap = new Map<string, {
            total: number
            count: number
            best_log_id?: string
            best_rating: number
        }>()

        data.forEach((r: any) => {
            const existing = playerMap.get(r.player_name) || {
                total: 0, count: 0, best_rating: 0
            }
            existing.total += r.rating
            existing.count++
            if (r.rating > existing.best_rating) {
                existing.best_rating = r.rating
                existing.best_log_id = r.match_log_id
            }
            playerMap.set(r.player_name, existing)
        })

        const result = Array.from(playerMap.entries())
            .map(([player_name, d]) => ({
                player_name,
                avg_rating: d.total / d.count,
                total_ratings: d.count,
                best_log_id: d.best_log_id
            }))
            .sort((a, b) => b.total_ratings - a.total_ratings)
            .slice(0, 20)

        setJugadores(result)
    }, [])

    const handleSearch = useCallback(async () => {
        // Permitir búsqueda vacía si hay filtro de liga o si estamos en Partidos (para ver recientes)
        if (!query && !filterLiga && tab !== 'partidos') {
            setLoading(false)
            setHasSearched(false)
            return
        }
        setLoading(true)
        setHasSearched(true)

        if (tab === 'partidos') {
            await searchPartidos(query)
        } else if (tab === 'usuarios') {
            await searchUsuarios(query)
        } else if (tab === 'jugadores') {
            await searchJugadores(query)
        } else {
            await searchResenas(query)
        }

        setLoading(false)
    }, [query, tab, filterLiga, searchPartidos, searchUsuarios, searchResenas, searchJugadores])

    // Auto-search on tab/filter change
    useEffect(() => {
        const triggerSearch = async () => {
            if (hasSearched || filterLiga || query) {
                await handleSearch()
            }
        }
        triggerSearch()
    }, [tab, filterLiga]) // eslint-disable-line react-hooks/exhaustive-deps

    // Debounced search on query change
    useEffect(() => {
        if (!query && !filterLiga) {
            setHasSearched(false)
            setPartidos([])
            setUsuarios([])
            setResenas([])
            return
        }

        const timeout = setTimeout(() => {
            handleSearch()
        }, 400)

        return () => clearTimeout(timeout)
    }, [query]) // eslint-disable-line react-hooks/exhaustive-deps

    const tabs = [
        { id: 'partidos' as SearchTab, label: 'Partidos', icon: Trophy },
        { id: 'usuarios' as SearchTab, label: 'Usuarios', icon: Users },
        { id: 'resenas' as SearchTab, label: 'Reseñas', icon: Film },
        { id: 'jugadores' as SearchTab, label: 'Jugadores', icon: TrendingUp },
    ]

    return (
        <>
            <DesktopNav />
            <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">
                <div className="max-w-2xl mx-auto px-4 py-4">
                    {/* Search Input */}
                    <div className="relative mb-4">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" />
                        <input
                            type="text"
                            value={query}
                            onChange={(e) => {
                                setQuery(e.target.value)
                                setShowSuggestions(true)
                            }}
                            onKeyDown={(e) => {
                                if (e.key === 'Enter') {
                                    setShowSuggestions(false)
                                    handleSearch()
                                }
                            }}
                            onFocus={() => setShowSuggestions(true)}
                            onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                            placeholder={
                                tab === 'partidos' ? 'BÚSQUEDA POR EQUIPO O LIGA...' :
                                    tab === 'usuarios' ? 'BÚSQUEDA DE USUARIOS...' :
                                        'BÚSQUEDA EN RESEÑAS...'
                            }
                            autoFocus
                            className="w-full pl-10 pr-10 py-3 bg-[var(--card-bg)] border border-[var(--card-border)]
                       text-[var(--foreground)] focus:outline-none focus:border-[var(--foreground)]
                       placeholder:text-[var(--text-muted)] text-[11px] font-black capitalize tracking-widest"
                            style={{ borderRadius: 'var(--radius)' }}
                        />
                        {query && (
                            <button
                                onClick={() => { setQuery(''); setHasSearched(false); setShowSuggestions(false); }}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)] hover:text-[var(--foreground)]"
                            >
                                <X size={14} />
                            </button>
                        )}

                        {/* Autocomplete Dropdown */}
                        {showSuggestions && autocompleteSuggestions.length > 0 && (
                            <div className="absolute top-full left-0 right-0 mt-0 bg-[var(--card-bg)] border border-[var(--card-border)] z-50 overflow-hidden"
                                style={{ borderTop: 'none', borderRadius: `0 0 var(--radius) var(--radius)` }}>
                                {autocompleteSuggestions.map(sug => (
                                    <button
                                        key={sug}
                                        onClick={() => {
                                            if (LIGAS.includes(sug as any)) {
                                                setFilterLiga(sug)
                                                setQuery('')
                                            } else {
                                                setQuery(sug)
                                            }
                                            setShowSuggestions(false)
                                        }}
                                        className="w-full text-left px-4 py-2.5 text-[10px] font-black capitalize hover:bg-[var(--hover-bg)] transition-colors border-b border-[var(--card-border)] last:border-b-0 flex items-center"
                                    >
                                        <Search size={12} className="mr-3 opacity-50" />
                                        {sug}
                                    </button>
                                ))}
                            </div>
                        )}
                    </div>

                    {/* Tabs */}
                    <div className="flex border border-[var(--card-border)] bg-[var(--card-bg)] mb-4 overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                        {tabs.map((t) => (
                            <button
                                key={t.id}
                                onClick={() => setTab(t.id)}
                                className={`flex-1 py-3 text-[10px] font-black capitalize tracking-widest transition-colors ${tab === t.id
                                    ? 'bg-[var(--foreground)] text-[var(--background)]'
                                    : 'text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'
                                    }`}
                            >
                                {t.label}
                            </button>
                        ))}
                    </div>

                    {/* Liga Filter (for partidos tab) */}
                    {tab === 'partidos' && (
                        <div className="flex gap-1 overflow-x-auto no-scrollbar mb-4">
                            <button
                                onClick={() => setFilterLiga('')}
                                className={`px-3 py-2 text-[9px] font-black capitalize tracking-tighter border transition-all whitespace-nowrap ${!filterLiga
                                    ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)]'
                                    : 'bg-[var(--card-bg)] text-[var(--text-muted)] border-[var(--card-border)]'
                                    }`}
                                style={{ borderRadius: 'var(--radius)' }}
                            >
                                TODAS
                            </button>
                            {LIGAS.filter(l => l !== 'Todos').map(liga => (
                                <button
                                    key={liga}
                                    onClick={() => setFilterLiga(filterLiga === liga ? '' : liga)}
                                    className={`px-3 py-2 text-[9px] font-black capitalize tracking-tighter border transition-all whitespace-nowrap ${filterLiga === liga
                                        ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)]'
                                        : 'bg-[var(--card-bg)] text-[var(--text-muted)] border-[var(--card-border)]'
                                        }`}
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    {liga}
                                </button>
                            ))}
                        </div>
                    )}

                    {!hasSearched && !loading && (
                        <div className="py-4 space-y-6">
                            {/* Tags trending */}
                            <div>
                                <p className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest mb-3">
                                    Tendencias
                                </p>
                                <div className="flex flex-wrap gap-1">
                                    {trendingTags.map(tag => (
                                        <button
                                            key={tag}
                                            onClick={() => { setQuery(tag); if (tab === 'usuarios') setTab('resenas') }}
                                            className="px-3 py-1.5 border border-[var(--card-border)] text-[10px] font-black capitalize hover:bg-[var(--hover-bg)] transition-all"
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            #{tag}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Top reseñas de la semana */}
                            <TopResenasSemana />

                            {/* Top usuarios activos */}
                            <TopUsuariosActivos />
                        </div>
                    )}

                    {/* Loading */}
                    {loading && (
                        <div className="pt-4 opacity-50">
                            <SearchSkeleton tab={tab} />
                        </div>
                    )}

                    {/* Results: Partidos */}
                    {!loading && hasSearched && tab === 'partidos' && (
                        <div className="space-y-4">
                            {partidos.length === 0 ? (
                                <div className="text-center py-12 border border-[var(--card-border)] border-dashed" style={{ borderRadius: 'var(--radius)' }}>
                                    <p className="text-[10px] font-black capitalize text-[var(--text-muted)]">SIN RESULTADOS</p>
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                    {partidos.map((partido) => (
                                        <PartidoCard key={partido.id} partido={partido} />
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Results: Usuarios */}
                    {!loading && hasSearched && tab === 'usuarios' && (
                        <div className="space-y-1">
                            {usuarios.length === 0 ? (
                                <div className="text-center py-12 border border-[var(--card-border)] border-dashed" style={{ borderRadius: 'var(--radius)' }}>
                                    <p className="text-[10px] font-black capitalize text-[var(--text-muted)]">
                                        {query.length < 2 ? 'ESCRIBÍ AL MENOS 2 CARACTERES' : 'SIN RESULTADOS'}
                                    </p>
                                </div>
                            ) : (
                                <div className="border border-[var(--card-border)] bg-[var(--card-bg)] divide-y divide-[var(--card-border)] overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                                    {usuarios.map((user) => (
                                        <div
                                            key={user.id}
                                            className="flex items-center gap-3 p-3 hover:bg-[var(--background)] transition-colors"
                                        >
                                            <div
                                                className="w-10 h-10 border border-[var(--card-border)] bg-[var(--background)] flex flex-shrink-0 items-center justify-center cursor-pointer overflow-hidden"
                                                onClick={() => router.push(`/perfil/${user.id}`)}
                                                style={{ borderRadius: 'var(--radius)' }}
                                            >
                                                {user.avatar_url ? (
                                                    <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
                                                ) : (
                                                    <span className="text-xs font-black">{user.username?.charAt(0)?.toUpperCase()}</span>
                                                )}
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="text-[11px] font-black capitalize tracking-widest hover:underline cursor-pointer" onClick={() => router.push(`/perfil/${user.id}`)}>
                                                    {user.username}
                                                </div>
                                                {user.equipo && (
                                                    <div className="text-[9px] text-[var(--text-muted)] font-black capitalize">
                                                        {user.equipo}
                                                    </div>
                                                )}
                                            </div>
                                            <div className="flex flex-col items-end gap-1">
                                                <FollowButton targetUserId={user.id} targetUsername={user.username || ''} />
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Results: Reseñas */}
                    {!loading && hasSearched && tab === 'resenas' && (
                        <div className="space-y-4">
                            {resenas.length === 0 ? (
                                <div className="text-center py-12 border border-[var(--card-border)] border-dashed" style={{ borderRadius: 'var(--radius)' }}>
                                    <p className="text-[10px] font-black capitalize text-[var(--text-muted)]">SIN RESULTADOS</p>
                                </div>
                            ) : (
                                <div className="space-y-2">
                                    {resenas.map((resena) => (
                                        <MatchLogCard key={resena.id} log={resena} />
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Results: Jugadores */}
                    {!loading && hasSearched && tab === 'jugadores' && (
                        <div className="space-y-2">
                            {jugadores.length === 0 ? (
                                <div className="text-center py-12 border border-[var(--card-border)] border-dashed" style={{ borderRadius: 'var(--radius)' }}>
                                    <p className="text-[10px] font-black capitalize text-[var(--text-muted)]">
                                        {query.length < 2 ? 'ESCRIBÍ AL MENOS 2 CARACTERES' : 'SIN RESULTADOS'}
                                    </p>
                                </div>
                            ) : (
                                <div className="border border-[var(--card-border)] bg-[var(--card-bg)] divide-y divide-[var(--card-border)] overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                                    {jugadores.map((j) => (
                                        <div
                                            key={j.player_name}
                                            className="flex items-center gap-3 p-3 hover:bg-[var(--background)] transition-colors cursor-pointer"
                                            onClick={() => j.best_log_id && router.push(`/log/${j.best_log_id}`)}
                                        >
                                            <div className="w-10 h-10 rounded-full bg-[var(--accent)]/10 flex items-center justify-center text-lg font-black shrink-0">
                                                ⚽
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="text-sm font-black truncate">{j.player_name}</div>
                                                <div className="text-[10px] text-[var(--text-muted)]">
                                                    {j.total_ratings} calificación{j.total_ratings !== 1 ? 'es' : ''}
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-1 px-2 py-1 bg-[var(--hover-bg)] rounded-lg">
                                                <span className="text-xs font-black">⭐ {j.avg_rating.toFixed(1)}</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            </main>
            <NavBar />
        </>
    )
}

function TopResenasSemana() {
    const [resenas, setResenas] = useState<any[]>([])
    const router = useRouter()

    useEffect(() => {
        const fetchData = async () => {
            const unaSemanAtras = new Date(Date.now() - 7 * 86400000).toISOString()
            const { data } = await supabase
                .from('match_logs')
                .select(`
                    id, equipo_local, equipo_visitante, rating_partido, review_title,
                    likes_count:match_log_likes(count),
                    profile:profiles!match_logs_user_id_fkey(username)
                `)
                .eq('is_private', false)
                .not('review_text', 'is', null)
                .gte('created_at', unaSemanAtras)
                .order('created_at', { ascending: false })
                .limit(3)

            if (data) setResenas(data.map((r: any) => ({
                ...r,
                likes_count: r.likes_count?.[0]?.count || 0
            })))
        }
        fetchData()
    }, [])

    if (!resenas.length) return null

    return (
        <div>
            <p className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest mb-3">
                🔥 Reseñas populares esta semana
            </p>
            <div className="space-y-2">
                {resenas.map(r => (
                    <button
                        key={r.id}
                        onClick={() => router.push(`/log/${r.id}`)}
                        className="w-full flex items-center gap-3 p-3 bg-[var(--card-bg)] border border-[var(--card-border)] hover:border-[var(--foreground)] transition-all text-left"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <div className="flex-1 min-w-0">
                            <p className="text-xs font-black truncate">
                                {r.equipo_local} vs {r.equipo_visitante}
                            </p>
                            <p className="text-[10px] text-[var(--text-muted)] truncate">
                                por @{r.profile?.username} · ⭐ {r.rating_partido?.toFixed(1)}
                            </p>
                        </div>
                        <span className="text-[10px] text-[var(--text-muted)] shrink-0">
                            ❤️ {r.likes_count}
                        </span>
                    </button>
                ))}
            </div>
        </div>
    )
}

function TopUsuariosActivos() {
    const [usuarios, setUsuarios] = useState<any[]>([])
    const router = useRouter()

    useEffect(() => {
        const fetchData = async () => {
            const { data } = await supabase
                .from('match_logs')
                .select(`
                    user_id,
                    profile:profiles!match_logs_user_id_fkey(username, avatar_url)
                `)
                .eq('is_private', false)
                .gte('created_at', new Date(Date.now() - 30 * 86400000).toISOString())

            if (!data) return

            const counts = new Map<string, { username: string; avatar_url?: string; count: number }>()
            data.forEach((d: any) => {
                const cur = counts.get(d.user_id) || { username: d.profile?.username, avatar_url: d.profile?.avatar_url, count: 0 }
                cur.count++
                counts.set(d.user_id, cur)
            })

            const sorted = Array.from(counts.entries())
                .map(([user_id, d]) => ({ user_id, ...d }))
                .sort((a, b) => b.count - a.count)
                .slice(0, 5)

            setUsuarios(sorted)
        }
        fetchData()
    }, [])

    if (!usuarios.length) return null

    return (
        <div>
            <p className="text-[9px] font-black text-[var(--text-muted)] uppercase tracking-widest mb-3">
                👤 Más activos este mes
            </p>
            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                {usuarios.map(u => (
                    <button
                        key={u.user_id}
                        onClick={() => router.push(`/perfil/${u.user_id}`)}
                        className="flex flex-col items-center gap-1.5 p-3 bg-[var(--card-bg)] border border-[var(--card-border)] hover:border-[var(--foreground)] transition-all shrink-0 min-w-[70px]"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <div className="w-10 h-10 rounded-full bg-[var(--accent)]/10 flex items-center justify-center overflow-hidden border border-[var(--card-border)]">
                            {u.avatar_url
                                ? <img src={u.avatar_url} alt="" className="w-full h-full object-cover" />
                                : <span className="text-sm font-black">{u.username?.[0]?.toUpperCase()}</span>
                            }
                        </div>
                        <span className="text-[9px] font-black truncate max-w-[60px]">{u.username}</span>
                        <span className="text-[8px] text-[var(--text-muted)]">{u.count} reseñas</span>
                    </button>
                ))}
            </div>
        </div>
    )
}

// src/app/grupos/[id]/page.tsx
'use client'

import { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useGrupos } from '@/hooks/useGrupos'
import { useToast } from '@/contexts/ToastContext'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { PartidosAmigosTab } from '@/components/grupos/PartidosAmigosTab'
import { TablaEstadisticas } from '@/components/grupos/TablaEstadisticas'
import { CommentSection } from '@/components/CommentSection'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { motion } from 'framer-motion'
import type { GrupoProde } from '@/types'

interface MiembroGrupo {
    user_id: string
    puntos_grupo: number
    joined_at: string
    profile?: {
        id: string
        username: string | null
        avatar_url: string | null
        equipo: string | null
    }
    puntos_mostrados: number
    racha?: { fase: number, copas: number }
}

export default function GrupoDetailPage() {
    const { id } = useParams()
    const router = useRouter()
    const { user } = useAuth()
    const { salirDeGrupo } = useGrupos()
    const { showToast } = useToast()

    const [grupo, setGrupo] = useState<GrupoProde | null>(null)
    const [miembros, setMiembros] = useState<MiembroGrupo[]>([])
    const [loading, setLoading] = useState(true)
    const [confirmandoSalir, setConfirmandoSalir] = useState(false)
    const [procesando, setProcesando] = useState(false)
    const [activeTab, setActiveTab] = useState<'ranking' | 'partidos' | 'chat' | 'stats'>('ranking')

    useEffect(() => {
        if (id && user) fetchGrupoData()
    }, [id, user])

    // Update last_read_at when in Chat tab
    useEffect(() => {
        if (activeTab === 'chat' && user && id) {
            supabase.rpc('mark_group_chat_as_read', {
                p_grupo_id: id,
                p_user_id: user.id
            }).then(({ error }) => {
                if (error) console.error('Error marking as read:', error)
            })
        }
    }, [activeTab, id, user])

    const fetchGrupoData = async () => {
        try {
            const { data: grupoData, error: errorGrupo } = await supabase
                .from('grupos_prode')
                .select('*')
                .eq('id', id)
                .single()

            if (errorGrupo) throw errorGrupo
            setGrupo(grupoData)

            const { data: miembrosData, error: errorMiembros } = await supabase
                .from('miembros_grupo')
                .select(`puntos_grupo, joined_at, user_id`)
                .eq('grupo_id', id)
                .order('puntos_grupo', { ascending: false })

            if (errorMiembros) throw errorMiembros

            const userIds = miembrosData.map(m => m.user_id)

            // Fetch Profiles
            const { data: profiles } = await supabase
                .from('profiles')
                .select('*')
                .in('id', userIds)

            // Fetch Rakings (Global Points)
            const { data: rankings } = await supabase
                .from('ranking_prode')
                .select('user_id, puntos_totales')
                .in('user_id', userIds)

            // Fetch Rachas Mundial
            const { data: rachas } = await supabase
                .from('racha_mundial')
                .select('user_id, fase, copas')
                .eq('grupo_id', id)
                .in('user_id', userIds)

            const miembrosWithData = miembrosData.map(m => {
                const ranking = rankings?.find(r => r.user_id === m.user_id)
                const racha = rachas?.find(r => r.user_id === m.user_id)
                return {
                    ...m,
                    profile: profiles?.find(p => p.id === m.user_id),
                    // Usamos puntos globales para el ranking del grupo por ahora
                    puntos_mostrados: ranking?.puntos_totales || 0,
                    racha: racha ? { fase: racha.fase, copas: racha.copas } : undefined
                }
            })

            // Ordenar por puntos globales
            miembrosWithData.sort((a, b) => b.puntos_mostrados - a.puntos_mostrados)

            setMiembros(miembrosWithData)
        } catch (error) {
            console.error('Error fetching group:', error)
            router.push('/grupos')
        } finally {
            setLoading(false)
        }
    }

    const copiarCodigo = () => {
        if (grupo?.codigo_invitacion) {
            navigator.clipboard.writeText(grupo.codigo_invitacion)
            showToast('Código copiado: ' + grupo.codigo_invitacion, 'success')
        }
    }

    const compartirWhatsApp = () => {
        if (!grupo) return
        const texto = `¡Unite a mi grupo "${grupo.nombre}" en FutLog! 🎯⚽\n\nCódigo: ${grupo.codigo_invitacion}`
        const url = `https://wa.me/?text=${encodeURIComponent(texto)}`
        window.open(url, '_blank')
    }

    const handleSalirGrupo = async () => {
        if (!grupo) return
        setProcesando(true)
        try {
            await salirDeGrupo(grupo.id)
            showToast('Saliste del grupo', 'success')
            router.push('/grupos')
        } catch (error: any) {
            showToast(error.message, 'error')
        } finally {
            setProcesando(false)
            setConfirmandoSalir(false)
        }
    }

    const esAdmin = user?.id === grupo?.admin_id

    if (loading) return (
        <div className="min-h-screen bg-[var(--background)] flex items-center justify-center">
            <LoadingSpinner />
        </div>
    )

    return (
        <>
            <DesktopNav />
            <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">

                {/* Header del Grupo */}
                <div className="bg-[#16a34a] text-white pt-10 pb-20 px-6 rounded-b-[40px] shadow-lg">
                    <div className="max-w-4xl mx-auto flex justify-between items-start">
                        <button onClick={() => router.push('/grupos')} className="bg-white/20 p-2 rounded-full backdrop-blur-md">←</button>
                        <div className="text-center flex-1">
                            <h1 className="text-3xl font-black">{grupo?.nombre}</h1>
                            <p className="opacity-80 text-sm mt-1">
                                {miembros.length} miembro{miembros.length !== 1 ? 's' : ''} • Ranking de Amigos
                            </p>
                        </div>
                        <button onClick={copiarCodigo} className="bg-white/20 px-4 py-2 rounded-xl backdrop-blur-md font-mono text-sm">
                            #{grupo?.codigo_invitacion}
                        </button>
                    </div>
                </div>

                {/* Tabs */}
                <div className="max-w-4xl mx-auto px-6 -mt-5 mb-4">
                    <div className="bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)] p-1 flex shadow-lg">
                        <button
                            onClick={() => setActiveTab('ranking')}
                            className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'ranking'
                                ? 'bg-[#16a34a] text-white shadow-md'
                                : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                }`}
                        >
                            🏆 Ranking Pronósticos
                        </button>
                        <button
                            onClick={() => setActiveTab('partidos')}
                            className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'partidos'
                                ? 'bg-[#16a34a] text-white shadow-md'
                                : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                }`}
                        >
                            ⚽ Partidos
                        </button>
                        <button
                            onClick={() => setActiveTab('stats')}
                            className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'stats'
                                ? 'bg-[#16a34a] text-white shadow-md'
                                : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                }`}
                        >
                            📊 Stats
                        </button>
                        <button
                            onClick={() => setActiveTab('chat')}
                            className={`flex-1 py-3 rounded-xl text-sm font-bold transition-all ${activeTab === 'chat'
                                ? 'bg-[#16a34a] text-white shadow-md'
                                : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                }`}
                        >
                            💬 Chat
                        </button>
                    </div>
                </div>

                {/* Tab Content */}
                <div className="max-w-4xl mx-auto px-6">
                    {activeTab === 'ranking' ? (
                        <>
                            {/* Lista de Miembros */}
                            <div className="bg-[var(--card-bg)] rounded-3xl shadow-xl border border-[var(--card-border)] overflow-hidden">
                                {miembros.map((miembro, index) => (
                                    <motion.div
                                        key={miembro.user_id}
                                        initial={{ x: -20, opacity: 0 }}
                                        animate={{ x: 0, opacity: 1 }}
                                        transition={{ delay: index * 0.1 }}
                                        className={`flex items-center gap-4 p-5 border-b border-[var(--card-border)] last:border-0
                                   ${index === 0 ? 'bg-[#ffd700]/5' : ''}`}
                                    >
                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm
                                        ${index === 0 ? 'bg-[#ffd700] text-black' :
                                                index === 1 ? 'bg-[#c0c0c0] text-black' :
                                                    index === 2 ? 'bg-[#cd7f32] text-black' : 'bg-[var(--background)] text-[var(--text-muted)]'}`}>
                                            {index + 1}
                                        </div>

                                        <div className="w-10 h-10 bg-[var(--background)] rounded-full border border-[var(--card-border)] overflow-hidden flex items-center justify-center text-lg shadow-sm">
                                            {miembro.profile?.avatar_url || '👤'}
                                        </div>

                                        <div className="flex-1">
                                            <div className="font-bold flex items-center gap-2">
                                                {miembro.profile?.username || 'Usuario'}
                                                {miembro.user_id === grupo?.admin_id && (
                                                    <span className="text-[9px] bg-[#ffd700]/20 text-[#ffd700] px-2 py-0.5 rounded-full">ADMIN</span>
                                                )}
                                                {miembro.user_id === user?.id && (
                                                    <span className="text-[9px] bg-[#16a34a]/20 text-[#16a34a] px-2 py-0.5 rounded-full">VOS</span>
                                                )}
                                            </div>
                                            <div className="text-[10px] text-[var(--text-muted)] capitalize">{miembro.profile?.equipo || 'Hincha'}</div>

                                            {/* Racha Mundial Display */}
                                            {miembro.racha && (miembro.racha.fase > 0 || miembro.racha.copas > 0) && (
                                                <div className="flex items-center gap-2 mt-1">
                                                    {miembro.racha.copas > 0 && (
                                                        <span className="text-xs bg-yellow-500/20 text-yellow-500 px-1.5 rounded font-bold border border-yellow-500/30" title="Copas Ganadas">
                                                            🏆 {miembro.racha.copas}
                                                        </span>
                                                    )}
                                                    {miembro.racha.fase > 0 && (
                                                        <div className="flex items-center gap-0.5" title={`Racha actual: ${miembro.racha.fase}/7`}>
                                                            {Array.from({ length: 7 }).map((_, i) => (
                                                                <div
                                                                    key={i}
                                                                    className={`w-1.5 h-1.5 rounded-full ${i < miembro.racha!.fase ? 'bg-green-500' : 'bg-[var(--card-border)]'}`}
                                                                />
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                        </div>

                                        <div className="text-right">
                                            <div className={`text-xl font-black ${index === 0 ? 'text-[#ffd700]' : 'text-[#16a34a]'}`}>{miembro.puntos_mostrados}</div>
                                            <div className="text-[9px] text-[var(--text-muted)] capitalize">Pts</div>
                                        </div>
                                    </motion.div>
                                ))}
                            </div>

                            {/* Acciones */}
                            <div className="mt-8 grid grid-cols-1 md:grid-cols-2 gap-4">
                                {/* Invitar */}
                                <div className="p-6 bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)]">
                                    <h4 className="font-bold mb-2">¿Falta alguien?</h4>
                                    <p className="text-xs text-[var(--text-muted)] mb-4">Invitá amigos a sumarse</p>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={compartirWhatsApp}
                                            className="flex-1 bg-[#25D366] text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2"
                                        >
                                            <span>📱</span> WhatsApp
                                        </button>
                                        <button
                                            onClick={copiarCodigo}
                                            className="px-4 py-3 bg-[var(--background)] border border-[var(--card-border)] rounded-xl text-sm"
                                        >
                                            📋 Copiar
                                        </button>
                                    </div>
                                </div>

                                {/* Salir del grupo */}
                                {!esAdmin && (
                                    <div className="p-6 bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)]">
                                        <h4 className="font-bold mb-2 text-[#ef4444]">⚠️ Zona peligrosa</h4>
                                        <p className="text-xs text-[var(--text-muted)] mb-4">Si salís, perdés tu posición en este grupo</p>

                                        {confirmandoSalir ? (
                                            <div className="flex gap-2">
                                                <button
                                                    onClick={handleSalirGrupo}
                                                    disabled={procesando}
                                                    className="flex-1 bg-[#ef4444] text-white py-3 rounded-xl font-bold disabled:opacity-50"
                                                >
                                                    {procesando ? 'Saliendo...' : 'Sí, salir'}
                                                </button>
                                                <button
                                                    onClick={() => setConfirmandoSalir(false)}
                                                    className="px-6 py-3 text-[var(--text-muted)]"
                                                >
                                                    Cancelar
                                                </button>
                                            </div>
                                        ) : (
                                            <button
                                                onClick={() => setConfirmandoSalir(true)}
                                                className="w-full py-3 border-2 border-[#ef4444] text-[#ef4444] rounded-xl font-bold hover:bg-[#ef4444]/10 transition-all"
                                            >
                                                Salir del grupo
                                            </button>
                                        )}
                                    </div>
                                )}
                            </div>
                        </>
                    ) : activeTab === 'partidos' ? (
                        /* Partidos Amigos Tab */
                        grupo && <PartidosAmigosTab grupo={grupo} />
                    ) : activeTab === 'stats' ? (
                        /* Stats Tab */
                        grupo && <TablaEstadisticas grupoId={grupo.id} miembros={miembros} />
                    ) : (
                        /* Chat Tab */
                        grupo && (
                            <div className="mt-2">
                                <CommentSection partidoId={`grupo-${grupo.id}`} />
                            </div>
                        )
                    )}
                </div>

            </main>
            <NavBar />
        </>
    )
}

// src/app/historial/page.tsx
'use client'

import { useState, useEffect, useMemo } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { motion } from 'framer-motion'

export default function HistorialPage() {
    const { user } = useAuth()
    const [historial, setHistorial] = useState<any[]>([])
    const [loading, setLoading] = useState(true)
    const [filtroLiga, setFiltroLiga] = useState<string>('Todas')

    useEffect(() => {
        if (user) {
            fetchHistorial()
        }
    }, [user])

    const fetchHistorial = async () => {
        setLoading(true)
        try {
            const { data, error } = await supabase
                .from('pronosticos')
                .select(`
                    *,
                    partido:partidos(*),
                    puntuacion:puntuaciones_prode(*)
                `)
                .eq('user_id', user?.id)
                .order('created_at', { ascending: false })

            if (error) throw error

            const finalizados = (data || []).filter(p =>
                p.partido?.estado === 'FINALIZADO' || p.puntuacion?.length > 0
            )

            setHistorial(finalizados)
        } catch (error) {
            console.error('Error fetching historial:', error)
        } finally {
            setLoading(false)
        }
    }

    // Calcular stats detalladas
    const stats = useMemo(() => {
        if (historial.length === 0) return null

        const conPuntos = historial.filter(p => p.puntuacion?.[0]?.puntos !== undefined)
        const totalPuntos = conPuntos.reduce((acc, p) => acc + (p.puntuacion?.[0]?.puntos || 0), 0)

        const exactos = conPuntos.filter(p => p.puntuacion?.[0]?.puntos === 8).length
        const ganadorDif = conPuntos.filter(p => p.puntuacion?.[0]?.puntos === 5).length
        const soloGanador = conPuntos.filter(p => p.puntuacion?.[0]?.puntos === 3).length
        const fallos = conPuntos.filter(p => p.puntuacion?.[0]?.puntos === 0).length

        // Racha actual (desde el último pronóstico)
        let racha = 0
        for (const p of historial) {
            const pts = p.puntuacion?.[0]?.puntos || 0
            if (pts > 0) racha++
            else break
        }

        // Stats por liga
        const ligaStats: Record<string, { puntos: number; count: number }> = {}
        conPuntos.forEach(p => {
            const liga = p.partido?.liga || 'Otra'
            if (!ligaStats[liga]) ligaStats[liga] = { puntos: 0, count: 0 }
            ligaStats[liga].puntos += p.puntuacion?.[0]?.puntos || 0
            ligaStats[liga].count++
        })

        return {
            total: conPuntos.length,
            totalPuntos,
            promedio: conPuntos.length > 0 ? (totalPuntos / conPuntos.length).toFixed(1) : '0',
            exactos,
            ganadorDif,
            soloGanador,
            fallos,
            porcentajeExactos: conPuntos.length > 0 ? ((exactos / conPuntos.length) * 100).toFixed(0) : '0',
            porcentajeAciertos: conPuntos.length > 0 ? (((exactos + ganadorDif + soloGanador) / conPuntos.length) * 100).toFixed(0) : '0',
            racha,
            ligaStats
        }
    }, [historial])

    // Ligas disponibles
    const ligas = useMemo(() => {
        const set = new Set(historial.map(p => p.partido?.liga).filter(Boolean))
        return ['Todas', ...Array.from(set)]
    }, [historial])

    // Filtrar por liga
    const historialFiltrado = useMemo(() => {
        if (filtroLiga === 'Todas') return historial
        return historial.filter(p => p.partido?.liga === filtroLiga)
    }, [historial, filtroLiga])

    const getPuntosColor = (puntos: number) => {
        if (puntos === 8) return 'text-[#16a34a]'
        if (puntos === 5) return 'text-[#3b82f6]'
        if (puntos === 3) return 'text-[#6366f1]'
        return 'text-[var(--text-muted)]'
    }

    const getPuntosBadge = (puntos: number) => {
        if (puntos === 8) return { text: 'EXACTO', color: 'bg-[#16a34a]' }
        if (puntos === 5) return { text: 'GANADOR+DIF', color: 'bg-[#3b82f6]' }
        if (puntos === 3) return { text: 'GANADOR', color: 'bg-[#6366f1]' }
        return { text: 'FALLADO', color: 'bg-[#ef4444]' }
    }

    return (
        <>
            <DesktopNav />
            <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">
                <div className="px-6 py-6 md:py-8">
                    <div className="max-w-4xl mx-auto">
                        <h1 className="text-2xl md:text-3xl font-bold tracking-tight mb-2">
                            📜 Mi Historial
                        </h1>
                        <p className="text-sm text-[var(--text-muted)]">
                            Repasá tus aciertos y errores en el PRODE.
                        </p>
                    </div>
                </div>

                {/* Stats Summary */}
                {stats && (
                    <div className="px-6 mb-8">
                        <div className="max-w-4xl mx-auto">
                            <motion.div
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="bg-gradient-to-br from-[#16a34a]/10 to-[#16a34a]/5 rounded-3xl border border-[#16a34a]/30 p-6"
                            >
                                {/* Stats principales */}
                                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-6">
                                    <div className="text-center">
                                        <div className="text-3xl font-black text-[#16a34a]">{stats.totalPuntos}</div>
                                        <div className="text-[10px] text-[var(--text-muted)] capitalize">Puntos Total</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-3xl font-black">{stats.total}</div>
                                        <div className="text-[10px] text-[var(--text-muted)] capitalize">Pronósticos</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-3xl font-black text-[#ffd700]">{stats.porcentajeExactos}%</div>
                                        <div className="text-[10px] text-[var(--text-muted)] capitalize">Exactos</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-3xl font-black text-[#3b82f6]">{stats.porcentajeAciertos}%</div>
                                        <div className="text-[10px] text-[var(--text-muted)] capitalize">Aciertos</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-3xl font-black text-[#ff6b6b]">{stats.racha}🔥</div>
                                        <div className="text-[10px] text-[var(--text-muted)] capitalize">Racha</div>
                                    </div>
                                </div>

                                {/* Breakdown por tipo */}
                                <div className="flex flex-wrap gap-2 justify-center mb-4">
                                    <span className="text-xs bg-[#16a34a]/20 text-[#16a34a] px-3 py-1 rounded-full font-bold">
                                        {stats.exactos} exactos
                                    </span>
                                    <span className="text-xs bg-[#3b82f6]/20 text-[#3b82f6] px-3 py-1 rounded-full font-bold">
                                        {stats.ganadorDif} ganador+dif
                                    </span>
                                    <span className="text-xs bg-[#6366f1]/20 text-[#6366f1] px-3 py-1 rounded-full font-bold">
                                        {stats.soloGanador} solo ganador
                                    </span>
                                    <span className="text-xs bg-[#ef4444]/20 text-[#ef4444] px-3 py-1 rounded-full font-bold">
                                        {stats.fallos} fallados
                                    </span>
                                </div>

                                {/* Stats por liga */}
                                {Object.keys(stats.ligaStats).length > 1 && (
                                    <div className="pt-4 border-t border-[#16a34a]/20">
                                        <h4 className="text-xs font-bold text-[var(--text-muted)] capitalize mb-3 text-center">Por Liga</h4>
                                        <div className="flex flex-wrap gap-4 justify-center">
                                            {Object.entries(stats.ligaStats).map(([liga, data]) => (
                                                <div key={liga} className="bg-[var(--card-bg)] px-4 py-2 rounded-xl text-center">
                                                    <div className="text-xs font-bold truncate max-w-[100px]">{liga}</div>
                                                    <div className="text-lg font-black text-[#16a34a]">{data.puntos}</div>
                                                    <div className="text-[9px] text-[var(--text-muted)]">{data.count} partidos</div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </motion.div>
                        </div>
                    </div>
                )}

                {/* Filtro por liga */}
                {ligas.length > 2 && (
                    <div className="px-6 mb-6">
                        <div className="max-w-4xl mx-auto">
                            <div className="flex gap-2 overflow-x-auto no-scrollbar">
                                {ligas.map(liga => (
                                    <button
                                        key={liga}
                                        onClick={() => setFiltroLiga(liga)}
                                        className={`px-4 py-2 rounded-lg text-xs font-medium whitespace-nowrap transition-all
                                            ${filtroLiga === liga
                                                ? 'bg-[#16a34a] text-white'
                                                : 'bg-[var(--card-bg)] border border-[var(--card-border)] text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                            }`}
                                    >
                                        {liga}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>
                )}

                <div className="px-6">
                    <div className="max-w-4xl mx-auto space-y-4">
                        {loading ? (
                            <div className="text-center py-12 opacity-50">
                                <span className="animate-spin inline-block text-2xl">⚽</span>
                                <p className="mt-2 text-xs capitalize tracking-widest">Cargando tus prodes...</p>
                            </div>
                        ) : historialFiltrado.length === 0 ? (
                            <div className="bg-[var(--card-bg)] rounded-2xl p-12 text-center border border-[var(--card-border)] border-dashed">
                                <span className="text-5xl mb-4 block opacity-30">📭</span>
                                <h3 className="text-lg font-bold">No hay historial todavía</h3>
                                <p className="text-sm text-[var(--text-muted)] mt-2">
                                    Tus pronósticos aparecerán acá una vez que los partidos finalicen.
                                </p>
                            </div>
                        ) : (
                            historialFiltrado.map((p, index) => {
                                const puntos = p.puntuacion?.[0]?.puntos || 0
                                const badge = getPuntosBadge(puntos)

                                return (
                                    <motion.div
                                        key={p.id}
                                        initial={{ opacity: 0, y: 20 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        transition={{ delay: index * 0.03 }}
                                        className="bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)] overflow-hidden hover:border-[var(--text-muted)]/30 transition-all"
                                    >
                                        <div className="px-4 py-2 bg-[var(--background)]/50 text-[10px] font-bold text-[var(--text-muted)] flex justify-between items-center">
                                            <span>{p.partido?.liga}</span>
                                            <div className="flex items-center gap-2">
                                                <span className={`${badge.color} text-white px-2 py-0.5 rounded text-[9px]`}>
                                                    {badge.text}
                                                </span>
                                                <span>{new Date(p.partido?.fecha_inicio).toLocaleDateString()}</span>
                                            </div>
                                        </div>

                                        <div className="p-4 grid grid-cols-1 md:grid-cols-3 gap-6 items-center">
                                            <div className="flex flex-col gap-2">
                                                <div className="flex items-center justify-between text-sm">
                                                    <span className="truncate">{p.partido?.equipo_local}</span>
                                                    <span className="font-bold">{p.partido?.goles_local}</span>
                                                </div>
                                                <div className="flex items-center justify-between text-sm">
                                                    <span className="truncate">{p.partido?.equipo_visitante}</span>
                                                    <span className="font-bold">{p.partido?.goles_visitante}</span>
                                                </div>
                                                <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tighter">Resultado Final</div>
                                            </div>

                                            <div className="bg-[var(--background)] rounded-xl p-3 border border-[var(--card-border)]">
                                                <div className="text-[9px] text-[var(--text-muted)] font-black capitalize tracking-widest mb-2 text-center">Mi Prode</div>
                                                <div className="flex items-center justify-center gap-3">
                                                    <span className="text-lg font-black">{p.goles_local_pronostico}</span>
                                                    <span className="opacity-20">-</span>
                                                    <span className="text-lg font-black">{p.goles_visitante_pronostico}</span>
                                                </div>
                                            </div>

                                            <div className="flex flex-col items-center justify-center">
                                                <div className={`text-4xl font-black ${getPuntosColor(puntos)}`}>
                                                    +{puntos}
                                                </div>
                                                <div className="text-[10px] font-bold capitalize tracking-widest opacity-60">puntos</div>
                                            </div>
                                        </div>
                                    </motion.div>
                                )
                            })
                        )}
                    </div>
                </div>
            </main>
            <NavBar />
        </>
    )
}

// src/app/listas/[id]/page.tsx
'use client'

import { useState, useEffect } from 'react'
import { useParams, useRouter } from 'next/navigation'
import { createClient } from '@/lib/supabase/client'
import { DesktopNav } from '@/components/DesktopNav'
import { NavBar } from '@/components/NavBar'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { TeamLogo } from '@/components/TeamLogo'
import { ChevronRight, Share2, Calendar, User } from 'lucide-react'
import Link from 'next/link'
import { motion } from 'framer-motion'

export default function ListViewPage() {
  const { id } = useParams()
  const router = useRouter()
  const [list, setList] = useState<any>(null)
  const [items, setItems] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  useEffect(() => {
    const fetchListData = async () => {
      setLoading(true)
      const { data: listData, error: listError } = await supabase
        .from('user_lists')
        .select('*, profile:profiles(username, avatar_url)')
        .eq('id', id)
        .single()

      if (listData) {
        setList(listData)
        const { data: itemData } = await supabase
          .from('user_list_items')
          .select('*')
          .eq('list_id', id)
          .order('created_at', { ascending: true })

        if (itemData) setItems(itemData)
      }
      setLoading(false)
    }

    if (id) fetchListData()
  }, [id])

  if (loading) return (
    <div className="min-h-screen bg-[var(--background)] flex items-center justify-center">
      <LoadingSpinner />
    </div>
  )

  if (!list) return (
    <div className="min-h-screen bg-[var(--background)] flex items-center justify-center p-6 text-center">
        <div>
            <h1 className="text-2xl font-black mb-2">Lista no encontrada</h1>
            <button onClick={() => router.push('/')} className="text-[var(--accent)] font-bold">Volver al inicio</button>
        </div>
    </div>
  )

  return (
    <>
      <DesktopNav />
      <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-32 md:pt-20">
        <div className="max-w-4xl mx-auto px-6 py-8">
            {/* Header de la Lista */}
            <div className="mb-10 text-center">
                <span className="text-4xl mb-4 block">{list.icon}</span>
                <h1 className="text-4xl font-black tracking-tighter mb-2">{list.title}</h1>
                <p className="text-[var(--text-muted)] text-sm max-w-lg mx-auto mb-6">{list.description}</p>

                <div className="flex items-center justify-center gap-6">
                    <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-full bg-[var(--card-border)] flex items-center justify-center text-[10px]">
                            {list.profile?.avatar_url || <User size={12} />}
                        </div>
                        <span className="text-xs font-bold text-[var(--accent)]">@{list.profile?.username}</span>
                    </div>
                    <div className="h-4 w-px bg-[var(--card-border)]" />
                    <button className="flex items-center gap-2 text-xs font-bold text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors">
                        <Share2 size={14} /> Compartir
                    </button>
                </div>
            </div>

            {/* Items de la Lista */}
            <div className="space-y-4">
                <h3 className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] mb-4 flex items-center gap-2">
                    ⚽ {items.length} Partidos en esta lista
                </h3>

                {items.length === 0 ? (
                    <div className="py-20 text-center bg-[var(--card-bg)] rounded-3xl border border-[var(--card-border)] border-dashed">
                        <p className="text-sm text-[var(--text-muted)] font-bold">Esta lista aún no tiene partidos.</p>
                    </div>
                ) : (
                    items.map((item, i) => {
                        const m = item.match_data || {}
                        return (
                            <motion.div
                                key={item.id}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: i * 0.1 }}
                            >
                                <Link 
                                    href={`/partido/${item.match_id}`}
                                    className="block bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-4 hover:border-[var(--accent)]/40 hover:shadow-lg transition-all"
                                >
                                    <div className="flex items-center justify-between">
                                        <div className="flex items-center gap-6 flex-1">
                                            <div className="flex items-center gap-3 min-w-[120px] justify-end">
                                                <span className="text-xs font-black truncate">{m.equipo_local}</span>
                                                <TeamLogo src={m.logo_local} teamName={m.equipo_local} size={32} />
                                            </div>

                                            <div className="bg-[var(--background)] px-3 py-1 rounded-lg border border-[var(--card-border)] shadow-sm font-black text-sm tracking-tighter">
                                                {m.goles_local} - {m.goles_visitante}
                                            </div>

                                            <div className="flex items-center gap-3 min-w-[120px]">
                                                <TeamLogo src={m.logo_visitante} teamName={m.equipo_visitante} size={32} />
                                                <span className="text-xs font-black truncate">{m.equipo_visitante}</span>
                                            </div>
                                        </div>
                                        <ChevronRight size={18} className="text-[var(--text-muted)] opacity-30" />
                                    </div>

                                    {item.note && (
                                        <div className="mt-4 pt-4 border-t border-[var(--card-border)] flex gap-3 italic">
                                            <span className="text-lg leading-none text-[var(--accent)] opacity-50">“</span>
                                            <p className="text-xs font-bold text-[var(--text-muted)] flex-1">{item.note}</p>
                                        </div>
                                    )}
                                </Link>
                            </motion.div>
                        )
                    })
                )}
            </div>
        </div>
      </main>
      <NavBar />
    </>
  )
}

// src/app/log/[id]/page.tsx
'use client'

import { useState, useEffect, use } from 'react'
import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import {
    ArrowLeft, Heart, Share2, Tv, MapPin, Users, HelpCircle,
    Eye, EyeOff, Clock, User, UserPlus, UserCheck
} from 'lucide-react'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { StarRating, StarRatingDisplay } from '@/components/StarRating'
import { TeamLogo } from '@/components/TeamLogo'
import { CommentSection } from '@/components/CommentSection'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { useMatchLogs } from '@/hooks/useMatchLogs'
import { useFollows } from '@/hooks/useMatchLogs'
import { useAuth } from '@/contexts/AuthContext'
import type { MatchLog } from '@/types'

const MATCH_TYPE_META: Record<string, { icon: typeof Tv; label: string; color: string }> = {
    tv: { icon: Tv, label: 'Lo vio por TV', color: '#3b82f6' },
    stadium: { icon: MapPin, label: 'En la cancha', color: '#16a34a' },
    friend: { icon: Users, label: 'Con amigos', color: '#f59e0b' },
    other: { icon: HelpCircle, label: 'Otro', color: '#2563eb' },
}

export default function LogDetailPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params)
    const router = useRouter()
    const { user } = useAuth()
    const { getMatchLog, toggleLike } = useMatchLogs()
    const { isFollowing, toggleFollow } = useFollows()
    const [log, setLog] = useState<MatchLog | null>(null)
    const [loading, setLoading] = useState(true)
    const [spoilerRevealed, setSpoilerRevealed] = useState(false)

    useEffect(() => {
        const fetch = async () => {
            setLoading(true)
            const data = await getMatchLog(id)
            setLog(data)
            setLoading(false)
        }
        fetch()
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [id])

    const handleLike = async () => {
        if (!log || !user) return
        await toggleLike(log.id)
        setLog(prev => prev ? {
            ...prev,
            is_liked: !prev.is_liked,
            likes_count: (prev.likes_count || 0) + (prev.is_liked ? -1 : 1),
        } : null)
    }

    const handleShare = async () => {
        if (navigator.share) {
            try {
                await navigator.share({
                    title: `${log?.equipo_local} vs ${log?.equipo_visitante}`,
                    url: window.location.href,
                })
            } catch { /* cancelled */ }
        } else {
            navigator.clipboard.writeText(window.location.href)
        }
    }

    if (loading) {
        return (
            <>
                <DesktopNav />
                <main className="min-h-screen bg-[var(--background)] flex items-center justify-center pb-24 md:pt-20">
                    <LoadingSpinner />
                </main>
                <NavBar />
            </>
        )
    }

    if (!log) {
        return (
            <>
                <DesktopNav />
                <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">
                    <div className="flex flex-col items-center justify-center py-16">
                        <span className="text-4xl mb-4">😕</span>
                        <h2 className="text-lg font-bold mb-1">Reseña no encontrada</h2>
                        <p className="text-sm text-[var(--text-muted)] mb-4">Puede que haya sido eliminada o sea privada.</p>
                        <button onClick={() => router.push('/feed')} className="px-4 py-2 bg-[#f59e0b] text-white rounded-xl text-sm font-semibold">
                            Ir al feed
                        </button>
                    </div>
                </main>
                <NavBar />
            </>
        )
    }

    const typeMeta = MATCH_TYPE_META[log.match_type] || MATCH_TYPE_META.other
    const TypeIcon = typeMeta.icon
    const isOwner = user?.id === log.user_id

    return (
        <>
            <DesktopNav />
            <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">
                {/* Top Bar */}
                <div className="flex items-center justify-between px-4 py-3">
                    <button onClick={() => router.back()} className="p-2 rounded-xl hover:bg-[var(--hover-bg)] transition-colors">
                        <ArrowLeft size={20} />
                    </button>
                    <div className="flex items-center gap-2">
                        <button onClick={handleLike}
                            className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-sm font-medium transition-all ${log.is_liked ? 'text-red-500 bg-red-500/10' : 'text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'
                                }`}
                        >
                            <Heart size={16} fill={log.is_liked ? 'currentColor' : 'none'} />
                            {(log.likes_count || 0) > 0 && <span>{log.likes_count}</span>}
                        </button>
                        <button onClick={handleShare}
                            className="p-2 rounded-xl text-[var(--text-muted)] hover:bg-[var(--hover-bg)] transition-colors">
                            <Share2 size={18} />
                        </button>
                    </div>
                </div>

                <div className="max-w-2xl mx-auto px-4 space-y-5">
                    {/* User Header */}
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-[#f59e0b] to-[#ef4444] flex items-center justify-center
                           text-white text-sm font-bold shrink-0">
                            {log.profile?.avatar_url ? (
                                <img src={log.profile.avatar_url} alt="" className="w-full h-full rounded-full object-cover" />
                            ) : (
                                log.profile?.username?.charAt(0)?.toUpperCase() || '?'
                            )}
                        </div>
                        <div className="flex-1 min-w-0">
                            <div className="text-sm font-semibold">{log.profile?.username || 'Anónimo'}</div>
                            <div className="flex items-center gap-1.5 text-xs text-[var(--text-muted)]">
                                <TypeIcon size={12} style={{ color: typeMeta.color }} />
                                <span>{typeMeta.label}</span>
                                <span>·</span>
                                <Clock size={10} />
                                <span>{new Date(log.created_at).toLocaleDateString('es-AR', { day: 'numeric', month: 'long', year: 'numeric' })}</span>
                            </div>
                        </div>
                        {!isOwner && user && (
                            <button
                                onClick={() => toggleFollow(log.user_id)}
                                className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-medium border transition-all ${isFollowing(log.user_id)
                                    ? 'border-[#16a34a]/30 bg-[#16a34a]/5 text-[#16a34a]'
                                    : 'border-[var(--card-border)] text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                    }`}
                            >
                                {isFollowing(log.user_id) ? <UserCheck size={13} /> : <UserPlus size={13} />}
                                {isFollowing(log.user_id) ? 'Siguiendo' : 'Seguir'}
                            </button>
                        )}
                    </div>

                    {log.is_neutral && (
                        <div className="flex items-center gap-2 mt-[-10px] sm:mt-[-15px] mb-3 opacity-90">
                            <span className="text-[10px] px-2 py-0.5 rounded-md bg-[#6366f1]/10 text-[#6366f1] font-medium inline-block border border-[#6366f1]/20">
                                📐 Reseña Neutral
                            </span>
                        </div>
                    )}

                    {/* Match Info Card */}
                    <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-5"
                    >
                        <div className="flex items-center gap-4">
                            <div className="flex flex-col items-center gap-1 flex-1">
                                <TeamLogo src={log.logo_local} teamName={log.equipo_local} size={48} />
                                <span className="text-xs font-semibold text-center">{log.equipo_local}</span>
                            </div>
                            <div className="text-center">
                                {log.goles_local != null && log.goles_visitante != null ? (
                                    <div className="text-2xl font-bold tabular-nums">
                                        {log.goles_local} - {log.goles_visitante}
                                    </div>
                                ) : (
                                    <span className="text-sm text-[var(--text-muted)]">vs</span>
                                )}
                                {log.liga && (
                                    <div className="text-[10px] text-[var(--text-muted)] mt-1">{log.liga}</div>
                                )}
                                <div className="text-[10px] text-[var(--text-muted)]">
                                    {new Date(log.fecha_partido).toLocaleDateString('es-AR')}
                                </div>
                            </div>
                            <div className="flex flex-col items-center gap-1 flex-1">
                                <TeamLogo src={log.logo_visitante} teamName={log.equipo_visitante} size={48} />
                                <span className="text-xs font-semibold text-center">{log.equipo_visitante}</span>
                            </div>
                        </div>
                        {log.partido_id && (
                            <div className="mt-4 pt-3 border-t border-[var(--card-border)] flex justify-center">
                                <button
                                    onClick={() => router.push(`/partido/${log.partido_id}`)}
                                    className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-[var(--accent)] hover:opacity-70 transition-opacity"
                                >
                                    Ver partido completo →
                                </button>
                            </div>
                        )}
                    </motion.div>

                    {/* Ratings Breakdown */}
                    <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.1 }}
                        className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-5 space-y-4"
                    >
                        {/* Main Rating */}
                        <div className="text-center">
                            <div className="text-xs text-[var(--text-muted)] mb-2">Rating del partido</div>
                            <div className="flex items-center justify-center gap-3">
                                <StarRatingDisplay value={log.rating_partido} size="md" />
                                <span className="text-xl font-bold text-[#f59e0b]">{log.rating_partido.toFixed(1)}</span>
                            </div>
                        </div>

                        {/* Secondary Ratings */}
                        {(log.rating_arbitro || log.rating_atmosfera) && (
                            <div className="grid grid-cols-2 gap-3 pt-3 border-t border-[var(--card-border)]">
                                {log.rating_arbitro && log.rating_arbitro > 0 && (
                                    <div className="text-center">
                                        <div className="text-[10px] text-[var(--text-muted)] mb-1">🟨 Árbitro</div>
                                        <div className="flex items-center justify-center gap-1.5">
                                            <StarRatingDisplay value={log.rating_arbitro} size="sm" />
                                            <span className="text-xs font-bold">{log.rating_arbitro.toFixed(1)}</span>
                                        </div>
                                    </div>
                                )}
                                {log.rating_atmosfera && log.rating_atmosfera > 0 && (
                                    <div className="text-center">
                                        <div className="text-[10px] text-[var(--text-muted)] mb-1">🏟️ Atmósfera</div>
                                        <div className="flex items-center justify-center gap-1.5">
                                            <StarRatingDisplay value={log.rating_atmosfera} size="sm" color="#16a34a" />
                                            <span className="text-xs font-bold">{log.rating_atmosfera.toFixed(1)}</span>
                                        </div>
                                    </div>
                                )}
                                {log.rating_garra && log.rating_garra > 0 && (
                                    <div className="text-center">
                                        <div className="text-[10px] text-[var(--text-muted)] mb-1">🔥 Garra</div>
                                        <div className="flex items-center justify-center gap-1.5">
                                            <StarRatingDisplay value={log.rating_garra} size="sm" color="#ef4444" />
                                            <span className="text-xs font-bold">{log.rating_garra.toFixed(1)}</span>
                                        </div>
                                    </div>
                                )}
                            </div>
                        )}
                    </motion.div>

                    {/* Player Ratings */}
                    {log.player_ratings && log.player_ratings.length > 0 && (
                        <motion.div
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.15 }}
                            className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-5"
                        >
                            <h3 className="text-sm font-semibold mb-3 flex items-center gap-2">
                                <User size={14} className="text-[var(--text-muted)]" />
                                Jugadores destacados
                            </h3>
                            <div className="space-y-2">
                                {log.player_ratings.map((pr) => (
                                    <div key={pr.id} className="flex items-center gap-3 py-1.5">
                                        <div className="flex-1 min-w-0">
                                            <div className="text-sm font-medium">{pr.player_name}</div>
                                            <div className="text-[10px] text-[var(--text-muted)]">
                                                {pr.player_team === 'local' ? log.equipo_local : log.equipo_visitante}
                                            </div>
                                        </div>
                                        <StarRatingDisplay value={pr.rating} size="sm" />
                                        <span className="text-xs font-bold tabular-nums w-7 text-right">{pr.rating.toFixed(1)}</span>
                                    </div>
                                ))}
                            </div>
                        </motion.div>
                    )}

                    {/* Review */}
                    {log.review_text && (
                        <motion.div
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.2 }}
                            className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-5"
                        >
                            {log.is_spoiler && !spoilerRevealed ? (
                                <button
                                    onClick={() => setSpoilerRevealed(true)}
                                    className="flex items-center gap-2 w-full p-4 rounded-xl bg-red-500/5 border border-red-500/20
                           text-sm text-red-400 hover:bg-red-500/10 transition-colors"
                                >
                                    <EyeOff size={16} />
                                    <span>Esta reseña contiene spoilers — tocar para revelar</span>
                                </button>
                            ) : (
                                <motion.div
                                    initial={{ opacity: 0 }}
                                    animate={{ opacity: 1 }}
                                    transition={{ duration: 0.4 }}
                                >
                                    {log.review_title && (
                                        <h3 className="text-base font-bold mb-3">{log.review_title}</h3>
                                    )}
                                    <p className="text-sm leading-relaxed whitespace-pre-wrap text-[var(--foreground)]/90">
                                        {log.review_text}
                                    </p>
                                </motion.div>
                            )}
                        </motion.div>
                    )}

                    {/* Tags */}
                    {log.tags && log.tags.length > 0 && (
                        <div className="flex gap-1.5 flex-wrap">
                            {log.tags.map(tag => (
                                <span key={tag} className="text-xs px-2.5 py-1 rounded-full bg-[#f59e0b]/10 text-[#f59e0b] font-medium">
                                    #{tag}
                                </span>
                            ))}
                        </div>
                    )}

                    {/* Comments */}
                    <motion.div
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.25 }}
                    >
                        <CommentSection partidoId={log.id} />
                    </motion.div>
                </div>
            </main>
            <NavBar />
        </>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { useAuth } from '@/contexts/AuthContext'
import { DesktopNav } from '@/components/DesktopNav'
import { NavBar } from '@/components/NavBar'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { motion } from 'framer-motion'
import { Trophy, Star, Shield, Share2, TrendingUp, Calendar, Zap } from 'lucide-react'
import { hapticFeedback } from '@/lib/helpers'
import { TeamLogo } from '@/components/TeamLogo'

export default function MyStatsPage() {
  const { user } = useAuth()
  const supabase = createClient()
  const [stats, setStats] = useState<any>(null)
  const [topTeam, setTopTeam] = useState<{ name: string; logo?: string; count: number } | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchStats = async () => {
      if (!user) return
      setLoading(true)

      // Stats base
      const { data } = await supabase
        .from('stats_usuario')
        .select('*')
        .eq('user_id', user.id)
        .single()

      // Ranking real — cuántos usuarios tienen más reseñas que vos
      const { count: rankingPos } = await supabase
        .from('stats_usuario')
        .select('*', { count: 'exact', head: true })
        .gt('total_resenas', data?.total_resenas || 0)

      // Equipo más visto
      const { data: logsData } = await supabase
        .from('match_logs')
        .select('equipo_local, equipo_visitante, logo_local, logo_visitante')
        .eq('user_id', user.id)

      if (logsData && logsData.length > 0) {
        const teamCount: Record<string, { count: number; logo?: string }> = {}
        logsData.forEach(l => {
          if (l.equipo_local) {
            teamCount[l.equipo_local] = {
              count: (teamCount[l.equipo_local]?.count || 0) + 1,
              logo: l.logo_local || undefined
            }
          }
          if (l.equipo_visitante) {
            teamCount[l.equipo_visitante] = {
              count: (teamCount[l.equipo_visitante]?.count || 0) + 1,
              logo: l.logo_visitante || undefined
            }
          }
        })
        const sorted = Object.entries(teamCount).sort((a, b) => b[1].count - a[1].count)
        if (sorted.length > 0) {
          setTopTeam({
            name: sorted[0][0],
            logo: sorted[0][1].logo,
            count: sorted[0][1].count
          })
        }
      }

      setStats({ ...data, ranking_pos: (rankingPos || 0) + 1 })
      setLoading(false)
    }

    fetchStats()
  }, [user])

  if (loading) return (
    <div className="min-h-screen bg-[var(--background)] flex items-center justify-center">
      <LoadingSpinner />
    </div>
  )

  if (!user) return (
    <div className="min-h-screen bg-[var(--background)] flex items-center justify-center">
      <p className="text-[var(--text-muted)] font-bold">Iniciá sesión para ver tus stats.</p>
    </div>
  )

  const cards = [
    {
      title: 'Partidos Logueados',
      value: stats?.total_resenas || 0,
      icon: Calendar,
      color: 'text-blue-500',
      bg: 'bg-blue-500/10'
    },
    {
      title: 'Rating Promedio',
      value: Number(stats?.rating_promedio || 0).toFixed(1),
      icon: Star,
      color: 'text-amber-500',
      bg: 'bg-amber-500/10'
    },
    {
      title: 'Aciertos Prode',
      value: stats?.prodes_correctos || 0,
      icon: Zap,
      color: 'text-purple-500',
      bg: 'bg-purple-500/10'
    },
    {
      title: 'Ranking Global',
      value: stats?.ranking_pos ? `#${stats.ranking_pos}` : '—',
      icon: Trophy,
      color: 'text-emerald-500',
      bg: 'bg-emerald-500/10'
    },
  ]

  return (
    <>
      <DesktopNav />
      <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-32 md:pt-20">
        <div className="max-w-4xl mx-auto px-6 py-12">

          <header className="text-center mb-12">
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              className="inline-block p-4 rounded-3xl bg-[var(--accent)]/10 text-[var(--accent)] mb-6"
            >
              <TrendingUp size={48} />
            </motion.div>
            <h1 className="text-5xl font-black tracking-tighter italic mb-4">MI RESUMEN 2025</h1>
            <p className="text-[var(--text-muted)] font-bold tracking-tight">Tu temporada en FutLog en números.</p>
          </header>

          {/* Cards de stats */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {cards.map((card, i) => {
              const Icon = card.icon
              return (
                <motion.div
                  key={card.title}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.1 }}
                  className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-8 flex flex-col items-center gap-4 text-center group hover:border-[var(--accent)] transition-all"
                >
                  <div className={`w-14 h-14 rounded-2xl ${card.bg} ${card.color} flex items-center justify-center group-hover:scale-110 transition-transform`}>
                    <Icon size={28} />
                  </div>
                  <div>
                    <p className="text-4xl font-black tracking-tighter tabular-nums mb-1">{card.value}</p>
                    <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-widest">{card.title}</p>
                  </div>
                </motion.div>
              )
            })}
          </div>

          {/* Equipo más visto */}
          {topTeam && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.5 }}
              className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-6 flex items-center gap-4 mb-8"
            >
              <TeamLogo src={topTeam.logo} teamName={topTeam.name} size={56} />
              <div>
                <p className="text-2xl font-black tracking-tighter">{topTeam.name}</p>
                <p className="text-xs text-[var(--text-muted)] font-bold uppercase tracking-widest">
                  Tu equipo más visto · {topTeam.count} partido{topTeam.count !== 1 ? 's' : ''}
                </p>
              </div>
            </motion.div>
          )}

          {/* Compartir */}
          <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-8 relative overflow-hidden">
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="max-w-md">
                <h2 className="text-2xl font-black tracking-tight mb-3">¿Listo para compartir tu pasión?</h2>
                <p className="text-sm text-[var(--text-muted)] font-medium mb-6">
                  Compartí tus estadísticas con tus amigos y mostrá tu amor por el fútbol.
                </p>
                <button
                  onClick={() => {
                    hapticFeedback(50)
                    if (navigator.share) {
                      navigator.share({
                        title: 'Mis stats en FutLog',
                        text: `Logueé ${stats?.total_resenas || 0} partidos con un rating promedio de ${Number(stats?.rating_promedio || 0).toFixed(1)}⭐`,
                        url: window.location.href,
                      }).catch(() => {})
                    } else {
                      navigator.clipboard.writeText(window.location.href)
                    }
                  }}
                  className="w-full md:w-auto bg-[var(--foreground)] text-[var(--background)] px-8 py-4 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-2 hover:opacity-90 transition-all active:scale-95"
                >
                  <Share2 size={16} /> Compartir mis stats
                </button>
              </div>
              <div className="w-full md:w-64 aspect-square bg-gradient-to-br from-[var(--accent)] to-[#6366f1] rounded-3xl rotate-3 shadow-2xl flex items-center justify-center text-white">
                <Shield size={100} className="drop-shadow-lg" />
              </div>
            </div>
            <div className="absolute top-0 right-0 w-64 h-64 bg-[var(--accent)]/5 rounded-full blur-3xl -mr-32 -mt-32" />
          </div>

        </div>
      </main>
      <NavBar />
    </>
  )
}

// src/app/page.tsx
'use client'

import { useState, useEffect, useMemo, Suspense } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import Link from 'next/link'
import { useLanguage } from '@/contexts/LanguageContext'
import { LoadingSpinner } from '@/components/LoadingSpinner'
import { PublicOnboarding } from '@/components/PublicOnboarding'
import { motion, AnimatePresence } from 'framer-motion'
import { usePartidos } from '@/hooks/usePartidos'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useTheme } from '@/contexts/ThemeContext'
import { FixtureTable } from '@/components/FixtureTable'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { PartidoCardSkeleton } from '@/components/skeletons/PartidoCardSkeleton'
import { TablaContent } from '@/components/TablaContent'
import { GoleadoresContent } from '@/components/GoleadoresContent'
import { ErrorMessage } from '@/components/ui/ErrorMessage'
import { Search, BarChart3, Trophy, Calendar, Globe, Users, Newspaper } from 'lucide-react'
import { PullToRefresh } from '@/components/PullToRefresh'
import { FeedGlobal } from '@/components/feed/FeedGlobal'
import { CommunityHighlights } from '@/components/CommunityHighlights'
import { NewsTab } from '@/components/NewsTab'
import { ThemeToggle } from '@/components/ThemeToggle'
import { LiveMatchesStrip } from '@/components/LiveMatchesStrip'
import { LeagueChips } from '@/components/LeagueChips'
import { hapticFeedback } from '@/lib/helpers'
import { LIGAS, type Liga } from '@/lib/constants'
import type { Partido } from '@/types'

type HomeTab = 'partidos' | 'tabla' | 'goleadores' | 'fixtures' | 'comunidad' | 'noticias'

const TABS: { id: HomeTab; label: string; icon: React.ReactNode }[] = [
  { id: 'partidos', label: 'Partidos', icon: <span className="text-sm">⚽</span> },
  { id: 'comunidad', label: 'Comunidad', icon: <Users size={14} /> },
  { id: 'tabla', label: 'Tabla', icon: <BarChart3 size={14} /> },
  { id: 'goleadores', label: 'Goleadores', icon: <Trophy size={14} /> },
  { id: 'noticias', label: 'Noticias', icon: <Newspaper size={14} /> },
]

function toLocalDateStr(date: Date): string {
  return date.toISOString().split('T')[0]
}

function formatDateLabel(date: Date, t: any, localeFormat: string): string {
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  const target = new Date(date)
  target.setHours(0, 0, 0, 0)
  const diff = Math.round((target.getTime() - today.getTime()) / 86400000)

  if (diff === 0) return t('common.today') || 'Hoy'
  if (diff === -1) return t('common.yesterday') || 'Ayer'
  if (diff === 1) return t('common.tomorrow') || 'Mañana'

  return target.toLocaleDateString(localeFormat, {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
  })
}

function generateDateRange(): Date[] {
  const dates: Date[] = []
  const today = new Date()
  today.setHours(0, 0, 0, 0)
  for (let i = -7; i <= 7; i++) {
    const d = new Date(today)
    d.setDate(d.getDate() + i)
    dates.push(d)
  }
  return dates
}

function HomeContent() {
  const { user } = useAuth()
  const { t, language } = useLanguage()
  const localeFormat = language === 'en' ? 'en-US' : language === 'pt' ? 'pt-BR' : 'es-AR'
  const router = useRouter()
  const searchParams = useSearchParams()

  const [activeTab, setActiveTab] = useState<HomeTab>(() => {
    const tab = searchParams.get('tab')
    if (tab && ['partidos', 'tabla', 'goleadores', 'fixtures', 'comunidad', 'noticias'].includes(tab)) {
      return tab as HomeTab
    }
    return 'partidos'
  })

  const [filtroLiga, setFiltroLiga] = useState<Liga | 'Favoritos'>('Todos')
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedDate, setSelectedDate] = useState<string>(toLocalDateStr(new Date()))
  const [favoritos, setFavoritos] = useState<string[]>([])

  const dateRange = useMemo(() => generateDateRange(), [])
  const { partidos, loading, error, refetch } = usePartidos(filtroLiga === 'Favoritos' ? 'Todos' : filtroLiga as Liga)

  useEffect(() => {
    if (user) {
      supabase
        .from('favoritos')
        .select('equipo_nombre')
        .eq('user_id', user.id)
        .then(({ data }) => {
          if (data) setFavoritos(data.map((f: any) => f.equipo_nombre))
        })
    }
  }, [user])

  useEffect(() => {
    const tab = searchParams.get('tab')
    if (tab && ['partidos', 'tabla', 'goleadores', 'fixtures', 'comunidad', 'noticias'].includes(tab)) {
      setActiveTab(tab as HomeTab)
    }
  }, [searchParams])

  const handleTabChange = (tab: HomeTab) => {
    setActiveTab(tab)
    const url = tab === 'partidos' ? '/' : `/?tab=${tab}`
    window.history.replaceState(null, '', url)
  }

  const partidosFiltrados = useMemo(() => {
    return partidos.filter(partido => {
      const matchesSearch = !searchQuery || (
        partido?.equipo_local?.toLowerCase()?.includes(searchQuery.toLowerCase()) ||
        partido?.equipo_visitante?.toLowerCase()?.includes(searchQuery.toLowerCase())
      )
      const matchesDate = !selectedDate || partido?.fecha_inicio?.startsWith(selectedDate)
      const matchesFavorites = filtroLiga !== 'Favoritos' || (
        favoritos.includes(partido?.equipo_local || '') ||
        favoritos.includes(partido?.equipo_visitante || '')
      )
      return matchesSearch && matchesDate && matchesFavorites
    })
  }, [partidos, searchQuery, selectedDate, filtroLiga, favoritos])

  const fixtureDisplay = useMemo(() => {
    if (partidosFiltrados.length > 0) {
      return { matches: partidosFiltrados, type: 'exact' as const, nearestDate: undefined }
    }
    if (partidos.length > 0) {
      const futureDates = new Map<string, Partido[]>()
      partidos.forEach(p => {
        const dateStr = p.fecha_inicio?.split('T')[0]
        if (dateStr && dateStr >= selectedDate) {
          const existing = futureDates.get(dateStr) || []
          existing.push(p)
          futureDates.set(dateStr, existing)
        }
      })
      const sortedDates = [...futureDates.keys()].sort()
      for (const date of sortedDates) {
        if (date > selectedDate) {
          return { matches: futureDates.get(date)!, type: 'nearest' as const, nearestDate: date }
        }
      }
      const pastDates = [...new Map(
        partidos.map(p => [p.fecha_inicio?.split('T')[0], p])
      ).keys()].filter(d => d && d < selectedDate).sort().reverse()
      for (const date of pastDates) {
        const pastMatches = partidos.filter(p => p.fecha_inicio?.startsWith(date!))
        if (pastMatches.length > 0) {
          return { matches: pastMatches, type: 'nearest' as const, nearestDate: date }
        }
      }
    }
    return { matches: [], type: 'example' as const, nearestDate: undefined }
  }, [partidosFiltrados, partidos, selectedDate])

  const liveCount = partidos.filter(p => p.estado === 'EN_JUEGO').length
  const livePartidos = partidos.filter(p => p.estado === 'EN_JUEGO')
  const currentLigaName = filtroLiga === 'Todos' || filtroLiga === 'Favoritos' ? undefined : filtroLiga

  return (
    <>
      <DesktopNav />
      <PullToRefresh onRefresh={async () => { await refetch() }}>
        <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-28 md:pt-20">
          <div className="relative z-10">

            {/* Header mobile */}
            <div className="md:hidden px-4 py-3 flex justify-between items-center border-b border-[var(--card-border)] bg-[var(--card-bg)] z-30 sticky top-0">
              <h1 className="text-xl font-black tracking-tighter text-[var(--foreground)]">FutLog</h1>
              <div className="flex items-center gap-1.5">
                <button
                  title="Desafíos"
                  onClick={() => document.dispatchEvent(new CustomEvent('open-challenges'))}
                  className="p-1.5 rounded-md text-[var(--text-muted)] hover:text-[#8b5cf6] hover:bg-[#8b5cf6]/10 transition-all"
                >
                  <Trophy size={16} />
                </button>
                <div className="w-px h-4 bg-[var(--card-border)] mx-0.5" />
                <button
                  onClick={() => router.push('/buscar')}
                  className="p-1.5 rounded-md text-[var(--text-muted)] hover:text-[var(--foreground)] hover:bg-[var(--card-bg)]"
                >
                  <Search size={16} />
                </button>
                <ThemeToggle compact />
                {!user && (
                  <Link href="/login" className="ml-1 px-2 py-1 text-[10px] font-bold bg-[var(--accent)] text-[var(--background)] rounded uppercase tracking-tight">
                    Ingresar
                  </Link>
                )}
              </div>
            </div>

            <div className="max-w-4xl mx-auto px-4 mt-2">

              {/* League chips */}
              <div className="sticky top-0 md:top-[68px] z-20 bg-[var(--background)]/95 backdrop-blur-sm py-3 -mx-4 px-4 border-b border-[var(--card-border)] mb-4">
                <LeagueChips
                  activeLiga={filtroLiga}
                  onSelect={(l) => {
                    hapticFeedback(10)
                    setFiltroLiga(l)
                  }}
                />
              </div>

              {/* Tabs — solo mobile, en desktop usa DesktopNav */}
              <div className="flex md:hidden gap-1 overflow-x-auto no-scrollbar mb-6 -mx-1 px-1">
                {TABS.map(tab => (
                  <button
                    key={tab.id}
                    onClick={() => handleTabChange(tab.id)}
                    className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-black whitespace-nowrap transition-all
                      ${activeTab === tab.id
                        ? 'bg-[var(--foreground)] text-[var(--background)]'
                        : 'text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'
                      }`}
                  >
                    {tab.icon}
                    {tab.label}
                    {tab.id === 'partidos' && liveCount > 0 && (
                      <span className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse" />
                    )}
                  </button>
                ))}
              </div>

              {!user && activeTab === 'partidos' && (
                <div className="mb-4 p-4 bg-[var(--card-bg)] rounded-2xl border border-dashed border-[var(--card-border)] text-center">
                  <p className="text-xs text-[var(--text-muted)] font-medium">
                    Ve los resultados en tiempo real. Para participar del Prode y ratear jugadores, creá tu cuenta.
                  </p>
                </div>
              )}

              {/* Contenido por tab */}
              <div className="space-y-10 pb-10">
                <AnimatePresence mode="wait">
                  <motion.div
                    key={activeTab}
                    initial={{ opacity: 0, y: 15 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.98 }}
                    transition={{ duration: 0.25, ease: 'easeOut' }}
                    className="w-full"
                  >
                    {/* TAB: NOTICIAS */}
                    {activeTab === 'noticias' && <NewsTab />}

                    {/* TAB: COMUNIDAD */}
                    {activeTab === 'comunidad' && (
                      <div className="space-y-8">
                        <CommunityHighlights />
                        <div className="pt-4 border-t border-[var(--card-border)]/50">
                          <div className="flex items-center justify-between mb-6 px-1">
                            <h2 className="text-[var(--foreground)] font-black text-xl italic tracking-tighter uppercase">
                              💬 La Tribuna Habla
                            </h2>
                            <Link
                              href="/comunidad"
                              className="text-[10px] font-black text-[var(--accent)] hover:opacity-70 uppercase tracking-widest transition-opacity"
                            >
                              Ver todo →
                            </Link>
                          </div>
                          <FeedGlobal />
                        </div>
                      </div>
                    )}

                    {/* TAB: TABLA */}
                    {activeTab === 'tabla' && (
                      <TablaContent ligaExterna={currentLigaName || 'Liga Profesional'} />
                    )}

                    {/* TAB: GOLEADORES */}
                    {activeTab === 'goleadores' && (
                      <GoleadoresContent ligaExterna={currentLigaName || 'Liga Profesional'} />
                    )}

                    {/* TAB: PARTIDOS (default) */}
                    {(activeTab === 'partidos' || activeTab === 'fixtures') && (
                      <>
                        {/* Live strip */}
                        <LiveMatchesStrip partidos={livePartidos} />

                        {/* Date navigation */}
                        <div className="flex items-center gap-1.5 overflow-x-auto no-scrollbar py-1">
                          {dateRange.map((date) => {
                            const dateStr = toLocalDateStr(date)
                            const label = formatDateLabel(date, t, localeFormat)
                            const isSelected = dateStr === selectedDate
                            const isToday = dateStr === toLocalDateStr(new Date())
                            return (
                              <button
                                key={dateStr}
                                onClick={() => {
                                  hapticFeedback(5)
                                  setSelectedDate(dateStr)
                                }}
                                className={`flex flex-col items-center justify-center min-w-[3.5rem] py-1.5 px-2 rounded-xl border transition-all
                                  ${isSelected
                                    ? 'bg-[var(--foreground)] border-[var(--foreground)] text-[var(--background)] shadow-md'
                                    : isToday
                                      ? 'bg-[var(--card-bg)] border-[var(--accent)]/50 text-[var(--foreground)]'
                                      : 'bg-[var(--card-bg)] border-[var(--card-border)] text-[var(--text-muted)] hover:border-[var(--card-border-hover)]'
                                  }`}
                              >
                                <span className={`text-[9px] font-black uppercase tracking-wider ${isSelected ? 'opacity-90' : 'opacity-70'}`}>
                                  {['Hoy','Mañana','Ayer'].includes(label) ? ' ' : new Date(dateStr + 'T12:00:00').toLocaleDateString(localeFormat, { weekday: 'short' })}
                                </span>
                                <span className={`text-sm font-black tracking-tighter mt-0.5 ${isSelected ? 'text-[var(--background)]' : ''}`}>
                                  {['Hoy','Mañana','Ayer'].includes(label) ? label : new Date(dateStr + 'T12:00:00').getDate()}
                                </span>
                              </button>
                            )
                          })}
                        </div>

                        {/* Fixture */}
                        <section>
                          <div className="flex items-center justify-between mb-3 px-1">
                            <div className="flex items-center gap-2">
                              <h2 className="text-[12px] font-bold tracking-tight capitalize">
                                Fixture: {filtroLiga === 'Todos' || filtroLiga === 'Favoritos'
                                  ? formatDateLabel(new Date(selectedDate + 'T12:00:00'), t, localeFormat).toUpperCase()
                                  : filtroLiga.toUpperCase()}
                              </h2>
                              {liveCount > 0 && (
                                <span className="px-1.5 py-0.5 rounded bg-red-100 text-red-600 text-[8px] font-black animate-pulse flex items-center gap-1">
                                  {liveCount} VIVO
                                </span>
                              )}
                            </div>
                          </div>

                          {loading ? (
                            <div className="space-y-2">
                              {Array(4).fill(0).map((_, i) => (
                                <div key={i} className="h-12 bg-[var(--card-bg)] border border-[var(--card-border)] animate-shimmer" />
                              ))}
                            </div>
                          ) : error ? (
                            <ErrorMessage message="No pudimos cargar los partidos." onRetry={refetch} />
                          ) : (
                            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm">
                              {fixtureDisplay.type === 'nearest' && fixtureDisplay.nearestDate && (
                                <div className="px-4 py-2.5 bg-[var(--accent-green)]/10 border-b border-[var(--card-border)] flex items-center justify-between">
                                  <p className="text-[10px] font-bold text-[var(--accent)] capitalize tracking-tight">
                                    📅 Próximos: {formatDateLabel(new Date(fixtureDisplay.nearestDate + 'T12:00:00'), t, localeFormat)}
                                  </p>
                                  <button
                                    onClick={() => setSelectedDate(fixtureDisplay.nearestDate!)}
                                    className="text-[9px] font-bold text-[var(--accent)] underline capitalize"
                                  >
                                    Ir a esa fecha
                                  </button>
                                </div>
                              )}
                              {fixtureDisplay.type === 'example' && (
                                <div className="px-4 py-2.5 bg-[var(--hover-bg)] border-b border-[var(--card-border)]">
                                  <p className="text-[10px] font-bold text-[var(--text-muted)] text-center">
                                    No hay partidos programados para esta fecha
                                  </p>
                                </div>
                              )}
                              {fixtureDisplay.matches.length > 0
                                ? <FixtureTable partidos={fixtureDisplay.matches} />
                                : (
                                  <div className="p-8 text-center">
                                    <p className="text-[var(--text-muted)] text-sm">Sin partidos para esta fecha</p>
                                  </div>
                                )
                              }
                            </div>
                          )}
                        </section>
                      </>
                    )}
                  </motion.div>
                </AnimatePresence>
              </div>
            </div>
          </div>
        </main>
      </PullToRefresh>
      <NavBar />
      {!user && <PublicOnboarding />}
    </>
  )
}

export default function Home() {
  return (
    <Suspense fallback={
      <div className="min-h-screen bg-[var(--background)] p-4 flex flex-col gap-4 pt-24 max-w-5xl mx-auto">
        {Array(4).fill(0).map((_, i) => <PartidoCardSkeleton key={i} />)}
      </div>
    }>
      <HomeContent />
    </Suspense>
  )
}

