      </main>

      {/* Modal seguidores/siguiendo */}
      {followModal && (
        <FollowListModal
          userId={initialProfile.id}
          type={followModal}
          onClose={() => setFollowModal(null)}
        />
      )}

      <NavBar />
    </>
  )
}

