                <div className="mt-8 mb-4 border-t border-[var(--card-border)] pt-6 text-center">
                  <div className="flex justify-center flex-wrap gap-3 text-xs font-bold text-[var(--text-muted)]">
                    <Link href="/privacy" className="hover:text-[#16a34a] hover:underline transition-colors">{t('footer.privacy')}</Link>
                    <span>•</span>
                    <Link href="/terms" className="hover:text-[#16a34a] hover:underline transition-colors">{t('footer.terms')}</Link>
                    <span>•</span>
                    <Link href="/sources" className="hover:text-[#16a34a] hover:underline transition-colors">{t('footer.sources')}</Link>
                  </div>
                  <p className="text-[10px] text-[var(--text-muted)] mt-4 opacity-50">
                    FutLog Beta © {new Date().getFullYear()}
                  </p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <NavBar />
      </main>

      {/* Modal Editor de Perfil */}
      <AnimatePresence>
        {showEditor && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-6 overflow-y-auto"
            onClick={() => setShowEditor(false)}
          >
            <motion.div
              initial={{ scale: 0.9, y: 20 }}
              animate={{ scale: 1, y: 0 }}
              exit={{ scale: 0.9, y: 20 }}
              onClick={(e) => e.stopPropagation()}
              className="bg-[var(--card-bg)] p-6 w-full max-w-lg border border-[var(--card-border)] my-auto"
              style={{ borderRadius: 'var(--radius)' }}
            >
              <div className="flex items-center justify-between mb-6 border-b border-[var(--card-border)] pb-2 border-dashed">
                <h2 className="text-sm font-black capitalize tracking-widest">✏️ Editar Perfil</h2>
                <button
                  onClick={() => setShowEditor(false)}
                  className="w-7 h-7 flex items-center justify-center border border-[var(--card-border)] bg-[var(--background)] text-[var(--text-muted)] hover:text-[var(--foreground)]"
                  style={{ borderRadius: 'var(--radius)' }}
                >
                  ✕
                </button>
              </div>

              <div className="space-y-6">
                {/* Avatar Selection */}
                <div className="space-y-3 pb-2 pt-2 border-t border-[var(--card-border)] border-dashed">
                  <label className="block text-[10px] font-black capitalize tracking-widest text-[var(--foreground)] opacity-90 mx-1">
                    Foto de perfil
                  </label>

                  <AvatarUploader
                    currentAvatarUrl={editAvatar}
                    onUploadSuccess={(url) => setEditAvatar(url)}
                  />

                  <p className="text-[8px] text-center text-[var(--text-muted)] font-black capitalize mt-2">
                    Toca la imagen para subir (MÁX 5MB)
                  </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Username */}
                  <div>
                    <label className="text-[9px] font-black text-[var(--text-muted)] capitalize mb-2 block">
                      Nombre de Usuario
                    </label>
                    <input
                      type="text"
                      value={editUsername}
                      onChange={(e) => setEditUsername(e.target.value)}
                      placeholder="Tu nombre..."
                      maxLength={20}
                      className="w-full bg-[var(--background)] border border-[var(--card-border)] px-4 py-3 
                                    focus:outline-none focus:border-[var(--foreground)] transition-colors"
                      style={{ borderRadius: 'var(--radius)' }}
                    />
                  </div>

                  {/* Equipo Favorito */}
                  <div>
                    <label className="text-[9px] font-black text-[var(--text-muted)] capitalize mb-2 block">
                      Equipo Favorito
                    </label>
                    <div className="relative group">
                      <input
                        type="text"
                        value={editEquipo}
                        readOnly
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] px-4 py-3 cursor-default"
                        style={{ borderRadius: 'var(--radius)' }}
                        placeholder="Seleccionar abajo..."
                      />
                      <div className="absolute inset-y-0 right-3 flex items-center pointer-events-none opacity-50 text-[10px]">▼</div>
                    </div>
                  </div>
                </div>

                {/* Team Selector Component */}
                <div className="bg-[var(--background)] p-4 border border-[var(--card-border)] text-sm mb-4" style={{ borderRadius: 'var(--radius)' }}>
                  <p className="text-[9px] font-black text-[var(--text-muted)] capitalize mb-2 border-b border-[var(--card-border)] pb-1 border-dashed">Buscar Equipo</p>
                  <EquipoSelector selectedEquipo={editEquipo} onSelect={setEditEquipo} />
                </div>

                {/* Idioma Selector */}
                <div>
                  <label className="text-[9px] font-black text-[var(--text-muted)] capitalize mb-2 block">
                    {t('profile.settings.language')}
                  </label>
                  <div className="flex gap-1">
                    {(['es', 'en', 'pt'] as const).map(lang => (
                      <button
                        key={lang}
                        onClick={(e) => {
                          e.preventDefault()
                          setLanguage(lang)
                        }}
                        className={`flex-1 py-2 px-3 border transition-all text-[9px] font-black capitalize
                          ${language === lang
                            ? 'bg-[var(--foreground)] border-[var(--foreground)] text-[var(--background)]'
                            : 'bg-[var(--background)] border-[var(--card-border)] text-[var(--text-muted)] hover:border-[var(--foreground)]'}`}
                        style={{ borderRadius: 'var(--radius)' }}
                      >
                        {lang === 'es' ? '🇪🇸 ES' : lang === 'en' ? '🇺🇸 EN' : '🇧🇷 PT'}
                      </button>
                    ))}
                  </div>
                </div>

                {/* Mensaje de guardado */}
                {saveMessage && (
                  <div className="text-center p-3 rounded-xl bg-[#16a34a]/10 text-[#16a34a] font-bold text-sm animate-pulse">
                    {saveMessage}
                  </div>
                )}

                {/* Botón Guardar */}
                <div className="pt-2">
                  <Button
                    onClick={handleSaveProfile}
                    loading={saving}
                    fullWidth
                    size="sm"
                  >
                    GUARDAR CAMBIOS
                  </Button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Follow List Modal */}
      {user && (
        <FollowListModal
          isOpen={followModalState.isOpen}
          onClose={() => setFollowModalState(prev => ({ ...prev, isOpen: false }))}
          userId={user.id}
          type={followModalState.type}
          title={followModalState.title}
        />
      )}
    </>
  )
}

// src/app/prode/page.tsx
'use client'

import { useState, useMemo, useEffect, useCallback } from 'react'
import { usePronosticos } from '@/hooks/usePronosticos'
import { useAuth } from '@/contexts/AuthContext'
import { ProdeCard } from '@/components/ProdeCard'
import { ProdeStats } from '@/components/ProdeStats'
import { SimuladorPuntos } from '@/components/SimuladorPuntos'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { PartidoCardSkeleton } from '@/components/skeletons/PartidoCardSkeleton'
import { ReglasPuntajeModal } from '@/components/ReglasPuntajeModal'
import { useRouter } from 'next/navigation'
import { useToast } from '@/contexts/ToastContext'
import { fetchFixturesWithSyncAction } from '@/app/actions/football'
import { supabase } from '@/lib/supabase'
import type { Partido } from '@/types'
import confetti from 'canvas-confetti'


import { LIGAS, type Liga } from '@/lib/constants'
type FiltroPronostico = 'todos' | 'sin_pronosticar' | 'pronosticados'

export default function ProdePage() {
    const router = useRouter()
    const { user } = useAuth()
    const { showToast } = useToast()
    const [filtroLiga, setFiltroLiga] = useState<Liga>('Todos')
    const [filtroPronostico, setFiltroPronostico] = useState<FiltroPronostico>('todos')
    const [partidos, setPartidos] = useState<Partido[]>([])
    const [loadingPartidos, setLoadingPartidos] = useState(true)
    const { pronosticos, loading: loadingPronosticos, guardarPronostico } = usePronosticos()
    const [historialReciente, setHistorialReciente] = useState<{
      partido_id: string
      tipo_acierto: string
      puntos: number
      partido?: { equipo_local: string; equipo_visitante: string }
    }[]>([])

    // Fetch partidos synced with Supabase (returns UUIDs)
    const fetchPartidos = useCallback(async () => {
        try {
            setLoadingPartidos(true)
            const ligaName = filtroLiga === 'Todos' ? 'Liga Profesional' : filtroLiga
            const data = await fetchFixturesWithSyncAction(ligaName)
            setPartidos(data || [])
        } catch (err) {
            console.error('Error fetching synced partidos:', err)
        } finally {
            setLoadingPartidos(false)
        }
    }, [filtroLiga])

    useEffect(() => {
        fetchPartidos()
    }, [fetchPartidos])

    // Manejar redirección en useEffect para evitar errores de hooks
    useEffect(() => {
        if (!user && !loadingPronosticos) {
            router.push('/login')
        }
    }, [user, loadingPronosticos, router])

    // Confetti on new hits
    useEffect(() => {
      const checkNewAciertos = async () => {
        if (!user) return
        const lastVisit = localStorage.getItem('prode_last_visit')
        const now = new Date().toISOString()
        const { data } = await supabase
          .from('puntuacion_prode')
          .select('tipo_acierto, puntos')
          .eq('user_id', user.id)
          .in('tipo_acierto', ['exacto', 'ganador_diferencia'])
          .gte('calculated_at', lastVisit || new Date(Date.now() - 86400000).toISOString())
        if (data && data.length > 0) {
          const hasExacto = data.some(d => d.tipo_acierto === 'exacto')
          setTimeout(() => {
            if (hasExacto) {
              confetti({ particleCount: 150, spread: 70, origin: { y: 0.6 }, colors: ['#16a34a', '#f59e0b', '#ffffff'] })
              showToast(`🎯 ¡Acertaste exacto! +${data[0].puntos} puntos`, 'success')
            } else {
              confetti({ particleCount: 80, spread: 50, origin: { y: 0.6 } })
              showToast(`✅ ¡Acertaste el resultado! +${data[0].puntos} puntos`, 'success')
            }
          }, 800)
        }
        localStorage.setItem('prode_last_visit', now)
      }
      checkNewAciertos()
    }, [user])

    // Fetch historial
    useEffect(() => {
      const fetchHistorial = async () => {
        if (!user) return
        const { data } = await supabase
          .from('puntuacion_prode')
          .select(`
            partido_id, tipo_acierto, puntos,
            partido:partidos(equipo_local, equipo_visitante)
          `)
          .eq('user_id', user.id)
          .order('calculated_at', { ascending: false })
          .limit(5)
        if (data) setHistorialReciente(data as any)
      }
      fetchHistorial()
    }, [user])

    // Filtrar solo partidos en PREVIA o próximos
    const partidosDisponibles = useMemo(() => {
        return partidos.filter(partido => {
            const fechaInicio = new Date(partido.fecha_inicio)
            const ahora = new Date()
            return fechaInicio > ahora || partido.estado === 'PREVIA'
        }).sort((a, b) => {
            return new Date(a.fecha_inicio).getTime() - new Date(b.fecha_inicio).getTime()
        })
    }, [partidos])

    // Aplicar filtro de pronóstico
    const partidosFiltrados = useMemo(() => {
        if (filtroPronostico === 'todos') return partidosDisponibles

        return partidosDisponibles.filter(partido => {
            const tienePronostico = pronosticos.some(p => String(p.partido_id) === String(partido.id))
            return filtroPronostico === 'pronosticados' ? tienePronostico : !tienePronostico
        })
    }, [partidosDisponibles, pronosticos, filtroPronostico])

    // Contadores para los tabs
    const contadores = useMemo(() => {
        const sinPronosticar = partidosDisponibles.filter(p =>
            !pronosticos.some(pr => String(pr.partido_id) === String(p.id))
        ).length
        const conPronostico = partidosDisponibles.length - sinPronosticar
        return { todos: partidosDisponibles.length, sinPronosticar, conPronostico }
    }, [partidosDisponibles, pronosticos])

    const handleGuardarPronostico = async (partidoId: string | number, golesLocal: number, golesVisitante: number) => {
        // Toast is now handled inside ProdeCard for better UX
        await guardarPronostico(String(partidoId), golesLocal, golesVisitante)
    }

    const getPronosticoExistente = (partidoId: string | number) => {
        return pronosticos.find(p => String(p.partido_id) === String(partidoId)) || null
    }

    // Mostrar loader o nada mientras redirige
    if (!user && !loadingPronosticos) {
        return null
    }

    return (
        <>
            <DesktopNav />

            <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20 overflow-x-hidden">
                {/* Header */}
                <div className="px-6 py-8">
                    <div className="max-w-4xl mx-auto">
                        <div className="flex items-center justify-between">
                            <div>
                                <h1 className="text-2xl md:text-3xl font-bold tracking-tight mb-2">
                                    Hacer Pronósticos 🎯
                                </h1>
                                <p className="text-sm text-[var(--text-muted)] font-medium">
                                    Predecí los resultados y sumá puntos.
                                </p>
                            </div>
                            <ReglasPuntajeModal />
                        </div>
                    </div>
                </div>

                {/* Filtros de liga */}
                <div className="px-6 mb-8">
                    <div className="max-w-4xl mx-auto">
                        <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
                            {LIGAS.map(liga => (
                                <button
                                    key={liga}
                                    onClick={() => setFiltroLiga(liga)}
                                    className={`px-5 py-2.5 rounded-xl text-xs font-bold capitalize tracking-tight transition-all whitespace-nowrap border
                             ${filtroLiga === liga
                                            ? 'bg-[var(--accent)] text-white border-[var(--accent)] shadow-lg shadow-purple-500/20'
                                            : 'bg-[var(--card-bg)] text-[var(--text-muted)] hover:text-[var(--foreground)] border-[var(--card-border)]'
                                        }`}
                                >
                                    {liga}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Filtros de pronóstico */}
                <div className="px-6 mb-10">
                    <div className="max-w-4xl mx-auto">
                        <div className="flex gap-2 bg-[var(--card-bg)] p-1.5 rounded-2xl border border-[var(--card-border)] w-fit shadow-sm">
                            <button
                                onClick={() => setFiltroPronostico('todos')}
                                className={`px-5 py-2.5 rounded-xl text-[10px] font-bold capitalize tracking-tight transition-all flex items-center gap-2
                                    ${filtroPronostico === 'todos'
                                        ? 'bg-[var(--background)] text-[var(--foreground)] shadow-sm'
                                        : 'text-[var(--text-muted)]'}`}
                            >
                                Todos <span className="bg-[var(--card-border)] px-2 py-0.5 rounded-full text-[9px] font-bold">{contadores.todos}</span>
                            </button>
                            <button
                                onClick={() => setFiltroPronostico('sin_pronosticar')}
                                className={`px-5 py-2.5 rounded-xl text-[10px] font-bold capitalize tracking-tight transition-all flex items-center gap-2
                                    ${filtroPronostico === 'sin_pronosticar'
                                        ? 'bg-[#ef4444]/10 text-[#ef4444] shadow-sm'
                                        : 'text-[var(--text-muted)]'}`}
                            >
                                Pendientes <span className="bg-[#ef4444]/20 text-[#ef4444] px-2 py-0.5 rounded-full text-[9px] font-bold">{contadores.sinPronosticar}</span>
                            </button>
                            <button
                                onClick={() => setFiltroPronostico('pronosticados')}
                                className={`px-5 py-2.5 rounded-xl text-[10px] font-bold capitalize tracking-tight transition-all flex items-center gap-2
                                    ${filtroPronostico === 'pronosticados'
                                        ? 'bg-[var(--accent)]/10 text-[var(--accent)] shadow-sm'
                                        : 'text-[var(--text-muted)]'}`}
                            >
                                Completados <span className={`px-2 py-0.5 rounded-full text-[9px] font-bold ${filtroPronostico === 'pronosticados' ? 'bg-[var(--accent)]/20 text-[var(--accent)]' : 'bg-[var(--card-border)]'}`}>{contadores.conPronostico}</span>
                            </button>
                        </div>
                    </div>
                </div>

                {/* Stats del usuario y Simulador */}
                <div className="px-6 mb-16">
                    <div className="max-w-4xl mx-auto grid grid-cols-1 md:grid-cols-3 gap-10">
                        {/* Mis Stats (Col 1) */}
                        <div className="md:col-span-1">
                            <ProdeStats />
                        </div>

                        {/* Simulador (Col 2-3) */}
                        <div className="md:col-span-2">
                            <SimuladorPuntos />
                        </div>
                    </div>
                </div>

                {/* Historial reciente */}
                {historialReciente.length > 0 && (
                    <div className="px-6 mb-8">
                        <div className="max-w-4xl mx-auto">
                            <h3 className="text-xs font-black uppercase tracking-widest text-[var(--text-muted)] mb-3">
                                Mis últimos resultados
                            </h3>
                            <div className="flex flex-col gap-2">
                                {historialReciente.map((h, i) => {
                                    const icono = h.tipo_acierto === 'exacto' ? '🎯'
                                        : h.tipo_acierto === 'ganador_diferencia' ? '✅'
                                        : h.tipo_acierto === 'ganador' ? '🟡'
                                        : '❌'
                                    const color = h.tipo_acierto === 'exacto' ? 'border-green-500/30 bg-green-500/5'
                                        : h.tipo_acierto === 'ganador_diferencia' ? 'border-blue-500/30 bg-blue-500/5'
                                        : h.tipo_acierto === 'ganador' ? 'border-yellow-500/30 bg-yellow-500/5'
                                        : 'border-[var(--card-border)] bg-[var(--card-bg)]'
                                    return (
                                        <div key={i} className={`flex items-center gap-3 p-3 rounded-2xl border ${color}`}>
                                            <span className="text-xl">{icono}</span>
                                            <div className="flex-1 min-w-0">
                                                <p className="text-xs font-bold truncate">
                                                    {(h.partido as any)?.equipo_local} vs {(h.partido as any)?.equipo_visitante}
                                                </p>
                                                <p className="text-[10px] text-[var(--text-muted)] capitalize">{h.tipo_acierto.replace('_', ' ')}</p>
                                            </div>
                                            {h.puntos > 0 && (
                                                <span className="text-xs font-black text-green-500">+{h.puntos} pts</span>
                                            )}
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    </div>
                )}

                {/* Grid de partidos */}
                <div className="px-6">
                    <div className="max-w-4xl mx-auto">
                        {loadingPartidos || loadingPronosticos ? (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                {Array(6).fill(0).map((_, idx) => (
                                    <PartidoCardSkeleton key={idx} />
                                ))}
                            </div>
                        ) : partidosFiltrados.length === 0 ? (
                            <div className="text-center py-20 bg-[var(--card-bg)] rounded-[2.5rem] border border-[var(--card-border)] shadow-xl">
                                <span className="text-6xl mb-6 block">
                                    {filtroPronostico === 'sin_pronosticar' ? '🎉' : filtroPronostico === 'pronosticados' ? '📝' : '🎯'}
                                </span>
                                <h3 className="text-xl font-bold tracking-tight mb-2">
                                    {filtroPronostico === 'sin_pronosticar'
                                        ? '¡Completaste todo!'
                                        : filtroPronostico === 'pronosticados'
                                            ? 'Sin pronósticos'
                                            : 'Sin partidos'}
                                </h3>
                                <p className="text-sm text-[var(--text-muted)] font-medium max-w-xs mx-auto">
                                    {filtroPronostico === 'sin_pronosticar'
                                        ? 'No hay más partidos pendientes para pronosticar.'
                                        : filtroPronostico === 'pronosticados'
                                            ? 'Hacé tu primer pronóstico para sumar puntos.'
                                            : 'No hay partidos próximos en esta liga.'}
                                </p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 stagger-fade">
                                {partidosFiltrados.map(partido => (
                                    <ProdeCard
                                        key={partido.id}
                                        partido={partido}
                                        pronosticoExistente={getPronosticoExistente(partido.id)}
                                        onGuardar={(golesLocal, golesVisitante) =>
                                            handleGuardarPronostico(partido.id, golesLocal, golesVisitante)
                                        }
                                    />
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {/* CTA para ver ranking */}
                {partidosFiltrados.length > 0 && (
                    <div className="px-6 mt-12 mb-8">
                        <div className="max-w-4xl mx-auto text-center">
                            <button
                                onClick={() => router.push('/ranking')}
                                className="inline-flex items-center gap-3 px-8 py-4 bg-[var(--card-bg)] 
                            border border-[var(--accent-green)] text-[var(--accent-green)] rounded-2xl font-bold capitalize tracking-tight text-xs
                            hover:bg-[var(--accent-green)] hover:text-black transition-all shadow-lg hover:shadow-green-500/10"
                            >
                                <span>🏆</span>
                                Ver Tabla de Posiciones
                            </button>
                        </div>
                    </div>
                )}
            </main>

            <NavBar />
        </>
    )
}

// src/app/ranking/page.tsx
'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { NavBar } from '@/components/NavBar'
import { DesktopNav } from '@/components/DesktopNav'
import { motion } from 'framer-motion'
import { SimuladorPuntos } from '@/components/SimuladorPuntos'
import { ReglasPuntajeModal } from '@/components/ReglasPuntajeModal'
import { PullToRefresh } from '@/components/PullToRefresh'
import { ClubRanking } from '@/components/ClubRanking'
import type { RankingProde } from '@/types'
import { RankingGoal } from '@/components/ranking/RankingGoal'

export default function RankingPage() {
    const router = useRouter()
    const { user } = useAuth()
    const [ranking, setRanking] = useState<RankingProde[]>([])
    const [loading, setLoading] = useState(true)
    const [periodo, setPeriodo] = useState<'semanal' | 'mensual' | 'global'>('global')
    const [filtroSocial, setFiltroSocial] = useState<'global' | 'amigos'>('global')
    const [rankingTab, setRankingTab] = useState<'prode' | 'resenas'>('prode')
    const [rankingResenas, setRankingResenas] = useState<{
      user_id: string
      username: string
      avatar_url?: string
      total_logs: number
      avg_rating: number
      total_likes: number
    }[]>([])
    const [loadingResenas, setLoadingResenas] = useState(false)

    useEffect(() => {
        fetchRanking()
    }, [periodo, filtroSocial])

    const fetchRanking = async () => {
        setLoading(true)

        try {
            let userIds: string[] = []

            if (filtroSocial === 'amigos' && user) {
                const { data: follows } = await supabase
                    .from('user_follows')
                    .select('following_id')
                    .eq('follower_id', user.id)

                if (follows) {
                    userIds = follows.map(f => f.following_id)
                    userIds.push(user.id)
                }
            }

            let pointsColumn = 'puntos_totales'
            if (periodo === 'semanal') pointsColumn = 'puntos_semanales'
            if (periodo === 'mensual') pointsColumn = 'puntos_mensuales'

            let query = supabase
                .from('ranking_prode')
                .select(`
                  *,
                  profile:profiles(*)
                `)
                .order(pointsColumn, { ascending: false })
                .limit(100)

            if (filtroSocial === 'amigos' && userIds.length > 0) {
                query = query.in('user_id', userIds)
            } else if (filtroSocial === 'amigos') {
                query = query.eq('user_id', user?.id || 'none')
            }

            const { data, error } = await query

            if (error) throw error

            setRanking(data || [])
        } catch (error) {
            console.error('Error fetching ranking:', error)
        } finally {
            setLoading(false)
        }
    }

    const getPosicionColor = (pos: number) => {
        if (pos === 1) return 'text-amber-400'
        if (pos === 2) return 'text-slate-300'
        if (pos === 3) return 'text-orange-400'
        return 'text-[var(--text-muted)]'
    }

    const getPosicionEmoji = (pos: number) => {
        if (pos === 1) return '🥇'
        if (pos === 2) return '🥈'
        if (pos === 3) return '🥉'
        return pos
    }

    const fetchRankingResenas = async () => {
        setLoadingResenas(true)
        try {
            const { data: logs } = await supabase
                .from('match_logs')
                .select(`
                    user_id,
                    rating_partido,
                    likes_count:match_log_likes(count),
                    profile:profiles!match_logs_user_id_fkey(username, avatar_url)
                `)
                .eq('is_private', false)
                .not('review_text', 'is', null)

            if (!logs) return

            const userMap = new Map<string, {
                username: string
                avatar_url?: string
                total_logs: number
                sum_rating: number
                total_likes: number
            }>()

            logs.forEach((log: any) => {
                const existing = userMap.get(log.user_id) || {
                    username: log.profile?.username || 'Anónimo',
                    avatar_url: log.profile?.avatar_url,
                    total_logs: 0,
                    sum_rating: 0,
                    total_likes: 0
                }
                existing.total_logs++
                existing.sum_rating += log.rating_partido || 0
                existing.total_likes += log.likes_count?.[0]?.count || 0
                userMap.set(log.user_id, existing)
            })

            const result = Array.from(userMap.entries())
                .map(([user_id, data]) => ({
                    user_id,
                    username: data.username,
                    avatar_url: data.avatar_url,
                    total_logs: data.total_logs,
                    avg_rating: data.total_logs > 0 ? data.sum_rating / data.total_logs : 0,
                    total_likes: data.total_likes
                }))
                .sort((a, b) => b.total_logs - a.total_logs)
                .slice(0, 50)

            setRankingResenas(result)
        } catch (err) {
            console.error('Error fetching resenas ranking:', err)
        } finally {
            setLoadingResenas(false)
        }
    }

    useEffect(() => {
        if (rankingTab === 'resenas') fetchRankingResenas()
    }, [rankingTab])

    return (
        <>
            <DesktopNav />

            <PullToRefresh onRefresh={async () => { await fetchRanking() }}>
                <main className="min-h-screen bg-[var(--background)] text-[var(--foreground)] pb-24 md:pt-20">
                    {/* Header */}
                    <div className="px-6 py-10">
                        <div className="max-w-4xl mx-auto">
                            <div className="flex items-center justify-between gap-4">
                                <div>
                                    <h1 className="text-2xl md:text-3xl font-bold tracking-tight mb-2">
                                        🏆 Tabla de Posiciones
                                    </h1>
                                    <p className="text-sm text-[var(--text-muted)] font-medium">
                                        Los mejores pronosticadores del momento
                                    </p>
                                </div>
                                <ReglasPuntajeModal />
                            </div>
                        </div>
                    </div>

                    {/* Filtros */}
                    <div className="px-6 mb-10">
                        <div className="max-w-4xl mx-auto space-y-6">
                            <div className="flex gap-2 overflow-x-auto no-scrollbar pb-1">
                                {['semanal', 'mensual', 'global'].map(p => (
                                    <button
                                        key={p}
                                        onClick={() => setPeriodo(p as any)}
                                        className={`px-6 py-2.5 rounded-2xl text-[11px] font-bold capitalize tracking-tight transition-all whitespace-nowrap border
                                        ${periodo === p
                                                ? 'bg-[var(--accent)] text-white border-[var(--accent)] shadow-lg shadow-purple-500/20'
                                                : 'bg-[var(--card-bg)] text-[var(--text-muted)] border border-[var(--card-border)] hover:bg-[var(--hover-bg)]'
                                            }`}
                                    >
                                        {p}
                                    </button>
                                ))}
                            </div>

                            <div className="flex gap-3">
                                <button
                                    onClick={() => setFiltroSocial('global')}
                                    className={`flex-1 py-3.5 rounded-2xl text-[11px] font-bold capitalize tracking-tight transition-all border
                                        ${filtroSocial === 'global'
                                            ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)] shadow-lg'
                                            : 'bg-[var(--card-bg)] text-[var(--text-muted)] border border-[var(--card-border)]'}
                                    `}
                                >
                                    Global
                                </button>
                                <button
                                    onClick={() => setFiltroSocial('amigos')}
                                    className={`flex-1 py-3.5 rounded-2xl text-[11px] font-bold capitalize tracking-tight transition-all border
                                        ${filtroSocial === 'amigos'
                                            ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)] shadow-lg'
                                            : 'bg-[var(--card-bg)] text-[var(--text-muted)] border border-[var(--card-border)]'}
                                    `}
                                >
                                    Amigos
                                </button>
                            </div>

                            {user && ranking.length > 0 && (
                                <RankingGoal
                                    currentPoints={ranking.find(r => r.user_id === user.id)?.[periodo === 'global' ? 'puntos_totales' : periodo === 'mensual' ? 'puntos_mensuales' : 'puntos_semanales'] || 0}
                                    rank={ranking.findIndex(r => r.user_id === user.id) !== -1 ? ranking.findIndex(r => r.user_id === user.id) + 1 : undefined}
                                />
                            )}
                        </div>
                    </div>

                    {/* Tab selector: Prode vs Reseñas */}
                    <div className="px-6 mb-8">
                        <div className="max-w-4xl mx-auto">
                            <div className="flex gap-2 bg-[var(--card-bg)] p-1.5 rounded-2xl border border-[var(--card-border)] w-fit">
                                <button
                                    onClick={() => setRankingTab('prode')}
                                    className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all
                                      ${rankingTab === 'prode'
                                        ? 'bg-[var(--foreground)] text-[var(--background)] shadow-sm'
                                        : 'text-[var(--text-muted)]'
                                      }`}
                                >
                                    🎯 Prode
                                </button>
                                <button
                                    onClick={() => setRankingTab('resenas')}
                                    className={`px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all
                                      ${rankingTab === 'resenas'
                                        ? 'bg-[var(--foreground)] text-[var(--background)] shadow-sm'
                                        : 'text-[var(--text-muted)]'
                                      }`}
                                >
                                    ⭐ Reseñas
                                </button>
                            </div>
                        </div>
                    </div>

                    {rankingTab === 'prode' ? (
                    <>
                    {/* Tu Posición */}
                    {user && !loading && (
                        <div className="px-6 mb-12">
                            <div className="max-w-4xl mx-auto bg-[var(--accent)]/5 border border-[var(--accent)]/10 rounded-[2rem] p-8 flex items-center justify-between shadow-xl relative overflow-hidden group">
                                <div className="absolute inset-0 bg-gradient-to-r from-[var(--accent)]/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
                                <div className="flex items-center gap-6 relative z-10">
                                    <div className="w-16 h-16 bg-[var(--accent)] text-white rounded-2xl flex items-center justify-center text-2xl font-bold shadow-lg shadow-purple-500/20">
                                        {ranking.findIndex(r => r.user_id === user.id) !== -1 ? `${ranking.findIndex(r => r.user_id === user.id) + 1}°` : '-'}
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-[var(--foreground)] text-lg">Tu posición actual</h4>
                                        <p className="text-[11px] text-[var(--text-muted)] font-medium capitalize tracking-tight mt-1">
