                                                                        {periodo}
                                                                    </span>
                                                                </div>
                                                            </td>
                                                            <td className="p-5">
                                                                <div className="flex items-center gap-4">
                                                                    <div className="w-10 h-10 rounded-full bg-[var(--background)] border border-[var(--card-border)] flex items-center justify-center text-xl overflow-hidden shadow-sm group-hover:border-[var(--accent)] transition-colors">
                                                                        {jugador.profile?.avatar_url || '👤'}
                                                                    </div>
                                                                    <div>
                                                                        <div className="font-bold text-sm">{jugador.profile?.username}</div>
                                                                        <div className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest">{jugador.profile?.equipo || 'Amante del fútbol'}</div>
                                                                    </div>
                                                                </div>
                                                            </td>
                                                            <td className="p-5 text-center">
                                                                <span className="font-black text-lg text-[var(--accent)]">
                                                                    {periodo === 'global' ? jugador.puntos_totales : periodo === 'mensual' ? jugador.puntos_mensuales : jugador.puntos_semanales}
                                                                </span>
                                                            </td>
                                                            <td className="p-5 text-center font-bold text-sm">{jugador.aciertos_exactos}</td>
                                                            <td className="p-5 text-center font-bold text-sm text-[var(--text-muted)]">{jugador.partidos_jugados}</td>
                                                        </tr>
                                                    )
                                                })}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                    </>
                    ) : (
                    <div className="px-6 mb-12">
                        <div className="max-w-4xl mx-auto">
                            {loadingResenas ? (
                                <div className="text-center py-20 animate-pulse text-[var(--text-muted)] font-black italic tracking-widest">
                                    Calculando críticos...
                                </div>
                            ) : rankingResenas.length === 0 ? (
                                <div className="text-center py-20 bg-[var(--card-bg)] rounded-3xl border border-[var(--card-border)]">
                                    <p className="text-4xl mb-4">⭐</p>
                                    <p className="font-black italic text-[var(--text-muted)]">No hay reseñas todavía</p>
                                </div>
                            ) : (
                                <div className="bg-[var(--card-bg)] rounded-[2.5rem] border border-[var(--card-border)] overflow-hidden shadow-2xl">
                                    <table className="w-full text-left">
                                        <thead className="bg-[var(--background)]/50 border-b border-[var(--card-border)]">
                                            <tr>
                                                <th className="p-5 text-[10px] font-black tracking-widest text-[var(--text-muted)]">POS</th>
                                                <th className="p-5 text-[10px] font-black tracking-widest text-[var(--text-muted)]">CRÍTICO</th>
                                                <th className="p-5 text-center text-[10px] font-black tracking-widest text-[var(--text-muted)]">RESEÑAS</th>
                                                <th className="p-5 text-center text-[10px] font-black tracking-widest text-[var(--text-muted)]">RATING PROM</th>
                                                <th className="p-5 text-center text-[10px] font-black tracking-widest text-[var(--text-muted)]">❤️</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-[var(--card-border)]">
                                            {rankingResenas.map((r, idx) => {
                                                const isMe = user?.id === r.user_id
                                                return (
                                                    <tr
                                                        key={r.user_id}
                                                        onClick={() => router.push(`/perfil/${r.user_id}`)}
                                                        className={`cursor-pointer transition-colors ${isMe ? 'bg-[var(--accent)]/5 hover:bg-[var(--accent)]/10' : 'hover:bg-[var(--hover-bg)]'}`}
                                                    >
                                                        <td className="p-5 text-center font-black text-[var(--text-muted)]">
                                                            {idx === 0 ? '🥇' : idx === 1 ? '🥈' : idx === 2 ? '🥉' : idx + 1}
                                                        </td>
                                                        <td className="p-5">
                                                            <div className="flex items-center gap-3">
                                                                <div className="w-10 h-10 rounded-full bg-[var(--background)] border border-[var(--card-border)] flex items-center justify-center overflow-hidden">
                                                                    {r.avatar_url
                                                                        ? <img src={r.avatar_url} alt="" className="w-full h-full object-cover" />
                                                                        : <span className="text-sm font-black">{r.username[0]?.toUpperCase()}</span>
                                                                    }
                                                                </div>
                                                                <span className="font-bold text-sm">{r.username}</span>
                                                            </div>
                                                        </td>
                                                        <td className="p-5 text-center font-black text-lg text-[var(--accent)]">{r.total_logs}</td>
                                                        <td className="p-5 text-center font-black text-sm">⭐ {r.avg_rating.toFixed(1)}</td>
                                                        <td className="p-5 text-center font-bold text-sm text-[var(--text-muted)]">{r.total_likes}</td>
                                                    </tr>
                                                )
                                            })}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>
                    )}

                    <div className="px-6 mt-12 mb-8">
                        <div className="max-w-4xl mx-auto">
                            <ClubRanking />
                        </div>
                    </div>
                </main>
            </PullToRefresh >

            <NavBar />
        </>
    )
}

// src/components/ActivityHeatmap.tsx
'use client'

import { useState, useEffect } from 'react'
import { createClient } from '@/lib/supabase/client'
import { motion } from 'framer-motion'

interface Props {
  userId: string
}

export function ActivityHeatmap({ userId }: Props) {
  const [activity, setActivity] = useState<Record<string, number>>({})
  const [loading, setLoading] = useState(true)
  const supabase = createClient()

  useEffect(() => {
    const fetchActivity = async () => {
      const oneYearAgo = new Date()
      oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1)

      const { data } = await supabase
        .from('match_logs')
        .select('watched_at')
        .eq('user_id', userId)
        .gte('watched_at', oneYearAgo.toISOString())

      if (data) {
        const counts: Record<string, number> = {}
        data.forEach(log => {
          const date = new Date(log.watched_at).toISOString().split('T')[0]
          counts[date] = (counts[date] || 0) + 1
        })
        setActivity(counts)
      }
      setLoading(false)
    }

    fetchActivity()
  }, [userId])

  const buildWeekGrid = () => {
    const grid: string[][] = []
    const today = new Date()

    // Start from 52 weeks ago
    const start = new Date(today)
    start.setDate(today.getDate() - (52 * 7))
    // Adjust to nearest Sunday
    start.setDate(start.getDate() - start.getDay())

    const current = new Date(start)
    for (let w = 0; w <= 52; w++) {
      const week: string[] = []
      for (let d = 0; d < 7; d++) {
        week.push(current.toISOString().split('T')[0])
        current.setDate(current.getDate() + 1)
        if (current > today) break
      }
      grid.push(week)
      if (current > today) break
    }
    return grid
  }

  if (loading) return <div className="h-24 bg-[var(--card-bg)] animate-pulse rounded-2xl" />

  const grid = buildWeekGrid()

  const getColor = (count: number) => {
    if (count === 0) return 'var(--card-border)'
    if (count === 1) return '#166534' // green-800
    if (count <= 3) return '#22c55e' // green-500
    return '#4ade80' // green-400
  }

  return (
    <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl p-6">
      <h3 className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] mb-4 flex items-center gap-2">
        📊 Actividad de Visionado (Último año)
      </h3>
      <div className="overflow-x-auto no-scrollbar pb-2">
        <div className="flex gap-1 min-w-max">
          {grid.map((week, wi) => (
            <div key={wi} className="flex flex-col gap-1">
              {week.map(day => {
                const count = activity[day] || 0
                return (
                  <motion.div
                    key={day}
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    transition={{ delay: (wi * 0.01) }}
                    title={`${day}: ${count} partido${count !== 1 ? 's' : ''}`}
                    className="w-2.5 h-2.5 rounded-[2px] transition-colors hover:ring-1 hover:ring-[var(--accent)] cursor-help"
                    style={{ backgroundColor: getColor(count) }}
                  />
                )
              })}
            </div>
          ))}
        </div>
      </div>
      <div className="flex items-center justify-end gap-2 mt-3 text-[9px] font-bold text-[var(--text-muted)]">
        <span>Menos</span>
        <div className="flex gap-1">
          {[0, 1, 3, 5].map(v => (
            <div key={v} className="w-2 h-2 rounded-[1px]" style={{ backgroundColor: getColor(v) }} />
          ))}
        </div>
        <span>Más</span>
      </div>
    </div>
  )
}

// src/components/AdvancedStats.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { CollapsibleSection } from './CollapsibleSection'

interface TeamStats {
    name: string
    logo: string
    possession: string | number
    shots: string | number
    shots_on_target: string | number
    corners: string | number
    fouls: string | number
    yellow_cards: string | number
    red_cards: string | number
    offsides: string | number
    passes_total: string | number
    passes_accurate: string | number
    expected_goals: string | number
}

interface StatsData {
    local: TeamStats
    visitante: TeamStats
}

interface AdvancedStatsProps {
    fixtureId: number | string
}

interface StatRow {
    label: string
    icon: string
    local: number
    visitante: number
    format?: 'percent' | 'number' | 'xg'
}

export function AdvancedStats({ fixtureId }: AdvancedStatsProps) {
    const [data, setData] = useState<StatsData | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const res = await fetch(`/api/partido/${fixtureId}/statistics`)
                const json = await res.json()
                setData(json.stats)
            } catch (err) {
                console.error('Error loading stats:', err)
            } finally {
                setLoading(false)
            }
        }
        fetchStats()
    }, [fixtureId])

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4" style={{ borderRadius: 'var(--radius)' }}>
                <div className="flex items-center gap-2 mb-3">
                    <span>📊</span>
                    <h3 className="text-xs font-bold text-[var(--text-muted)] capitalize">Estadísticas Avanzadas</h3>
                </div>
                <div className="space-y-3">
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="h-6 bg-[var(--background)] rounded animate-pulse" />
                    ))}
                </div>
            </div>
        )
    }

    if (!data) return null

    const parseNum = (v: string | number): number => {
        if (typeof v === 'number') return v
        const n = parseFloat(String(v).replace('%', ''))
        return isNaN(n) ? 0 : n
    }

    const rows: StatRow[] = [
        { label: 'Posesión', icon: '🎯', local: parseNum(data.local.possession), visitante: parseNum(data.visitante.possession), format: 'percent' },
        { label: 'xG', icon: '📈', local: parseNum(data.local.expected_goals), visitante: parseNum(data.visitante.expected_goals), format: 'xg' },
        { label: 'Tiros', icon: '🥅', local: parseNum(data.local.shots), visitante: parseNum(data.visitante.shots) },
        { label: 'Al arco', icon: '🎯', local: parseNum(data.local.shots_on_target), visitante: parseNum(data.visitante.shots_on_target) },
        { label: 'Corners', icon: '🏁', local: parseNum(data.local.corners), visitante: parseNum(data.visitante.corners) },
        { label: 'Pases', icon: '📋', local: parseNum(data.local.passes_total), visitante: parseNum(data.visitante.passes_total) },
        { label: 'Pases prec.', icon: '✅', local: parseNum(data.local.passes_accurate), visitante: parseNum(data.visitante.passes_accurate) },
        { label: 'Faltas', icon: '⚠️', local: parseNum(data.local.fouls), visitante: parseNum(data.visitante.fouls) },
        { label: 'Offsides', icon: '🚩', local: parseNum(data.local.offsides), visitante: parseNum(data.visitante.offsides) },
    ]

    // Filter out rows where both values are 0
    const activeRows = rows.filter(r => r.local > 0 || r.visitante > 0)

    if (activeRows.length === 0) return null

    return (
        <CollapsibleSection title="Estadísticas Avanzadas" icon={<span className="text-xl">📊</span>} defaultOpen={false}>

            {/* Team names header */}
            <div className="flex items-center justify-between px-4 py-2 bg-[var(--background)]">
                <div className="flex items-center gap-2">
                    {data.local.logo && (
                        <img src={data.local.logo} alt="" className="w-5 h-5 object-contain" />
                    )}
                    <span className="text-[10px] font-bold truncate max-w-[80px]">{data.local.name}</span>
                </div>
                <div className="flex items-center gap-2">
                    <span className="text-[10px] font-bold truncate max-w-[80px]">{data.visitante.name}</span>
                    {data.visitante.logo && (
                        <img src={data.visitante.logo} alt="" className="w-5 h-5 object-contain" />
                    )}
                </div>
            </div>

            {/* Stats rows */}
            <div className="px-4 py-2 space-y-3">
                {activeRows.map((row, idx) => {
                    const total = row.local + row.visitante
                    const localPct = total > 0 ? (row.local / total) * 100 : 50
                    const visitantePct = total > 0 ? (row.visitante / total) * 100 : 50

                    const formatValue = (v: number) => {
                        if (row.format === 'percent') return `${v}%`
                        if (row.format === 'xg') return v.toFixed(2)
                        return String(v)
                    }

                    const localWins = row.local > row.visitante
                    const visitanteWins = row.visitante > row.local

                    return (
                        <motion.div
                            key={row.label}
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: idx * 0.05 }}
                        >
                            {/* Label */}
                            <div className="flex items-center justify-between mb-1">
                                <span className={`text-[11px] font-bold tabular-nums ${localWins ? 'text-[#16a34a]' : 'text-[var(--text-muted)]'}`}>
                                    {formatValue(row.local)}
                                </span>
                                <span className="text-[10px] text-[var(--text-muted)] font-medium">
                                    {row.icon} {row.label}
                                </span>
                                <span className={`text-[11px] font-bold tabular-nums ${visitanteWins ? 'text-[#2563eb]' : 'text-[var(--text-muted)]'}`}>
                                    {formatValue(row.visitante)}
                                </span>
                            </div>

                            {/* Bar */}
                            <div className="flex h-1.5 gap-0.5 border border-black/5 bg-black/5">
                                <motion.div
                                    initial={{ width: '50%' }}
                                    animate={{ width: `${localPct}%` }}
                                    transition={{ duration: 0.6, delay: idx * 0.05 }}
                                    className=""
                                    style={{ backgroundColor: localWins ? '#16a34a' : 'var(--card-border)' }}
                                />
                                <motion.div
                                    initial={{ width: '50%' }}
                                    animate={{ width: `${visitantePct}%` }}
                                    transition={{ duration: 0.6, delay: idx * 0.05 }}
                                    className=""
                                    style={{ backgroundColor: visitanteWins ? '#2563eb' : 'var(--card-border)' }}
                                />
                            </div>
                        </motion.div>
                    )
                })}
            </div>
        </CollapsibleSection>
    )
}

import { useState, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Button } from '@/components/ui/Button'
import { toPng } from 'html-to-image'

interface AutoShareModalProps {
    isOpen: boolean
    onClose: () => void
    type: 'prode_exact' | 'badge_unlock'
    title: string
    subtitle: string
    achievementData: {
        badgeIcon?: string
        badgeName?: string
        matchDetails?: string
        pointsIcon?: string
        pointsText?: string
    }
}

export function AutoShareModal({ isOpen, onClose, type, title, subtitle, achievementData }: AutoShareModalProps) {
    const cardRef = useRef<HTMLDivElement>(null)
    const [isGenerating, setIsGenerating] = useState(false)
    const [generatedImage, setGeneratedImage] = useState<string | null>(null)

    useEffect(() => {
        if (isOpen) {
            setGeneratedImage(null) // Reset image on open
            // Short delay to ensure DOM is fully rendered with animations
            const timer = setTimeout(() => {
                generateImage()
            }, 500)
            return () => clearTimeout(timer)
        }
    }, [isOpen])

    const generateImage = async () => {
        if (!cardRef.current) return

        try {
            setIsGenerating(true)
            const imgData = await toPng(cardRef.current, {
                pixelRatio: 2, // High resolution
                backgroundColor: '#0f172a', // force dark background for consistent share cards
                style: { margin: '0' }
            })

            setGeneratedImage(imgData)
        } catch (error) {
            console.error('Error generating share preview:', error)
        } finally {
            setIsGenerating(false)
        }
    }

    const handleNativeShare = async () => {
        const shareData = {
            title: '¡Mirá mi logro en FutLog!',
            text: subtitle,
            url: window.location.origin
        }

        if (navigator.share && generatedImage) {
            try {
                // Convert base64 to File for native sharing
                const res = await fetch(generatedImage)
                const blob = await res.blob()
                const file = new File([blob], 'futlog_achievement.png', { type: 'image/png' })

                if (navigator.canShare && navigator.canShare({ files: [file] })) {
                    await navigator.share({
                        ...shareData,
                        files: [file]
                    })
                } else {
                    // Fallback to text link share
                    await navigator.share(shareData)
                }
            } catch (err: any) {
                if (err.name !== 'AbortError') {
                    console.error('Error sharing:', err)
                }
            }
        } else {
            // Fallback clipboard
            navigator.clipboard.writeText(`${shareData.title}\n${shareData.text}\n${shareData.url}`)
            alert('Enlace copiado al portapapeles')
        }
    }

    return (
        <AnimatePresence>
            {isOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4"
                    onClick={onClose}
                >
                    <motion.div
                        initial={{ scale: 0.9, y: 20 }}
                        animate={{ scale: 1, y: 0 }}
                        exit={{ scale: 0.9, y: 20 }}
                        onClick={(e) => e.stopPropagation()}
                        className="bg-[var(--card-bg)] rounded-3xl w-full max-w-sm overflow-hidden shadow-2xl border border-[var(--card-border)] relative"
                    >
                        {/* Close button */}
                        <button
                            onClick={onClose}
                            className="absolute top-3 right-3 w-8 h-8 bg-black/20 rounded-full flex items-center justify-center text-white/70 hover:text-white z-20"
                        >
                            ✕
                        </button>

                        {/* Hidden preview structure for html2canvas generation */}
                        {!generatedImage && (
                            <div
                                ref={cardRef}
                                className="absolute top-[-9999px] left-[-9999px] w-[400px] h-[500px] bg-gradient-to-br from-[#0f172a] to-[#1e293b] p-8 flex flex-col items-center justify-center text-white text-center rounded-3xl border border-[#334155]"
                            >
                                <div className="text-6xl mb-4">
                                    {type === 'badge_unlock' ? achievementData.badgeIcon : '🎯'}
                                </div>
                                <h2 className="text-3xl font-black mb-2 leading-tight bg-gradient-to-r from-emerald-400 to-cyan-400 bg-clip-text text-transparent">
                                    {title}
                                </h2>
                                <p className="text-lg opacity-80 font-medium mb-8 px-4">
                                    {subtitle}
                                </p>

                                <div className="bg-black/30 backdrop-blur-md rounded-2xl p-6 w-full border border-white/10">
                                    {type === 'prode_exact' && (
                                        <>
                                            <p className="text-sm font-bold opacity-60 capitalize mb-2">Partido</p>
                                            <p className="font-bold text-xl">{achievementData.matchDetails}</p>
                                            <div className="mt-4 flex justify-center items-center gap-2 text-emerald-400 font-bold bg-emerald-400/10 py-2 rounded-xl">
                                                <span>+</span>{achievementData.pointsText} PTS
                                            </div>
                                        </>
                                    )}
                                    {type === 'badge_unlock' && (
                                        <>
                                            <p className="text-sm font-bold opacity-60 capitalize mb-2">Nueva Insignia</p>
                                            <p className="font-bold text-2xl text-amber-400">{achievementData.badgeName}</p>
                                        </>
                                    )}
                                </div>

                                <div className="mt-auto pt-8 flex items-center justify-center gap-3 w-full opacity-60">
                                    <span className="text-emerald-500 font-black text-xl">FutLog</span>
                                </div>
                            </div>
                        )}

                        <div className="p-6 text-center">
                            {/* Visual Header */}
                            <div className="mb-6 relative">
                                <div className="absolute inset-0 bg-gradient-to-t from-[var(--card-bg)] to-transparent z-10 bottom-0 top-1/2" />
                                {generatedImage ? (
                                    <img
                                        src={generatedImage}
                                        alt="Tu logro"
                                        className="w-full h-auto rounded-xl shadow-lg border border-[var(--card-border)]"
                                    />
                                ) : (
                                    <div className="w-full aspect-[4/5] bg-[var(--hover-bg)] animate-pulse rounded-xl flex items-center justify-center border border-[var(--card-border)]">
                                        <div className="text-sm text-[var(--text-muted)] font-bold">
                                            Generando imagen...
                                        </div>
                                    </div>
                                )}
                            </div>

                            <h3 className="text-xl font-black mb-2">{title}</h3>
                            <p className="text-sm text-[var(--text-muted)] mb-6">
                                {subtitle}
                            </p>

                            <div className="space-y-3">
                                <Button
                                    onClick={handleNativeShare}
                                    fullWidth
                                    disabled={!generatedImage || isGenerating}
                                    className="bg-gradient-to-r from-green-500 to-emerald-600 border-none flex items-center justify-center gap-2"
                                >
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="18" cy="5" r="3"></circle><circle cx="6" cy="12" r="3"></circle><circle cx="18" cy="19" r="3"></circle><line x1="8.59" y1="13.51" x2="15.42" y2="17.49"></line><line x1="15.41" y1="6.51" x2="8.59" y2="10.49"></line></svg>
                                    Compartir Logro
                                </Button>
                                <Button
                                    onClick={onClose}
                                    variant="outline"
                                    fullWidth
                                >
                                    Cerrar
                                </Button>
                            </div>
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    )
}

// src/components/BadgeDisplay.tsx
'use client'

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Lock, ChevronDown, ChevronUp, Sparkles } from 'lucide-react'
import confetti from 'canvas-confetti'
import { BADGES, getUnlockedBadges, getBadgeProgress, getNextBadges, type Badge, type BadgeStats } from '@/lib/badges'

interface BadgeDisplayProps {
    stats: BadgeStats
    compact?: boolean
}

export function BadgeDisplay({ stats, compact = false }: BadgeDisplayProps) {
    const [showAll, setShowAll] = useState(false)
    const [lastUnlockedCount, setLastUnlockedCount] = useState<number | null>(null)
    const unlocked = getUnlockedBadges(stats)
    const nextBadges = getNextBadges(stats)
    const unlockedIds = new Set(unlocked.map(b => b.id))

    useEffect(() => {
        if (lastUnlockedCount !== null && unlocked.length > lastUnlockedCount) {
            // New badge unlocked!
            confetti({
                particleCount: 150,
                spread: 70,
                origin: { y: 0.6 },
                colors: ['#f59e0b', '#16a34a', '#2563eb']
            })
        }
        setLastUnlockedCount(unlocked.length)
    }, [unlocked.length])

    if (compact) {
        // Compact mode: just show unlocked badge icons in a row
        return (
            <div className="flex flex-wrap gap-1.5">
                {unlocked.length === 0 ? (
                    <span className="text-xs text-[var(--text-muted)]">Sin logros aún</span>
                ) : (
                    unlocked.map(badge => (
                        <span
                            key={badge.id}
                            title={`${badge.name}: ${badge.description}`}
                            className="text-lg cursor-default hover:scale-125 transition-transform"
                        >
                            {badge.icon}
                        </span>
                    ))
                )}
            </div>
        )
    }

    const displayBadges = showAll ? BADGES : [...unlocked, ...nextBadges.filter(b => !unlockedIds.has(b.id))].slice(0, 8)

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4" style={{ borderRadius: 'var(--radius)' }}>
            <div className="flex items-center justify-between mb-4 border-b border-[var(--card-border)] pb-2 border-dashed">
                <h3 className="text-[10px] font-black capitalize tracking-widest flex items-center gap-2">
                    🏅 Logros
                    <span className="text-[9px] font-bold text-[var(--text-muted)] border border-[var(--card-border)] px-1.5 py-0.5 ml-1">
                        {unlocked.length}/{BADGES.length}
                    </span>
                </h3>
                {BADGES.length > 8 && (
                    <button
                        onClick={() => setShowAll(!showAll)}
                        className="text-[9px] font-black capitalize text-[var(--accent)] hover:underline flex items-center gap-1"
                    >
                        {showAll ? 'Menos' : 'Ver todos'}
                    </button>
                )}
            </div>

            <div className="grid grid-cols-2 gap-2">
                {displayBadges.map((badge) => {
                    const isUnlocked = unlockedIds.has(badge.id)
                    const progress = getBadgeProgress(badge, stats)

                    return (
                        <div
                            key={badge.id}
                            className={`relative flex items-center gap-2 p-2 border transition-all ${isUnlocked
                                ? 'bg-[var(--background)] border-[var(--foreground)]/20'
                                : 'bg-[var(--background)] border-[var(--card-border)] opacity-40'
                                }`}
                            style={{ borderRadius: 'var(--radius)' }}
                        >
                            <div className={`text-xl shrink-0 ${!isUnlocked ? 'grayscale brightness-50' : ''}`}>
                                {isUnlocked ? badge.icon : '🔒'}
                            </div>
                            <div className="flex-1 min-w-0">
                                <div className="text-[10px] font-black capitalize tracking-tighter truncate">{badge.name}</div>
                                <div className="text-[8px] text-[var(--text-muted)] font-bold truncate leading-tight">{badge.description}</div>
                                {!isUnlocked && (
                                    <div className="mt-1">
                                        <div className="h-1 bg-[var(--card-border)] overflow-hidden">
                                            <div
                                                className="h-full bg-[var(--foreground)] transition-all duration-500"
                                                style={{ width: `${progress}%` }}
                                            />
                                        </div>
                                    </div>
                                )}
                            </div>
                            {isUnlocked && (
                                <div className="absolute -top-1 -right-1 w-3.5 h-3.5 bg-[var(--foreground)] border border-[var(--background)] flex items-center justify-center">
                                    <span className="text-[var(--background)] text-[8px] font-black">✓</span>
                                </div>
                            )}
                        </div>
                    )
                })}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { BarChart2, Plus, X, Check } from 'lucide-react'

interface Poll {
    id: string
    question: string
    options: string[]
    active: boolean
}

interface VoteCount {
    option_index: number
    count: number
}

export function ChatPoll({ partidoId }: { partidoId: string }) {
    const { user } = useAuth()
    const [poll, setPoll] = useState<Poll | null>(null)
    const [votes, setVotes] = useState<VoteCount[]>([])
    const [userVote, setUserVote] = useState<number | null>(null)
    const [showCreate, setShowCreate] = useState(false)
    const [newQuestion, setNewQuestion] = useState('')
    const [newOptions, setNewOptions] = useState(['', ''])

    useEffect(() => {
        if (!partidoId) return
        fetchPoll()

        const pollSub = supabase
            .channel(`poll-${partidoId}`)
            .on('postgres_changes' as any, { event: '*', table: 'chat_polls', filter: `partido_id=eq.${partidoId}` }, fetchPoll)
            .on('postgres_changes' as any, { event: '*', table: 'chat_poll_votes' }, fetchVotes)
            .subscribe()

        return () => { supabase.removeChannel(pollSub) }
    }, [partidoId])

    const fetchPoll = async () => {
        const { data, error } = await supabase
            .from('chat_polls')
            .select('*')
            .eq('partido_id', partidoId)
            .eq('active', true)
            .order('created_at', { ascending: false })
            .limit(1)
            .maybeSingle()

        if (data) {
            setPoll(data)
            fetchVotes()
            if (user) fetchUserVote(data.id)
        } else {
            setPoll(null)
        }
    }

    const fetchVotes = async () => {
        if (!poll) return
        const { data, error } = await supabase
            .from('chat_poll_votes')
            .select('option_index')
            .eq('poll_id', poll.id)

        if (data) {
            const counts: Record<number, number> = {}
            data.forEach(v => {
                counts[v.option_index] = (counts[v.option_index] || 0) + 1
            })
            setVotes(Object.entries(counts).map(([idx, count]) => ({
                option_index: parseInt(idx),
                count
            })))
        }
    }

    const fetchUserVote = async (pollId: string) => {
        if (!user) return
        const { data } = await supabase
            .from('chat_poll_votes')
            .select('option_index')
            .eq('poll_id', pollId)
            .eq('user_id', user.id)
            .maybeSingle()

        if (data) setUserVote(data.option_index)
    }

    const handleVote = async (idx: number) => {
        if (!user || !poll) return
        const { error } = await supabase
            .from('chat_poll_votes')
            .upsert({
                poll_id: poll.id,
                user_id: user.id,
                option_index: idx
            })

        if (!error) {
            setUserVote(idx)
            fetchVotes()
        }
    }

    const handleCreatePoll = async () => {
        if (!user || !newQuestion || newOptions.some(o => !o.trim())) return

        // Deactivate previous poll
        await supabase.from('chat_polls').update({ active: false }).eq('partido_id', partidoId)

        const { error } = await supabase.from('chat_polls').insert({
            partido_id: partidoId,
            created_by: user.id,
            question: newQuestion,
            options: newOptions.filter(o => o.trim() !== '')
        })

        if (!error) {
            setShowCreate(false)
            setNewQuestion('')
            setNewOptions(['', ''])
            fetchPoll()
        }
    }

    const totalVotes = votes.reduce((acc, v) => acc + v.count, 0)

    if (showCreate) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4 rounded-2xl mb-4">
                <div className="flex justify-between items-center mb-4">
                    <h4 className="font-bold text-sm">Nueva Encuesta</h4>
                    <button onClick={() => setShowCreate(false)}><X size={16} /></button>
                </div>
                <input
                    type="text"
                    placeholder="Pregunta (ej: ¿Quién gana?)"
                    className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-3 py-2 text-sm mb-3"
                    value={newQuestion}
                    onChange={e => setNewQuestion(e.target.value)}
                />
                <div className="space-y-2 mb-4">
                    {newOptions.map((opt, i) => (
                        <input
                            key={i}
                            type="text"
                            placeholder={`Opción ${i + 1}`}
                            className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-xl px-3 py-2 text-sm"
                            value={opt}
                            onChange={e => {
                                const copy = [...newOptions]
                                copy[i] = e.target.value
                                setNewOptions(copy)
                            }}
                        />
                    ))}
                    {newOptions.length < 4 && (
                        <button
                            onClick={() => setNewOptions([...newOptions, ''])}
                            className="text-[10px] font-bold text-[var(--accent)]"
                        >
                            + AGREGAR OPCIÓN
                        </button>
                    )}
                </div>
                <button
                    onClick={handleCreatePoll}
                    className="w-full bg-[var(--accent)] text-white font-bold py-2 rounded-xl text-sm"
                >
                    Lanzar Encuesta
                </button>
            </div>
        )
    }

    if (!poll) {
        return (
            <button
                onClick={() => setShowCreate(true)}
                className="flex items-center gap-2 text-xs font-bold text-[var(--text-muted)] hover:text-[var(--accent)] transition-colors p-2"
            >
                <Plus size={14} /> Lanzar encuesta en vivo
            </button>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4 rounded-2xl mb-4 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 p-2 opacity-10">
                <BarChart2 size={40} />
            </div>

            <h4 className="font-black text-sm mb-4 pr-10 capitalize tracking-tight">
                🔥 {poll.question}
            </h4>

            <div className="space-y-2.5">
                {poll.options.map((opt, i) => {
                    const voteData = votes.find(v => v.option_index === i)
                    const count = voteData?.count || 0
                    const percent = totalVotes > 0 ? (count / totalVotes) * 100 : 0
                    const isSelected = userVote === i

                    return (
                        <div key={i} className="relative">
                            <button
                                onClick={() => handleVote(i)}
                                disabled={!user}
                                className={`w-full relative z-10 p-3 rounded-xl border transition-all text-left flex justify-between items-center group
                                    ${isSelected ? 'border-[var(--accent)] bg-[var(--accent)]/5' : 'border-[var(--card-border)] bg-[var(--background)]/50 hover:bg-[var(--background)]'}`}
                            >
                                <span className={`text-xs font-bold ${isSelected ? 'text-[var(--accent)]' : 'text-[var(--foreground)]'}`}>
                                    {opt}
                                </span>
                                {totalVotes > 0 && (
                                    <span className="text-[10px] font-black opacity-60">
                                        {Math.round(percent)}%
                                    </span>
                                )}
                                {isSelected && (
                                    <span className="absolute -left-1 top-1/2 -translate-y-1/2 w-2 h-4 bg-[var(--accent)] rounded-r-full" />
                                )}
                            </button>
                            <motion.div
                                initial={{ width: 0 }}
                                animate={{ width: `${percent}%` }}
                                className={`absolute inset-0 h-full rounded-xl pointer-events-none opacity-10
                                    ${isSelected ? 'bg-[var(--accent)]' : 'bg-[var(--text-muted)]'}`}
                            />
                        </div>
                    )
                })}
            </div>

            <div className="mt-4 flex justify-between items-center">
                <span className="text-[10px] font-bold text-[var(--text-muted)] capitalize tracking-widest">
                    {totalVotes} {totalVotes === 1 ? 'VOTO' : 'VOTOS'}
                </span>
                <button
                    onClick={() => setShowCreate(true)}
                    className="text-[10px] font-bold text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                >
                    NUEVA
                </button>
            </div>
        </div>
    )
}

// src/components/ClubRanking.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'

interface ClubData {
    equipo: string
    avg_rating: number
    total_logs: number
    logo?: string
}

export function ClubRanking() {
    const [clubs, setClubs] = useState<ClubData[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        const fetchRanking = async () => {
            try {
                // Get match logs grouped by equipo_local and equipo_visitante teams
                const { data: logs } = await supabase
                    .from('match_logs')
                    .select('equipo_local, equipo_visitante, rating, logo_local, logo_visitante')

                if (!logs || logs.length === 0) {
                    setLoading(false)
                    return
                }

                // Aggregate ratings per team
                const teamMap = new Map<string, { total: number; count: number; logo?: string }>()

                logs.forEach(log => {
                    // Local team
                    if (log.equipo_local) {
                        const current = teamMap.get(log.equipo_local) || { total: 0, count: 0 }
                        current.total += log.rating || 0
                        current.count++
                        if (log.logo_local) current.logo = log.logo_local
                        teamMap.set(log.equipo_local, current)
                    }

                    // Visitante team
                    if (log.equipo_visitante) {
                        const current = teamMap.get(log.equipo_visitante) || { total: 0, count: 0 }
                        current.total += log.rating || 0
                        current.count++
                        if (log.logo_visitante) current.logo = log.logo_visitante
                        teamMap.set(log.equipo_visitante, current)
                    }
                })

                // Convert to array and sort
                const ranking: ClubData[] = Array.from(teamMap.entries())
                    .filter(([_, data]) => data.count >= 2) // Min 2 logs
                    .map(([equipo, data]) => ({
                        equipo,
                        avg_rating: data.total / data.count,
                        total_logs: data.count,
                        logo: data.logo,
                    }))
                    .sort((a, b) => b.avg_rating - a.avg_rating)
                    .slice(0, 20) // Top 20

                setClubs(ranking)
            } catch (err) {
                console.error('Error fetching club ranking:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchRanking()
    }, [])

    const getMedal = (index: number) => {
        if (index === 0) return '🥇'
        if (index === 1) return '🥈'
        if (index === 2) return '🥉'
        return `${index + 1}`
    }

    const getRatingColor = (rating: number) => {
        if (rating >= 8) return '#10b981'
        if (rating >= 6) return '#fbbf24'
        if (rating >= 4) return '#f59e0b'
        return '#ef4444'
    }

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-6">
                <div className="animate-pulse space-y-3">
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="h-12 bg-[var(--background)] rounded-xl" />
                    ))}
                </div>
            </div>
        )
    }

    if (clubs.length === 0) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-8 text-center">
                <p className="text-3xl mb-2">🏆</p>
                <p className="text-xs text-[var(--text-muted)] italic">
                    Todavía no hay suficientes reseñas
                </p>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl overflow-hidden shadow-sm">
            <div className="p-4 border-b border-[var(--card-border)]">
                <h3 className="text-sm font-bold text-[var(--foreground)] flex items-center justify-between">
                    Ranking de Clubes
                    <span className="text-[10px] text-[var(--text-muted)] font-normal">Top 20</span>
                </h3>
            </div>

            <table className="w-full text-left border-collapse">
                <thead className="bg-[var(--background)]">
                    <tr className="border-b border-[var(--card-border)]">
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] w-10 text-center">#</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)]">Equipo</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] text-right">Logs</th>
                        <th className="px-4 py-2 text-[10px] font-bold capitalize text-[var(--text-muted)] text-center">Rating</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-[var(--card-border)]">
                    {clubs.map((club, idx) => (
                        <tr key={club.equipo} className="hover:bg-[var(--background)] transition-colors">
                            <td className="px-4 py-3 text-sm font-medium text-center text-[var(--text-muted)] w-10">
                                {idx + 1}
                            </td>
                            <td className="px-4 py-3">
                                <div className="flex items-center gap-3">
                                    {club.logo && (
                                        <img src={club.logo} alt="" className="w-6 h-6 object-contain" />
                                    )}
                                    <span className="text-sm font-semibold truncate max-w-[120px]">{club.equipo}</span>
                                </div>
                            </td>
                            <td className="px-4 py-3 text-xs text-[var(--text-muted)] text-right">
                                {club.total_logs}
                            </td>
                            <td className="px-4 py-3 text-center">
                                <span
                                    className="inline-block px-2 py-1 text-xs font-bold text-white rounded-lg shadow-sm"
                                    style={{ backgroundColor: getRatingColor(club.avg_rating) }}
                                >
                                    {club.avg_rating.toFixed(1)}
                                </span>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    )
}

// src/components/CommentSection.tsx
'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { LoadingSpinner } from './LoadingSpinner'
import { Heart, Reply } from 'lucide-react'
import type { Comentario } from '@/types'
import { Button } from './ui/Button'

interface CommentSectionProps {
    partidoId: string | number
}

export function CommentSection({ partidoId }: CommentSectionProps) {
    const { user } = useAuth()
    const router = useRouter()
    const [comments, setComments] = useState<Comentario[]>([])
    const [newComment, setNewComment] = useState('')
    const [loading, setLoading] = useState(true)
    const [sending, setSending] = useState(false)
    const [replyTo, setReplyTo] = useState<{ username: string; id: string } | null>(null)
    const scrollRef = useRef<HTMLDivElement>(null)
    const inputRef = useRef<HTMLInputElement>(null)

    const partidoIdStr = String(partidoId)

    // Cargar comentarios iniciales
    useEffect(() => {
        const fetchComments = async () => {
            try {
                const { data, error } = await supabase
                    .from('comentarios')
                    .select(`
                        *,
                        profile:profiles(username, avatar_url),
                        likes_count:comentario_likes(count)
                    `)
                    .eq('partido_id', partidoIdStr)
                    .order('created_at', { ascending: true })

                if (error) {
                    console.error('Error fetching comments:', error)
                } else if (data) {
                    const processedComments = data.map((c: any) => ({
                        ...c,
                        likes_count: c.likes_count[0]?.count || 0,
                    }))

                    if (user) {
                        const { data: userLikes } = await supabase
                            .from('comentario_likes')
                            .select('comentario_id')
                            .eq('user_id', user.id)

                        const likedIds = new Set(userLikes?.map(l => l.comentario_id) || [])
                        processedComments.forEach(c => c.is_liked = likedIds.has(c.id))
                    }

                    setComments(processedComments)
                    scrollToBottom()
                }
            } catch (err: any) {
                console.error('Error in fetchComments:', err)
            } finally {
                setLoading(false)
            }
        }

        fetchComments()

        // Suscripción a nuevos comentarios
        const channel = supabase
            .channel(`partido:${partidoIdStr}`)
            .on('postgres_changes', {
                event: 'INSERT',
                schema: 'public',
                table: 'comentarios',
                filter: `partido_id=eq.${partidoIdStr}`
            }, async (payload) => {
                const { data } = await supabase
                    .from('comentarios')
                    .select(`*, profile:profiles(username, avatar_url)`)
                    .eq('id', payload.new.id)
                    .single()

                if (data) {
                    setComments(prev => [...prev, data])
                    scrollToBottom()
                }
            })
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [partidoIdStr])

    const scrollToBottom = () => {
        setTimeout(() => {
            scrollRef.current?.scrollIntoView({ behavior: 'smooth' })
        }, 100)
    }

    const handleReply = (username: string, commentId: string) => {
        setReplyTo({ username, id: commentId })
        inputRef.current?.focus()
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!user || !newComment.trim() || sending) return

        setSending(true)
        try {
            // Prepend reply mention if replying
            const mensaje = replyTo
                ? `@${replyTo.username} ${newComment.trim()}`
                : newComment.trim()

            const { error } = await supabase
                .from('comentarios')
                .insert({
                    partido_id: partidoIdStr,
                    user_id: user.id,
                    mensaje: newComment.trim(),
                    parent_id: replyTo?.id || null
                })

            if (error) throw error
            setNewComment('')
            setReplyTo(null)
        } catch (error) {
            console.error('Error enviando comentario:', error)
        } finally {
            setSending(false)
        }
    }

    const toggleCommentLike = async (commentId: string) => {
        if (!user) return

        const comment = comments.find(c => c.id === commentId)
        if (!comment) return

        const wasLiked = comment.is_liked

        // Optimistic update
        setComments(prev => prev.map(c =>
            c.id === commentId
                ? { ...c, is_liked: !wasLiked, likes_count: (c.likes_count || 0) + (wasLiked ? -1 : 1) }
                : c
        ))

        try {
            if (wasLiked) {
                await supabase
                    .from('comentario_likes')
                    .delete()
                    .eq('comentario_id', commentId)
                    .eq('user_id', user.id)
            } else {
                await supabase
                    .from('comentario_likes')
                    .insert({ comentario_id: commentId, user_id: user.id })
            }
        } catch {
            // Revert
            setComments(prev => prev.map(c =>
                c.id === commentId
                    ? { ...c, is_liked: wasLiked, likes_count: (c.likes_count || 0) + (wasLiked ? 1 : -1) }
                    : c
            ))
        }
    }

    const formatTime = (dateStr: string) => {
        const date = new Date(dateStr)
        const now = new Date()
        const diff = Math.floor((now.getTime() - date.getTime()) / 60000)

        if (diff < 1) return 'Ahora'
        if (diff < 60) return `Hace ${diff} min`
        if (diff < 1440) return `Hace ${Math.floor(diff / 60)} h`
        return date.toLocaleDateString()
    }

    // Render UI (Teaser for Unauthenticated Users)
    if (!user) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden mb-6 relative" style={{ borderRadius: 'var(--radius)' }}>
                {/* Header */}
                <div className="p-4 border-b border-[var(--card-border)] bg-[var(--card-bg)]">
                    <h3 className="text-xs font-black capitalize tracking-widest flex items-center gap-2">
                        💬 Reseñas
                        <span className="bg-[var(--background)] border border-[var(--card-border)] text-[9px] px-2 py-0.5 text-[var(--text-muted)]" style={{ borderRadius: 'var(--radius)' }}>
                            ...
                        </span>
                    </h3>
                </div>

                {/* Blurred Content Teaser */}
                <div className="h-[250px] relative p-4 space-y-4 bg-[var(--background)] overflow-hidden cursor-pointer" onClick={() => router.push('/login')}>
                    <div className="absolute inset-0 z-10 bg-black/5 backdrop-blur-[3px]" />
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none">
                        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-5 max-w-[280px] text-center transform scale-105 pointer-events-auto" style={{ borderRadius: 'var(--radius)' }}>
                            <h4 className="font-black text-sm capitalize italic tracking-tighter mb-2 text-[var(--foreground)]">Análisis de los hinchas</h4>
                            <p className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-4">Iniciá sesión para leer las reseñas.</p>
                            <Button fullWidth onClick={() => router.push('/login')}>
                                Iniciar sesión
                            </Button>
                        </div>
                    </div>

                    {/* Fake Comments for visual effect */}
                    <div className="flex gap-3 opacity-40 blur-[2px]">
                        <div className="w-8 h-8 rounded-full bg-blue-500/20" />
                        <div>
                            <div className="h-3 w-24 bg-[var(--border)] rounded mb-2" />
                            <div className="h-4 w-48 bg-[var(--border)] rounded" />
                        </div>
                    </div>

                    <div className="text-center absolute bottom-4 left-0 right-0 z-20 pointer-events-none opacity-50 blur-[1px]">
                        <p className="text-[10px] font-black capitalize tracking-widest text-[#16a34a]">Ver más mensajes...</p>
                    </div>
                </div>

                {/* Disabled Input */}
                <div className="p-4 bg-[var(--card-bg)] border-t border-[var(--card-border)] opacity-50 relative pointer-events-none">
                    <input
                        type="text"
                        disabled
                        placeholder="INICIA SESIÓN PARA COMENTAR..."
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] pl-4 pr-12 py-3 text-xs font-black capitalize tracking-widest focus:outline-none"
                        style={{ borderRadius: 'var(--radius)' }}
                    />
                </div>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden mb-6" style={{ borderRadius: 'var(--radius)' }}>
            {/* Header */}
            <div className="p-4 border-b border-[var(--card-border)] bg-[var(--card-bg)]">
                <h3 className="text-xs font-black capitalize tracking-widest flex items-center gap-2">
                    💬 Reseñas
                    <span className="bg-[var(--background)] border border-[var(--card-border)] text-[9px] font-black px-2 py-0.5 text-[var(--text-muted)]" style={{ borderRadius: 'var(--radius)' }}>
                        {comments.length}
                    </span>
                </h3>
            </div>

            {/* Lista de Comentarios */}
            <div className="h-[350px] overflow-y-auto p-4 space-y-3 bg-[var(--background)]">
                {loading ? (
                    <div className="flex justify-center py-4">
                        <LoadingSpinner />
                    </div>
                ) : comments.length === 0 ? (
                    <div className="text-center py-12 text-[var(--text-muted)] text-sm">
                        <p>Sé el primero en comentar 👇</p>
                    </div>
                ) : (
                    comments
                        .filter(c => !c.parent_id) // Root comments
                        .map((comment) => {
                            const replies = comments.filter(r => r.parent_id === comment.id)

                            return (
                                <div key={comment.id} className="space-y-3">
                                    <CommentItem
                                        comment={comment}
                                        user={user}
                                        onReply={handleReply}
                                        onLike={toggleCommentLike}
                                        formatTime={formatTime}
                                    />

                                    {/* Replies */}
                                    {replies.length > 0 && (
                                        <div className="ml-8 space-y-3 border-l-2 border-[var(--hover-bg)] pl-4">
                                            {replies.map(reply => (
                                                <CommentItem
                                                    key={reply.id}
                                                    comment={reply}
                                                    user={user}
                                                    onReply={handleReply}
                                                    onLike={toggleCommentLike}
                                                    formatTime={formatTime}
                                                    isReply
                                                />
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )
                        })
                )}
                <div ref={scrollRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-[var(--card-bg)] border-t border-[var(--card-border)]">
                {/* Reply indicator */}
                {replyTo && (
                    <div className="flex items-center justify-between mb-2 px-2 py-1.5 bg-[#16a34a]/5 border border-[#16a34a]/20" style={{ borderRadius: 'var(--radius)' }}>
                        <span className="text-[10px] text-[#16a34a] font-black capitalize tracking-widest">
                            ↩ Respondiendo a @{replyTo.username}
                        </span>
                        <button
                            onClick={() => setReplyTo(null)}
                            className="text-[10px] text-[var(--text-muted)] hover:text-[var(--foreground)]"
                        >
                            ✕
                        </button>
                    </div>
                )}

                <form onSubmit={handleSubmit} className="relative">
                    <input
                        ref={inputRef}
                        type="text"
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder={replyTo ? `RESPONDER A @${replyTo.username.toUpperCase()}...` : 'ESCRIBIR RESEÑA...'}
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] pl-4 pr-12 py-3 text-xs font-black capitalize tracking-widest focus:outline-none focus:border-[#16a34a] transition-colors placeholder-[var(--text-muted)] text-[var(--foreground)]"
                        style={{ borderRadius: 'var(--radius)' }}
                        maxLength={500}
                    />
                    <button
                        type="submit"
                        disabled={!newComment.trim() || sending}
                        className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 text-[#16a34a] disabled:text-[var(--text-muted)] disabled:cursor-not-allowed hover:scale-110 transition-transform"
                    >
                        ➤
                    </button>
                </form>
            </div>
        </div>
    )
}

function CommentItem({
    comment,
    user,
    onReply,
    onLike,
    formatTime,
    isReply = false
}: {
