                    <div className="absolute inset-0 flex items-center justify-center bg-[var(--card-bg)]/80 z-10">
                        <Loader2 className="animate-spin text-[var(--accent)]" />
                    </div>
                )}

                <div className="grid grid-cols-3 gap-2">
                    {gifs.map((gif) => (
                        <button
                            key={gif.id}
                            type="button"
