    )
}

'use client'

import { useState, useEffect, useRef } from 'react'
import { Search, X, Loader2 } from 'lucide-react'

// You should add NEXT_PUBLIC_GIPHY_API_KEY to your .env.local
// Falling back to a public beta key if not provided (might be rate-limited)
const GIPHY_API_KEY = process.env.NEXT_PUBLIC_GIPHY_API_KEY || 'GlVGYHqc3SyCEGqmeHg5XcGWtwMky1A8'

interface GiphySelectorProps {
    onSelect: (gifUrl: string) => void
    onClose: () => void
}

export function GiphySelector({ onSelect, onClose }: GiphySelectorProps) {
    const [query, setQuery] = useState('')
    const [gifs, setGifs] = useState<any[]>([])
    const [loading, setLoading] = useState(false)
    const [error, setError] = useState('')
    const searchTimeoutRef = useRef<NodeJS.Timeout | null>(null)

    const fetchGifs = async (searchQuery: string) => {
        setLoading(true)
        setError('')
        try {
            const endpoint = searchQuery.trim()
                ? `https://api.giphy.com/v1/gifs/search?api_key=${GIPHY_API_KEY}&q=${encodeURIComponent(searchQuery)}&limit=20&rating=g`
                : `https://api.giphy.com/v1/gifs/trending?api_key=${GIPHY_API_KEY}&limit=20&rating=g`

            const response = await fetch(endpoint)
            const data = await response.json()

            if (data.meta?.status === 200) {
                setGifs(data.data)
            } else {
                setError('Error al cargar GIFs')
            }
        } catch (err) {
            console.error('Giphy API error:', err)
            setError('Error de conexión')
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        fetchGifs('')
        return () => {
            if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current)
        }
    }, [])

    const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = e.target.value
        setQuery(val)

        if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current)
        searchTimeoutRef.current = setTimeout(() => {
            fetchGifs(val)
        }, 500)
    }

    return (
        <div className="absolute bottom-full right-0 mb-2 w-72 h-80 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl shadow-xl flex flex-col overflow-hidden z-50">
            {/* Header / Search */}
            <div className="p-3 border-b border-[var(--card-border)] bg-[var(--background)] relative flex items-center gap-2">
                <div className="relative flex-1">
                    <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-[var(--text-muted)] w-4 h-4" />
                    <input
                        type="text"
                        placeholder="Buscar GIFs..."
                        value={query}
                        onChange={handleSearch}
                        className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-full pl-9 pr-4 py-1.5 text-sm focus:outline-none focus:border-[var(--accent)]"
                        autoFocus
                    />
                </div>
                <button
                    onClick={onClose}
                    className="p-1.5 text-[var(--text-muted)] hover:bg-[var(--hover-bg)] rounded-full transition-colors"
                >
                    <X size={16} />
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-2 no-scrollbar">
                {loading && gifs.length === 0 ? (
                    <div className="h-full flex items-center justify-center text-[var(--text-muted)]">
                        <Loader2 className="animate-spin w-6 h-6" />
                    </div>
                ) : error ? (
                    <div className="h-full flex flex-col items-center justify-center text-center p-4">
                        <span className="text-2xl mb-2">😢</span>
                        <p className="text-xs text-[var(--text-muted)]">{error}</p>
                    </div>
                ) : gifs.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-center p-4">
                        <span className="text-2xl mb-2">🔍</span>
                        <p className="text-xs text-[var(--text-muted)]">No se encontraron GIFs</p>
                    </div>
                ) : (
                    <div className="columns-2 gap-2 space-y-2">
                        {gifs.map((gif) => (
                            <div
                                key={gif.id}
                                className="break-inside-avoid relative group cursor-pointer rounded-lg overflow-hidden bg-[var(--input-bg)]"
                                onClick={() => onSelect(gif.images.fixed_height.url)}
                            >
                                <img
                                    src={gif.images.fixed_height_small.url}
                                    alt={gif.title || 'GIF'}
                                    className="w-full h-auto object-cover group-hover:scale-105 transition-transform duration-200"
                                    loading="lazy"
                                />
                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors" />
                            </div>
                        ))}
                    </div>
                )}
            </div>
            {/* Giphy Attribution */}
            <div className="py-1 px-3 text-[10px] text-center text-[var(--text-muted)] bg-[var(--background)] border-t border-[var(--card-border)]">
                Powered By GIPHY
            </div>
        </div>
    )
}

// src/components/HeadToHead.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import Image from 'next/image'
import { CollapsibleSection } from './CollapsibleSection'

interface H2HMatch {
    id: string
    fecha: string
    golesLocal: number
    golesVisitante: number
    competicion: string
}

interface HeadToHeadProps {
    equipoLocal: string
    equipoVisitante: string
    logoLocal?: string
    logoVisitante?: string
}

interface H2HStats {
    victorias1: number
    empates: number
    victorias2: number
    goles1: number
    goles2: number
    partidos: H2HMatch[]
}

export function HeadToHead({ equipoLocal, equipoVisitante, logoLocal, logoVisitante }: HeadToHeadProps) {
    const [stats, setStats] = useState<H2HStats | null>(null)
    const [loading, setLoading] = useState(true)
    const [expanded, setExpanded] = useState(false)

    useEffect(() => {
        fetchH2H()
    }, [equipoLocal, equipoVisitante])

    const fetchH2H = async () => {
        setLoading(true)
        try {
            // Buscar partidos entre estos dos equipos
            const { data, error } = await supabase
                .from('partidos')
                .select('*')
                .or(`and(equipo_local.eq.${equipoLocal},equipo_visitante.eq.${equipoVisitante}),and(equipo_local.eq.${equipoVisitante},equipo_visitante.eq.${equipoLocal})`)
                .eq('estado', 'FINALIZADO')
                .order('fecha_inicio', { ascending: false })
                .limit(10)

            if (error) throw error

            if (data && data.length > 0) {
                let v1 = 0, v2 = 0, e = 0, g1 = 0, g2 = 0

                const partidos: H2HMatch[] = data.map(p => {
                    const esLocal1 = p.equipo_local === equipoLocal
                    const golesEquipo1 = esLocal1 ? p.goles_local : p.goles_visitante
                    const golesEquipo2 = esLocal1 ? p.goles_visitante : p.goles_local

                    g1 += golesEquipo1
                    g2 += golesEquipo2

                    if (golesEquipo1 > golesEquipo2) v1++
                    else if (golesEquipo2 > golesEquipo1) v2++
                    else e++

                    return {
                        id: p.id,
                        fecha: p.fecha_inicio,
                        golesLocal: p.goles_local,
                        golesVisitante: p.goles_visitante,
                        competicion: p.liga
                    }
                })

                setStats({
                    victorias1: v1,
                    empates: e,
                    victorias2: v2,
                    goles1: g1,
                    goles2: g2,
                    partidos
                })
            } else {
                // Demo data si no hay historial
                setStats({
                    victorias1: 3,
                    empates: 2,
                    victorias2: 4,
                    goles1: 12,
                    goles2: 14,
                    partidos: []
                })
            }
        } catch (err: any) {
            console.error('Error fetching H2H:', err)
            // Demo data
            setStats({
                victorias1: 3,
                empates: 2,
                victorias2: 4,
                goles1: 12,
                goles2: 14,
                partidos: []
            })
        } finally {
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-5 animate-pulse" style={{ borderRadius: 'var(--radius)' }}>
                <div className="h-4 w-32 bg-[var(--card-border)] mb-4" style={{ borderRadius: 'var(--radius)' }}></div>
                <div className="flex justify-between items-center">
                    <div className="w-16 h-16 bg-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}></div>
                    <div className="flex-1 mx-4">
                        <div className="h-6 bg-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}></div>
                    </div>
                    <div className="w-16 h-16 bg-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}></div>
                </div>
            </div>
        )
    }

    if (!stats) return null

    const total = stats.victorias1 + stats.empates + stats.victorias2
    const pct1 = total > 0 ? (stats.victorias1 / total) * 100 : 33
    const pctE = total > 0 ? (stats.empates / total) * 100 : 34
    const pct2 = total > 0 ? (stats.victorias2 / total) * 100 : 33

    return (
        <CollapsibleSection title="Historial de Enfrentamientos" icon={<span className="text-xl">⚔️</span>} defaultOpen={false}>

            <div className="p-5">
                {/* Escudos y stats */}
                <div className="flex items-center justify-between gap-4 mb-4">
                    {/* Equipo 1 */}
                    <div className="flex flex-col items-center">
                        {logoLocal ? (
                            <div className="relative w-14 h-14 mb-2">
                                <Image src={logoLocal} alt={equipoLocal} fill className="object-contain" />
                            </div>
                        ) : (
                            <div className="w-14 h-14 bg-[var(--background)] rounded-full flex items-center justify-center mb-2">
                                <span className="text-2xl">⚽</span>
                            </div>
                        )}
                        <span className="text-2xl font-black text-[#16a34a]">{stats.victorias1}</span>
                        <span className="text-[10px] text-[var(--text-muted)] capitalize font-black tracking-widest">Victorias</span>
                    </div>

                    {/* Empates */}
                    <div className="flex flex-col items-center">
                        <div className="w-12 h-12 bg-[var(--background)] flex items-center justify-center mb-2 border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                            <span className="text-xl">🤝</span>
                        </div>
                        <span className="text-2xl font-black text-[#6b7280]">{stats.empates}</span>
                        <span className="text-[10px] text-[var(--text-muted)] capitalize font-black tracking-widest">Empates</span>
                    </div>

                    {/* Equipo 2 */}
                    <div className="flex flex-col items-center">
                        {logoVisitante ? (
                            <div className="relative w-14 h-14 mb-2">
                                <Image src={logoVisitante} alt={equipoVisitante} fill className="object-contain" />
                            </div>
                        ) : (
                            <div className="w-14 h-14 bg-[var(--background)] rounded-full flex items-center justify-center mb-2">
                                <span className="text-2xl">⚽</span>
                            </div>
                        )}
                        <span className="text-2xl font-black text-[#dc2626]">{stats.victorias2}</span>
                        <span className="text-[10px] text-[var(--text-muted)] capitalize font-black tracking-widest">Victorias</span>
                    </div>
                </div>

                {/* Barra de victorias */}
                <div className="flex h-4 overflow-hidden mb-4 border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                    <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${pct1}%` }}
                        transition={{ duration: 0.5 }}
                        className="bg-[#16a34a]"
                    />
                    <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${pctE}%` }}
                        transition={{ duration: 0.5, delay: 0.1 }}
                        className="bg-[#6b7280]"
                    />
                    <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${pct2}%` }}
                        transition={{ duration: 0.5, delay: 0.2 }}
                        className="bg-[#dc2626]"
                    />
                </div>

                {/* Goles totales */}
                <div className="flex justify-between text-xs text-[var(--text-muted)] border-t border-[var(--card-border)] pt-3">
                    <div>
                        <span className="font-bold text-[var(--foreground)]">{stats.goles1}</span> goles
                    </div>
                    <div>
                        <span className="font-bold">{total}</span> partidos
                    </div>
                    <div>
                        <span className="font-bold text-[var(--foreground)]">{stats.goles2}</span> goles
                    </div>
                </div>

                {/* Últimos partidos (expandible) */}
                {stats.partidos.length > 0 && (
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="mt-4 w-full text-center text-xs text-[#ff6b6b] font-bold"
                    >
                        {expanded ? '▲ Ocultar partidos' : '▼ Ver últimos partidos'}
                    </button>
                )}

                {expanded && stats.partidos.length > 0 && (
                    <motion.div
                        initial={{ height: 0, opacity: 0 }}
                        animate={{ height: 'auto', opacity: 1 }}
                        className="mt-3 space-y-2"
                    >
                        {stats.partidos.slice(0, 5).map(match => (
                            <div key={match.id} className="flex justify-between items-center text-[10px] bg-[var(--background)] px-3 py-2 border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                                <span className="text-[var(--text-muted)] font-bold capitalize tracking-widest">
                                    {new Date(match.fecha).toLocaleDateString('es-AR', { day: 'numeric', month: 'short', year: '2-digit' })}
                                </span>
                                <span className="font-black text-xs">
                                    {match.golesLocal} - {match.golesVisitante}
                                </span>
                                <span className="text-[var(--text-muted)] font-bold capitalize tracking-widest">{match.competicion}</span>
                            </div>
                        ))}
                    </motion.div>
                )}
            </div>
        </CollapsibleSection>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { X, Download, Share } from 'lucide-react'

export function InstallPrompt() {
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null)
    const [showPrompt, setShowPrompt] = useState(false)
    const [isIOS, setIsIOS] = useState(false)

    useEffect(() => {
        // Don't show if already dismissed
        if (localStorage.getItem('pwa-dismissed')) return

        // Don't show if already installed (standalone mode)
        const isStandalone = window.matchMedia('(display-mode: standalone)').matches
        if (isStandalone) return

        // Detect iOS
        const isIosDevice = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream
        if (isIosDevice) {
            setIsIOS(true)
            // Delay showing on iOS gracefully
            setTimeout(() => setShowPrompt(true), 1500)
        }

        // Detect Android/PC (Chrome/Edge)
        const handleBeforeInstallPrompt = (e: any) => {
            e.preventDefault()
            setDeferredPrompt(e)
            // Show prompt almost instantly when the browser signals it's ready
            setTimeout(() => setShowPrompt(true), 1000)
        }

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt)

        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt)
        }
    }, [])

    const handleDismiss = () => {
        setShowPrompt(false)
        localStorage.setItem('pwa-dismissed', 'true')
    }

    const handleInstallClick = async () => {
        if (!deferredPrompt) return

        deferredPrompt.prompt()
        const { outcome } = await deferredPrompt.userChoice

        if (outcome === 'accepted') {
            localStorage.setItem('pwa-dismissed', 'true')
        }
        setShowPrompt(false)
        setDeferredPrompt(null)
    }

    return (
        <AnimatePresence>
            {showPrompt && (
                <motion.div
                    initial={{ opacity: 0, y: 20, scale: 0.95 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 10, scale: 0.95 }}
                    transition={{ type: 'spring', damping: 25, stiffness: 300 }}
                    className="fixed z-50
                        bottom-20 left-4 right-4
                        md:bottom-6 md:left-auto md:right-6 md:max-w-xs"
                >
                    <div className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                        {/* Close button */}
                        <button
                            onClick={handleDismiss}
                            className="absolute top-2.5 right-2.5 w-6 h-6 border border-[var(--card-border)]
                                       bg-[var(--background)] flex items-center justify-center
                                       text-[var(--text-muted)] hover:text-[var(--foreground)]
                                       transition-colors z-10"
                            aria-label="Cerrar"
                        >
                            <X size={10} />
                        </button>

                        <div className="p-4">
                            <div className="flex items-start gap-3">
                                {/* Icon */}
                                <div className="w-10 h-10 bg-[var(--background)] border border-[var(--card-border)]
                                                flex items-center justify-center flex-shrink-0" style={{ borderRadius: 'var(--radius)' }}>
                                    <span className="text-lg">⚽</span>
                                </div>

                                <div className="flex-1 min-w-0 pr-4">
                                    <h3 className="font-black text-[10px] capitalize tracking-widest text-[var(--foreground)] leading-tight">
                                        Instalá FutLog
                                    </h3>
                                    <p className="text-[9px] font-bold text-[var(--text-muted)] capitalize mt-0.5 leading-snug">
                                        {isIOS
                                            ? 'Acceso rápido desde tu inicio'
                                            : 'Accedé más rápido como app'}
                                    </p>
                                </div>
                            </div>

                            {/* Action area */}
                            <div className="mt-3">
                                {isIOS ? (
                                    <p className="text-[9px] font-bold capitalize text-[var(--text-muted)] bg-[var(--background)] border border-[var(--card-border)] px-3 py-2 flex items-center gap-2">
                                        <Share size={12} className="text-[var(--foreground)] flex-shrink-0" />
                                        <span>
                                            Tocá <span className="font-black text-[var(--foreground)]">Compartir</span> y luego{' '}
                                            <span className="font-black text-[var(--foreground)]">"Agregar a Inicio"</span>
                                        </span>
                                    </p>
                                ) : (
                                    <div className="flex gap-2">
                                        <button
                                            onClick={handleDismiss}
                                            className="flex-1 py-2 border border-[var(--card-border)] text-[9px] font-black capitalize
                                                       text-[var(--text-muted)] hover:text-[var(--foreground)]
                                                       hover:bg-[var(--hover-bg)] transition-all"
                                        >
                                            AHORA NO
                                        </button>
                                        <button
                                            onClick={handleInstallClick}
                                            className="flex-1 py-2 border border-[var(--foreground)] text-[9px] font-black capitalize
                                                       bg-[var(--foreground)] text-[var(--background)]
                                                       transition-all flex items-center justify-center gap-1.5"
                                        >
                                            <Download size={11} />
                                            INSTALAR
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    )
}

// src/components/MatchLiveChat.tsx
'use client'

import { useState, useRef, useEffect } from 'react'
import { Send, Users, MoreVertical, Trash2, Smile, AlertTriangle, ShieldAlert } from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { useRouter } from 'next/navigation'
import { useMatchChat, type ChatMessage } from '@/hooks/useMatchChat'
import { useToast } from '@/contexts/ToastContext'
import { GiphySelector } from '@/components/GiphySelector'
import { CreateGroupModal } from '@/components/CreateGroupModal'
import { ChatPoll } from '@/components/ChatPoll'

interface MatchLiveChatProps {
    partidoId: string
    matchTitle?: string
}

function timeAgoShort(date: string) {
    const diff = Date.now() - new Date(date).getTime()
    const diffMins = Math.floor(diff / 60000)
    const diffHours = Math.floor(diffMins / 60)

    if (diffMins < 1) return 'ahora'
    if (diffMins < 60) return `${diffMins}m`
    if (diffHours < 24) return `${diffHours}h`
    return new Date(date).toLocaleDateString()
}

function renderMessage(content: string) {
    if (content.includes('giphy.com/media/')) {
        return (
            <img
                src={content}
                alt="GIF"
                className="max-w-[200px] w-full h-auto rounded-lg object-cover"
                loading="lazy"
            />
        )
    }
    return <p className="break-words">{content}</p>
}

export function MatchLiveChat({ partidoId, matchTitle }: MatchLiveChatProps) {
    const { user } = useAuth()
    const { showToast } = useToast()
    const router = useRouter()
    const { messages, loading, onlineUsers, sendMessage, deleteMessage } = useMatchChat(partidoId)

    const [newMessage, setNewMessage] = useState('')
    const [isSending, setIsSending] = useState(false)
    const [activeMenuId, setActiveMenuId] = useState<string | null>(null)
    const [showGiphy, setShowGiphy] = useState(false)
    const [showCreateGroup, setShowCreateGroup] = useState(false)
    const messagesEndRef = useRef<HTMLDivElement>(null)
    const chatContainerRef = useRef<HTMLDivElement>(null)

    // Auto-scroll logic. Scroll to bottom if user is already near the bottom,
    // or if they just sent a message.
    useEffect(() => {
        if (!chatContainerRef.current) return

        const { scrollTop, scrollHeight, clientHeight } = chatContainerRef.current
        const isNearBottom = scrollHeight - scrollTop - clientHeight < 100

        if (isNearBottom || isSending) {
            messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
        }
    }, [messages, isSending])

    const handleSend = async (e: React.FormEvent) => {
        e.preventDefault()
        if (!newMessage.trim() || !user || isSending) return

        setIsSending(true)
        const success = await sendMessage(newMessage)
        if (success) {
            setNewMessage('')
            // Auto scroll will trigger from effect
        } else {
            showToast('Error al enviar mensaje', 'error')
        }
        setIsSending(false)
    }

    const handleSelectGif = async (gifUrl: string) => {
        setShowGiphy(false)
        if (!user || isSending) return

        setIsSending(true)
        const success = await sendMessage(gifUrl)
        if (!success) {
            showToast('Error al enviar GIF', 'error')
        }
        setIsSending(false)
    }

    const handleDelete = async (msgId: string) => {
        const success = await deleteMessage(msgId)
        if (success) {
            showToast('Mensaje eliminado', 'success')
            setActiveMenuId(null)
        }
    }

    const handleReport = async (msgId: string) => {
        if (!user) {
            router.push('/login')
            return
        }
        try {
            const { error } = await supabase.from('message_reports').insert({
                reporter_id: user.id,
                message_id: msgId,
                reason: 'Reportado por usuario'
            })
            if (error) {
                if (error.code === '23505') { // Unique constraint violation
                    showToast('Ya reportaste este mensaje', 'error')
                } else {
                    throw error
                }
            } else {
                showToast('Mensaje reportado. Nuestro equipo lo revisará.', 'success')
            }
        } catch (err) {
            console.error('Error reporting message:', err)
            showToast('Error al reportar mensaje', 'error')
        } finally {
            setActiveMenuId(null)
        }
    }

    // Blurred Teaser for Unauthenticated Users
    if (!user) {
        return (
            <div className="flex flex-col h-[500px] bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden relative" style={{ borderRadius: 'var(--radius)' }}>
                {/* Header */}
                <div className="flex items-center justify-between px-4 py-3 bg-[var(--background)] border-b border-[var(--card-border)] border-dashed sticky top-0 z-10">
                    <div className="flex items-center gap-2">
                        <h3 className="font-black text-[10px] capitalize tracking-widest">Chat en vivo</h3>
                        <div className="flex items-center gap-1.5 px-2 py-0.5 border border-[#16a34a] text-[#16a34a] text-[8px] font-black capitalize">
                            <div className="w-1.5 h-1.5 bg-[#16a34a]" />
                            LIVE
                        </div>
                    </div>
                </div>

                {/* Blurred Chat Area */}
                <div className="flex-1 relative overflow-hidden bg-[var(--background)] p-4 flex flex-col justify-end cursor-pointer" onClick={() => router.push('/login')}>
                    <div className="absolute inset-0 z-10 bg-black/5 backdrop-blur-[2px]" />
                    <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none">
                        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-5 shadow-xl max-w-[280px] text-center transform scale-105 pointer-events-auto" style={{ borderRadius: 'var(--radius)' }}>
                            <h4 className="font-black text-sm mb-2 text-[var(--foreground)] capitalize">¡Sumate a la tribuna!</h4>
                            <p className="text-[10px] text-[var(--text-muted)] font-bold capitalize mb-4 leading-tight">Iniciá sesión para leer los mensajes y debatir.</p>
                            <a href="/login" className="inline-block w-full bg-[var(--foreground)] text-[var(--background)] font-black py-2.5 text-[10px] capitalize tracking-widest hover:bg-[var(--foreground)] transition-colors" style={{ borderRadius: 'var(--radius)' }}>
                                ENTRAR A LA CANCHA
                            </a>
                        </div>
                    </div>

                    {/* Fake glowing messages */}
                    <div className="flex flex-col gap-4 opacity-30 blur-[2px] mb-2 pointer-events-none">
                        <div className="self-end bg-[var(--accent)] h-10 w-48 rounded-2xl rounded-tr-sm" />
                        <div className="self-start bg-[var(--input-bg)] h-12 w-64 rounded-2xl rounded-tl-sm" />
                        <div className="self-end bg-[var(--accent)] h-8 w-32 rounded-2xl rounded-tr-sm" />
                        <div className="self-start bg-[var(--input-bg)] h-16 w-56 rounded-2xl rounded-tl-sm" />
                    </div>

                    <div className="text-center pb-2 z-20 pointer-events-none opacity-50 blur-[1px]">
                        <p className="text-[9px] font-black capitalize text-[var(--foreground)]">Ver más mensajes...</p>
                    </div>
                </div>

                {/* Disabled Input */}
                <div className="p-3 bg-[var(--background)] border-t border-[var(--card-border)] opacity-50 relative pointer-events-none">
                    <div className="flex items-center gap-2">
                        <input
                            type="text"
                            disabled
                            placeholder="Iniciá sesión para unirte al chat..."
                            className="flex-1 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-full px-4 py-2.5 text-sm"
                        />
                        <button
                            disabled
                            className="w-10 h-10 rounded-full bg-[var(--card-border)] flex items-center justify-center shrink-0"
                        >
                            <Send size={16} className="text-[var(--text-muted)]" style={{ marginLeft: 2 }} />
                        </button>
                    </div>
                </div>
            </div>
        )
    }

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center py-12 text-[var(--text-muted)] animate-pulse">
                <div className="w-8 h-8 rounded-full border-2 border-[var(--accent)] border-t-transparent animate-spin mb-4" />
                Cargando chat...
            </div>
        )
    }

    return (
        <div className="flex flex-col h-[500px] bg-[var(--card-bg)] border border-[var(--card-border)] rounded-3xl overflow-hidden shadow-sm relative">
            <CreateGroupModal
                isOpen={showCreateGroup}
                onClose={() => setShowCreateGroup(false)}
            />
            {/* Header */}
            <div className="flex flex-col bg-[var(--background)] border-b border-[var(--card-border)] sticky top-0 z-10">
                <div className="flex items-center justify-between px-4 py-3">
                    <div className="flex items-center gap-2">
                        <h3 className="font-bold text-sm">Chat en vivo</h3>
                        <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-green-500/10 text-green-500 text-[10px] font-bold">
                            <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                            LIVE
                        </div>
                    </div>
                    <div className="flex gap-2 items-center">
                        <button
                            onClick={() => setShowCreateGroup(true)}
                            className="text-[8px] bg-[var(--background)] text-[var(--foreground)] font-black px-2 py-1 hover:bg-[var(--hover-bg)] transition-colors border border-[var(--card-border)] hidden sm:flex items-center gap-1 capitalize"
                            style={{ borderRadius: 'var(--radius)' }}
                            title="Crear grupo privado para este partido"
                        >
                            <Users size={10} />
                            Crear Grupo
                        </button>
                        <div className="flex items-center gap-1.5 text-xs text-[var(--text-muted)] font-medium bg-[var(--hover-bg)] px-2 py-1 rounded-full">
                            <Users size={12} />
                            {onlineUsers} {onlineUsers === 1 ? 'espectador' : 'espectadores'}
                        </div>
                    </div>
                </div>
                {/* Mobile Create Group Button */}
                <div className="sm:hidden px-4 pb-2">
                    <button
                        onClick={() => setShowCreateGroup(true)}
                        className="w-full text-[9px] bg-[var(--background)] text-[var(--foreground)] font-black py-1.5 hover:bg-[var(--hover-bg)] transition-colors border border-[var(--card-border)] flex items-center justify-center gap-1.5 capitalize"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <Users size={12} className="text-[var(--text-muted)]" />
                        Crear Grupo Privado
                    </button>
                </div>
            </div>

            {/* Messages Area */}
            <div
                ref={chatContainerRef}
                className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar"
                style={{ scrollBehavior: 'smooth' }}
                onClick={() => setActiveMenuId(null)} // Close menus when clicking outside
            >
                <ChatPoll partidoId={partidoId} />
                {messages.length === 0 ? (
                    <div className="h-full flex flex-col items-center justify-center text-center text-[var(--text-muted)] opacity-70">
                        <span className="text-4xl mb-3">💬</span>
                        <p className="text-sm">No hay mensajes aún.</p>
                        <p className="text-xs">¡Sé el primero en comentar!</p>
                    </div>
                ) : (
                    messages.map((msg) => {
                        const isOwn = user?.id === msg.user_id
                        const isMenuOpen = activeMenuId === msg.id

                        return (
                            <motion.div
                                key={msg.id}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                className={`flex gap-3 ${isOwn ? 'flex-row-reverse' : 'flex-row'}`}
                            >
                                <div
                                    className="w-8 h-8 bg-[var(--background)] border border-[var(--card-border)] shrink-0 overflow-hidden flex items-center justify-center text-[var(--foreground)] text-[10px] font-black cursor-pointer hover:border-[var(--foreground)] transition-all"
                                    style={{ borderRadius: 'var(--radius)' }}
                                    onClick={(e) => {
                                        e.stopPropagation()
                                        if (msg.user_id) window.location.href = `/perfil/${msg.user_id}`
                                    }}
                                >
                                    {msg.profile?.avatar_url ? (
                                        <img src={msg.profile.avatar_url} alt="" className="w-full h-full object-cover" />
                                    ) : (
                                        msg.profile?.username?.charAt(0)?.toUpperCase() || '?'
                                    )}
                                </div>

                                <div className={`flex flex-col relative group max-w-[80%] ${isOwn ? 'items-end' : 'items-start'}`}>
                                    <div className="flex items-baseline gap-2 mb-1 px-1">
                                        <span
                                            className="text-[9px] font-black capitalize text-[var(--text-muted)] cursor-pointer hover:text-[var(--foreground)] hover:underline transition-colors"
                                            onClick={(e) => {
                                                e.stopPropagation()
                                                if (msg.user_id) window.location.href = `/perfil/${msg.user_id}`
                                            }}
                                        >
                                            {isOwn ? 'Vos' : (msg.profile?.username || 'Anónimo')}
                                        </span>
                                        <span className="text-[9px] text-[var(--text-muted)] opacity-60">
                                            {timeAgoShort(msg.created_at)}
                                        </span>
                                    </div>

                                    <div className={`
                                        relative px-4 py-2.5 text-sm leading-relaxed border border-[var(--card-border)]
                                        ${isOwn
                                            ? 'bg-[var(--foreground)] text-[var(--background)]'
                                            : 'bg-[var(--background)] text-[var(--foreground)]'
                                        }
                                    `} style={{ borderRadius: 'var(--radius)' }}>
                                        {renderMessage(msg.content)}

                                        {/* Actions Menu Trigger */}
                                        {user && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation()
                                                    setActiveMenuId(isMenuOpen ? null : msg.id)
                                                }}
                                                className={`absolute top-1/2 -translate-y-1/2 p-1.5 rounded-full transition-opacity
                                                    ${isOwn ? '-left-8 text-[var(--text-muted)] hover:bg-[var(--hover-bg)]' : '-right-8 text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'}
                                                    ${isMenuOpen ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}
                                                `}
                                            >
                                                <MoreVertical size={14} />
                                            </button>
                                        )}
                                    </div>

                                    {/* Action Context Menu */}
                                    <AnimatePresence>
                                        {isMenuOpen && user && (
                                            <motion.div
                                                initial={{ opacity: 0, scale: 0.95 }}
                                                animate={{ opacity: 1, scale: 1 }}
                                                exit={{ opacity: 0, scale: 0.95 }}
                                                className={`absolute top-10 ${isOwn ? 'left-auto right-full mr-2' : 'left-full ml-2'} z-20 
                                                        bg-[var(--card-bg)] border border-[var(--card-border)] shadow-xl overflow-hidden py-1 min-w-[120px]`}
                                                style={{ borderRadius: 'var(--radius)' }}
                                            >
                                                {isOwn ? (
                                                    <button
                                                        onClick={() => handleDelete(msg.id)}
                                                        className="w-full flex items-center gap-2 px-4 py-2 text-xs text-red-500 hover:bg-red-500/10 transition-colors whitespace-nowrap"
                                                    >
                                                        <Trash2 size={14} />
                                                        Eliminar
                                                    </button>
                                                ) : (
                                                    <button
                                                        onClick={() => handleReport(msg.id)}
                                                        className="w-full flex items-center gap-2 px-4 py-2 text-xs text-[#f59e0b] hover:bg-[#f59e0b]/10 transition-colors whitespace-nowrap"
                                                    >
                                                        <ShieldAlert size={14} />
                                                        Reportar
                                                    </button>
                                                )}
                                            </motion.div>
                                        )}
                                    </AnimatePresence>
                                </div>
                            </motion.div>
                        )
                    })
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-3 bg-[var(--background)] border-t border-[var(--card-border)] relative">
                {showGiphy && (
                    <div className="absolute bottom-full right-4 mb-2 z-50">
                        <GiphySelector
                            onSelect={handleSelectGif}
                            onClose={() => setShowGiphy(false)}
                        />
                    </div>
                )}

                <form onSubmit={handleSend} className="flex items-center gap-2">
                    <button
                        type="button"
                        onClick={() => setShowGiphy(!showGiphy)}
                        className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 transition-colors
                            ${showGiphy ? 'bg-[var(--accent)] text-white' : 'bg-[var(--hover-bg)] text-[var(--text-muted)] hover:bg-[var(--card-border)]'}`}
                    >
                        <Smile size={18} />
                    </button>
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        placeholder="Comentá algo..."
                        className="flex-1 bg-[var(--background)] border border-[var(--card-border)] px-4 py-2.5 text-[10px] font-bold capitalize focus:outline-none focus:border-[var(--foreground)] transition-colors"
                        style={{ borderRadius: 'var(--radius)' }}
                        disabled={isSending}
                    />
                    <button
                        type="submit"
                        disabled={!newMessage.trim() || isSending}
                        className="w-10 h-10 border border-[var(--foreground)] bg-[var(--foreground)] text-[var(--background)] flex items-center justify-center shrink-0 hover:bg-[var(--foreground)] disabled:opacity-50 transition-all font-black"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <Send size={14} className={isSending ? 'animate-pulse' : ''} style={{ marginLeft: 2 }} />
                    </button>
                </form>
            </div>
        </div>
    )
}

// src/components/MatchLogCard.tsx
'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { motion, AnimatePresence } from 'framer-motion'
import { Heart, MessageCircle, Share2, Eye, EyeOff, Tv, MapPin, Users, HelpCircle, Clock, ListPlus, Flag } from 'lucide-react'
import { StarRatingDisplay } from './StarRating'
import { TeamLogo } from './TeamLogo'
import { AddToListModal } from './AddToListModal'
import { hapticFeedback } from '@/lib/helpers'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import { supabase } from '@/lib/supabase'
import type { MatchLog } from '@/types'

const MATCH_TYPE_META: Record<string, { icon: typeof Tv; label: string; color: string }> = {
    tv: { icon: Tv, label: 'TV', color: '#2563eb' },
    stadium: { icon: MapPin, label: 'Cancha', color: '#16a34a' },
    friend: { icon: Users, label: 'Amigos', color: '#d97706' },
    other: { icon: HelpCircle, label: 'Otro', color: '#7c3aed' },
}

function timeAgo(date: string): string {
    const now = new Date()
    const d = new Date(date)
    const diffMs = now.getTime() - d.getTime()
    const diffMins = Math.floor(diffMs / 60000)
    const diffHours = Math.floor(diffMs / 3600000)
    const diffDays = Math.floor(diffMs / 86400000)

    if (diffMins < 1) return 'ahora'
    if (diffMins < 60) return `${diffMins}m`
    if (diffHours < 24) return `${diffHours}h`
    if (diffDays < 7) return `${diffDays}d`
    return d.toLocaleDateString('es-AR', { day: 'numeric', month: 'short' })
}

interface MatchLogCardProps {
    log: MatchLog
    onLike?: (id: string, type?: string) => void
    compact?: boolean
}

const REACTIONS = [
    { type: 'like', emoji: '❤️', label: 'Like' },
    { type: 'fuego', emoji: '🔥', label: 'Fuego' },
    { type: 'termo', emoji: '🧉', label: 'Termo' },
    { type: 'roja', emoji: '🟥', label: 'Roja' },
]

export function MatchLogCard({ log, onLike, compact = false }: MatchLogCardProps) {
    const router = useRouter()
    const [spoilerRevealed, setSpoilerRevealed] = useState(false)
    const [showAddToList, setShowAddToList] = useState(false)
    const [reporting, setReporting] = useState(false)
    const [showReactions, setShowReactions] = useState(false)
    const [showReportConfirm, setShowReportConfirm] = useState(false)
    const { user } = useAuth()
    const { showToast } = useToast()

    const typeMeta = MATCH_TYPE_META[log.match_type] || MATCH_TYPE_META.other
    const TypeIcon = typeMeta.icon

    const handleShare = async (e: React.MouseEvent) => {
        e.stopPropagation()
        if (navigator.share) {
            try {
                await navigator.share({
                    title: `${log.equipo_local} vs ${log.equipo_visitante}`,
                    text: log.review_title || `Rating: ${log.rating_partido}/5`,
                    url: `${window.location.origin}/log/${log.id}`,
                })
            } catch { /* cancelled */ }
        } else {
            navigator.clipboard.writeText(`${window.location.origin}/log/${log.id}`)
        }
    }

    const handleReport = async (e: React.MouseEvent) => {
      e.stopPropagation()
      if (!user) { router.push('/login'); return }
      if (!showReportConfirm) { setShowReportConfirm(true); return }
      setReporting(true)
      setShowReportConfirm(false)
      try {
        const { error } = await supabase
          .from('match_log_reports')
          .insert({
            match_log_id: log.id,
            reporter_id: user.id,
            reason: 'Contenido Inapropiado',
            details: 'Reportado desde la card de reseña.'
          })
        if (error) throw error
        showToast('Reporte enviado. Lo revisaremos a la brevedad.', 'success')
      } catch {
        showToast('Hubo un error al enviar el reporte.', 'error')
      } finally {
        setReporting(false)
      }
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-[var(--card-bg)] border border-[var(--card-border)] overflow-hidden
                 hover:border-[var(--foreground)] transition-all duration-300 cursor-pointer group"
            style={{ borderRadius: 'var(--radius)' }}
            onClick={() => router.push(`/log/${log.id}`)}
        >
            {/* Header: User info + time */}
            <div className="flex items-center gap-3 px-4 pt-3.5 pb-2">
                <div
                    className="w-8 h-8 bg-[var(--foreground)] flex items-center justify-center text-[var(--background)] text-xs font-black shrink-0 cursor-pointer hover:ring-2 hover:ring-[var(--foreground)]/50 transition-all"
                    style={{ borderRadius: 'var(--radius)' }}
                    onClick={(e) => {
                        e.stopPropagation()
                        if (log.user_id) router.push(`/perfil/${log.user_id}`)
                    }}
                >
                    {log.profile?.avatar_url ? (
                        <img src={log.profile.avatar_url} alt="" className="w-full h-full object-cover" style={{ borderRadius: 'var(--radius)' }} />
                    ) : (
                        log.profile?.username?.charAt(0)?.toUpperCase() || '?'
                    )}
                </div>
                <div className="flex-1 min-w-0">
                    <span
                        className="text-sm font-black capitalize italic tracking-tighter truncate block cursor-pointer hover:underline transition-colors w-fit"
                        onClick={(e) => {
                            e.stopPropagation()
                            if (log.user_id) router.push(`/perfil/${log.user_id}`)
                        }}
                    >
                        {log.profile?.username || 'Anónimo'}
                    </span>
                    <div className="flex items-center gap-1.5 text-[10px] text-[var(--text-muted)]">
                        <TypeIcon size={10} style={{ color: typeMeta.color }} />
                        <span>{typeMeta.label}</span>
                        <span>·</span>
                        <Clock size={9} />
                        <span>{timeAgo(log.created_at)}</span>
                    </div>
                </div>
                {log.is_neutral && (
                    <span className="text-[10px] px-1.5 py-0.5 border border-[var(--card-border)] bg-[var(--background)] text-[var(--foreground)] font-black capitalize tracking-widest hidden sm:inline-block">
                        📐 Neutral
                    </span>
                )}
                <div className="flex gap-1">
                    {log.is_neutral && (
                        <span className="sm:hidden text-[10px] px-1.5 py-0.5 border border-[var(--card-border)] bg-[var(--background)] text-[var(--foreground)] font-black shrink-0">
                            📐
                        </span>
                    )}
                    {log.is_private && (
                        <span className="text-[10px] px-1.5 py-0.5 border border-amber-500/30 bg-amber-500/10 text-amber-600 font-bold capitalize shrink-0">
                            Privado
                        </span>
                    )}
                </div>
            </div>

            {/* Match Info */}
            <div className="px-4 py-3">
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2 flex-1 min-w-0">
                        <TeamLogo src={log.logo_local} teamName={log.equipo_local} size={24} />
                        <span className="text-sm font-semibold truncate">{log.equipo_local}</span>
                    </div>

                    {log.goles_local != null && log.goles_visitante != null ? (
                        <div className="text-center px-2">
                            <div className="text-lg font-bold tabular-nums tracking-wider">
                                {log.goles_local} - {log.goles_visitante}
                            </div>
                        </div>
                    ) : (
                        <div className="text-xs text-[var(--text-muted)] px-2">vs</div>
                    )}

                    <div className="flex items-center gap-2 flex-1 min-w-0 justify-end">
                        <span className="text-sm font-semibold truncate text-right">{log.equipo_visitante}</span>
                        <TeamLogo src={log.logo_visitante} teamName={log.equipo_visitante} size={24} />
                    </div>
                </div>
                {log.liga && (
                    <div className="text-[10px] text-[var(--text-muted)] text-center mt-1">{log.liga}</div>
                )}
            </div>

            {/* Rating Stars - prominent */}
            <div className="flex items-center justify-center gap-3 px-4 py-2 border-y border-[var(--card-border)] bg-[var(--background)]/30">
                <StarRatingDisplay value={log.rating_partido} size="md" />
                <span className="text-xl font-black text-[var(--foreground)] italic tracking-tighter tabular-nums">{log.rating_partido.toFixed(1)}</span>
            </div>

            {/* Secondary Ratings Pills */}
            {(log.rating_arbitro || log.rating_atmosfera || log.rating_dt) && (
                <div className="flex gap-2 px-4 pb-2 justify-center flex-wrap">
                    {log.rating_arbitro && log.rating_arbitro > 0 && (
                        <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 font-black capitalize tracking-widest
                           bg-[var(--hover-bg)] text-[var(--text-muted)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                            🟨 Arb {log.rating_arbitro.toFixed(1)}
                        </span>
                    )}
                    {log.rating_atmosfera && log.rating_atmosfera > 0 && (
                        <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 font-black capitalize tracking-widest
                           bg-[var(--hover-bg)] text-[var(--text-muted)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                            🏟️ Atm {log.rating_atmosfera.toFixed(1)}
                        </span>
                    )}
                    {log.rating_dt && log.rating_dt > 0 && (
                        <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 font-black capitalize tracking-widest
                           bg-[var(--hover-bg)] text-[var(--text-muted)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                            🧥 DT {log.rating_dt.toFixed(1)}
                        </span>
                    )}
                    {log.rating_garra && log.rating_garra > 0 && (
                        <span className="flex items-center gap-1 text-[10px] px-2 py-0.5 font-black capitalize tracking-widest
                           bg-red-600 text-white border border-red-700" style={{ borderRadius: 'var(--radius)' }}>
                            🔥 Garra {log.rating_garra.toFixed(1)}
                        </span>
                    )}
                </div>
            )}

            {/* Estrella y Villano */}
            {(log.jugador_estrella || log.jugador_villano) && (
                <div className="flex gap-2 px-4 pb-2 justify-center">
                    {log.jugador_estrella && (
                        <span className="text-[10px] px-2 py-0.5 font-black capitalize tracking-widest bg-[var(--foreground)] text-[var(--background)] border border-[var(--foreground)]" style={{ borderRadius: 'var(--radius)' }}>
                            ⭐ {log.jugador_estrella}
                        </span>
                    )}
                    {log.jugador_villano && (
                        <span className="text-[10px] px-2 py-0.5 font-black capitalize tracking-widest bg-red-600 text-white border border-red-700" style={{ borderRadius: 'var(--radius)' }}>
                            😈 {log.jugador_villano}
                        </span>
                    )}
                </div>
            )}

            {/* Photo */}
            {log.foto_url && !compact && (
                <div className="px-4 pb-3">
                    <div className="overflow-hidden border border-[var(--card-border)] max-h-48 grayscale hover:grayscale-0 transition-all" style={{ borderRadius: 'var(--radius)' }}>
                        <img src={log.foto_url} alt="Momento del partido" className="w-full h-full object-cover"
                            onError={(e) => (e.currentTarget.style.display = 'none')} />
                    </div>
                </div>
            )}

            {/* Review Preview */}
            {log.review_text && !compact && (
                <div className="px-4 pb-3">
                    {log.is_spoiler && !spoilerRevealed ? (
                        <button
                            onClick={(e) => { e.stopPropagation(); setSpoilerRevealed(true) }}
                            className="flex items-center gap-2 w-full p-3 rounded-xl bg-red-500/5 border border-red-500/20
                       text-xs text-red-400 hover:bg-red-500/10 transition-colors"
                        >
                            <EyeOff size={14} />
                            <span>Esta reseña contiene spoilers — tocar para revelar</span>
                        </button>
                    ) : (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ duration: 0.4 }}
                        >
                            {log.review_title && (
                                <h4 className="text-sm font-semibold mb-1">{log.review_title}</h4>
                            )}
                            <p className="text-xs text-[var(--text-muted)] line-clamp-3 leading-relaxed">
                                {log.review_text}
                            </p>
                        </motion.div>
                    )}
                </div>
            )}

            {/* Tags */}
            {log.tags && log.tags.length > 0 && !compact && (
                <div className="flex gap-1 px-4 pb-3 flex-wrap">
                    {log.tags.map(tag => (
                        <span key={tag} className="text-[10px] px-2 py-0.5 font-black capitalize tracking-widest border border-[var(--card-border)] bg-[var(--background)] text-[var(--text-muted)]" style={{ borderRadius: 'var(--radius)' }}>
                            #{tag}
                        </span>
                    ))}
                </div>
            )}

            {/* Action Bar */}
            <div className="flex items-center gap-1 px-2 py-2 border-t border-[var(--card-border)] relative z-10">
                <div className="relative">
                    <button
                        type="button"
                        onClick={(e) => {
                            e.stopPropagation();
                            hapticFeedback(15);
                            if (log.is_liked) {
                                onLike?.(log.id, log.my_reaction);
                            } else {
                                setShowReactions(!showReactions);
                            }
                        }}
                        onMouseEnter={() => setShowReactions(true)}
                        className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-black transition-all group/heart
                            ${log.is_liked
                                ? 'text-red-600 bg-red-600/10'
                                : 'text-[var(--text-muted)] hover:text-red-600 hover:bg-black/5'
                            }`}
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <motion.div
                            animate={log.is_liked ? { scale: [1, 1.2, 1] } : {}}
                            transition={{ duration: 0.3 }}
                        >
                            {log.is_liked ? (
                                <span className="text-sm">
                                    {REACTIONS.find(r => r.type === log.my_reaction)?.emoji || '❤️'}
                                </span>
                            ) : (
                                <Heart
                                    size={16}
                                    className={`${log.is_liked ? 'drop-shadow-[0_0_8px_rgba(239,68,68,0.5)]' : ''}`}
                                />
                            )}
                        </motion.div>
                        {(log.likes_count || 0) > 0 && (
                            <motion.span
                                key={log.likes_count}
                                initial={{ opacity: 0, y: 5 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="tabular-nums"
                            >
                                {log.likes_count}
                            </motion.span>
                        )}
                    </button>

                    <AnimatePresence>
                        {showReactions && (
                            <motion.div
                                initial={{ opacity: 0, y: 10, scale: 0.9 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                exit={{ opacity: 0, y: 10, scale: 0.9 }}
                                onMouseLeave={() => setShowReactions(false)}
                                className="absolute bottom-full left-0 mb-2 p-1 bg-[var(--card-bg)] border border-[var(--card-border)] shadow-xl flex gap-1 z-[60]"
                                style={{ borderRadius: '20px' }}
                            >
                                {REACTIONS.map((r) => (
                                    <button
                                        key={r.type}
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            hapticFeedback(20);
                                            onLike?.(log.id, r.type);
                                            setShowReactions(false);
                                        }}
                                        className={`w-10 h-10 flex items-center justify-center text-lg hover:bg-[var(--hover-bg)] transition-colors
                                            ${log.my_reaction === r.type ? 'bg-[var(--accent)]/10' : ''}`}
                                        style={{ borderRadius: '50%' }}
                                        title={r.label}
                                    >
                                        {r.emoji}
                                    </button>
                                ))}
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
                <button
                    type="button"
                    onClick={(e) => { e.stopPropagation(); router.push(`/log/${log.id}`) }}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-black
                   text-[var(--text-muted)] hover:text-blue-600 hover:bg-blue-600/5 transition-all"
                    style={{ borderRadius: 'var(--radius)' }}
                >
                    <MessageCircle size={14} />
                </button>
                <button
                    type="button"
                    onClick={(e) => { e.stopPropagation(); setShowAddToList(true) }}
                    className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-black
                   text-[var(--text-muted)] hover:text-[#16a34a] hover:bg-[#16a34a]/5 transition-all"
                    style={{ borderRadius: 'var(--radius)' }}
                    title="Añadir a una lista"
                >
                    <ListPlus size={14} />
                </button>
                <div className="flex-1" />
                <div className="relative">
                    <AnimatePresence>
                        {showReportConfirm && (
                            <motion.div
                                initial={{ opacity: 0, scale: 0.9, y: 5 }}
                                animate={{ opacity: 1, scale: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.9, y: 5 }}
                                className="absolute bottom-full right-0 mb-2 p-2 bg-[var(--card-bg)] border border-red-500/30 shadow-xl flex items-center gap-2 z-[60] whitespace-nowrap"
                                style={{ borderRadius: 'var(--radius)' }}
                                onClick={e => e.stopPropagation()}
                            >
                                <span className="text-xs text-[var(--text-muted)]">¿Reportar?</span>
                                <button
                                    onClick={handleReport}
                                    className="text-xs font-black px-2 py-1 bg-red-600 text-white"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >Sí</button>
                                <button
                                    onClick={e => { e.stopPropagation(); setShowReportConfirm(false) }}
                                    className="text-xs font-black px-2 py-1 bg-[var(--hover-bg)] text-[var(--text-muted)]"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >No</button>
                            </motion.div>
                        )}
                    </AnimatePresence>
                    <button
                        type="button"
                        onClick={handleReport}
                        disabled={reporting}
                        className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-black
                           text-[var(--text-muted)] hover:text-red-600 hover:bg-red-600/5 transition-all disabled:opacity-50"
                        style={{ borderRadius: 'var(--radius)' }}
                        title="Reportar contenido"
                    >
                        <Flag size={14} className={reporting ? 'animate-pulse' : ''} />
                    </button>
                </div>
            </div>

            {/* List Modal - Mounted only when needed so it doesn't cause hydration or bubbling issues */}
            {showAddToList && (
                <div onClick={(e) => e.stopPropagation()}>
                    <AddToListModal
                        isOpen={showAddToList}
                        onClose={() => setShowAddToList(false)}
                        matchData={{
                            partido_id: log.partido_id?.toString() || log.id,
                            equipo_local: log.equipo_local,
                            equipo_visitante: log.equipo_visitante,
                            logo_local: log.logo_local,
                            logo_visitante: log.logo_visitante
                        }}
                    />
                </div>
            )}
        </motion.div>
    )
}

// src/components/MatchLogForm.tsx
'use client'

import { useState, useEffect, useRef } from 'react'
import { useRouter } from 'next/navigation'
import { motion, AnimatePresence } from 'framer-motion'
import {
    Tv, MapPin, Users, HelpCircle, ChevronLeft, ChevronRight,
    Check, Plus, X, Eye, EyeOff, Lock, Globe, Tag, Loader2, ImagePlus
} from 'lucide-react'
import { StarRating } from './StarRating'
import { TeamLogo } from './TeamLogo'
import { NeutralModeToggle } from './NeutralModeToggle'
import { GiphyPicker } from './GiphyPicker'
import { SubRatings } from './SubRatings'
import { useMatchLogs, type CreateMatchLogData } from '@/hooks/useMatchLogs'
import { useAuth } from '@/contexts/AuthContext'
import { useToast } from '@/contexts/ToastContext'
import { supabase } from '@/lib/supabase'
import { isMatchTooOld } from '@/lib/helpers'
import type { Partido, MatchLogPlayerRating } from '@/types'

const MATCH_TYPES = [
    { value: 'tv', label: 'Lo vi por TV', icon: Tv, color: '#2563eb' },
    { value: 'stadium', label: 'En la cancha', icon: MapPin, color: '#16a34a' },
    { value: 'friend', label: 'Con amigos', icon: Users, color: '#d97706' },
    { value: 'other', label: 'Otro', icon: HelpCircle, color: '#7c3aed' },
] as const

const MOODS = [
    { value: 'euforia', emoji: '🤩', label: 'Euforia' },
    { value: 'contento', emoji: '😊', label: 'Contento' },
    { value: 'indiferente', emoji: '😐', label: 'Indiferente' },
    { value: 'caliente', emoji: '😤', label: 'Caliente' },
    { value: 'destruido', emoji: '😢', label: 'Destruido' },
    { value: 'locura', emoji: '🤯', label: 'Locura' },
] as const

const POPULAR_TAGS = [
    'clasico', 'remontada', 'penales', 'goleada', 'debut', 'despedida',
    'historico', 'final', 'derbi', 'copa', 'nocturno', 'lluvia'
]

const STEPS = [
    { title: 'Partido', desc: 'Seleccioná el partido' },
    { title: 'Tipo', desc: '¿Cómo lo viste?' },
    { title: 'Rating', desc: 'Puntuá el partido' },
    { title: 'Jugadores', desc: 'Puntuá jugadores' },
    { title: 'Reseña', desc: 'Tu opinión' },
]

interface PlayerRatingInput {
    name: string
    team: 'local' | 'visitante'
    rating: number
    comment: string
}

export function MatchLogForm({ preselectedMatch }: { preselectedMatch?: Partido }) {
    const router = useRouter()
    const { user } = useAuth()
    const { showToast } = useToast()
    const { createMatchLog } = useMatchLogs()

    const [step, setStep] = useState(0)
    const [submitting, setSubmitting] = useState(false)

    // Step 1 - Match selection
    const [searchQuery, setSearchQuery] = useState('')
    const [searchResults, setSearchResults] = useState<Partido[]>([])
    const [searching, setSearching] = useState(false)
    const [selectedMatch, setSelectedMatch] = useState<Partido | null>(preselectedMatch || null)
    const [manualMode, setManualMode] = useState(false)
    const [manualLocal, setManualLocal] = useState('')
    const [manualVisitante, setManualVisitante] = useState('')
    const [manualLiga, setManualLiga] = useState('')
    const [manualFecha, setManualFecha] = useState(new Date().toISOString().split('T')[0])
    const [manualGolesLocal, setManualGolesLocal] = useState<string>('')
    const [manualGolesVisitante, setManualGolesVisitante] = useState<string>('')

    // Step 2 - Type
    const [matchType, setMatchType] = useState<string>('tv')
    const [mood, setMood] = useState<string>('')

    // Step 3 - Ratings
    const [ratingPartido, setRatingPartido] = useState(0)
    const [ratingArbitro, setRatingArbitro] = useState(0)
    const [ratingAtmosfera, setRatingAtmosfera] = useState(0)
    const [ratingGarra, setRatingGarra] = useState(0)

    // Step 4 - Player ratings
    const [playerRatings, setPlayerRatings] = useState<PlayerRatingInput[]>([])
    const [newPlayerName, setNewPlayerName] = useState('')
    const [newPlayerTeam, setNewPlayerTeam] = useState<'local' | 'visitante'>('local')

    // Step 5 - Review
    const [reviewTitle, setReviewTitle] = useState('')
    const [reviewText, setReviewText] = useState('')
    const [isSpoiler, setIsSpoiler] = useState(false)
    const [isPrivate, setIsPrivate] = useState(false)
    const [selectedTags, setSelectedTags] = useState<string[]>([])
    const [showPreview, setShowPreview] = useState(false)
    const [isNeutral, setIsNeutral] = useState(false)

    // New: DT rating, estrella/villano, photo, giphy
    const [ratingDT, setRatingDT] = useState(0)
    const [jugadorEstrella, setJugadorEstrella] = useState('')
    const [jugadorVillano, setJugadorVillano] = useState('')
    const [fotoUrl, setFotoUrl] = useState('')
    const [showGiphy, setShowGiphy] = useState(false)
    const [uploadingPhoto, setUploadingPhoto] = useState(false)
    const fileInputRef = useRef<HTMLInputElement>(null)

    // Search matches from DB
    useEffect(() => {
        if (!searchQuery || searchQuery.length < 2) {
            setSearchResults([])
            return
        }

        const timeout = setTimeout(async () => {
            setSearching(true)
            try {
                const { data } = await supabase
                    .from('partidos')
                    .select('*')
                    .or(`equipo_local.ilike.%${searchQuery}%,equipo_visitante.ilike.%${searchQuery}%`)
                    .order('fecha_inicio', { ascending: false })
                    .limit(10)

                setSearchResults(data || [])
            } catch {
                setSearchResults([])
            } finally {
                setSearching(false)
            }
        }, 300)

        return () => clearTimeout(timeout)
    }, [searchQuery])

    const getMatchInfo = () => {
        if (selectedMatch) {
            return {
                partido_id: String(selectedMatch.id),
                equipo_local: selectedMatch.equipo_local,
                equipo_visitante: selectedMatch.equipo_visitante,
                logo_local: selectedMatch.logo_local,
                logo_visitante: selectedMatch.logo_visitante,
                liga: selectedMatch.liga,
                fecha_partido: selectedMatch.fecha_inicio,
                goles_local: selectedMatch.goles_local,
                goles_visitante: selectedMatch.goles_visitante,
            }
        }
        return {
            equipo_local: manualLocal,
            equipo_visitante: manualVisitante,
            liga: manualLiga || undefined,
            fecha_partido: new Date(manualFecha).toISOString(),
            goles_local: manualGolesLocal ? parseInt(manualGolesLocal) : undefined,
            goles_visitante: manualGolesVisitante ? parseInt(manualGolesVisitante) : undefined,
        }
    }

    const canGoNext = () => {
        switch (step) {
            case 0: return selectedMatch || (manualMode && manualLocal && manualVisitante)
            case 1: return !!matchType
            case 2: return ratingPartido > 0
            case 3: return true // optional
            case 4: return true // optional
            default: return false
        }
    }

    const addPlayerRating = () => {
        if (!newPlayerName.trim()) return
        setPlayerRatings(prev => [...prev, {
            name: newPlayerName.trim(),
            team: newPlayerTeam,
            rating: 0,
            comment: '',
        }])
        setNewPlayerName('')
    }

    const updatePlayerRating = (index: number, field: keyof PlayerRatingInput, value: string | number) => {
        setPlayerRatings(prev => prev.map((pr, i) =>
            i === index ? { ...pr, [field]: value } : pr
        ))
    }

    const removePlayerRating = (index: number) => {
        setPlayerRatings(prev => prev.filter((_, i) => i !== index))
    }

    const toggleTag = (tag: string) => {
        setSelectedTags(prev =>
            prev.includes(tag) ? prev.filter(t => t !== tag) : [...prev, tag]
        )
    }

    const handleSubmit = async () => {
        if (!user) {
            router.push('/login')
            return
        }

        if (ratingPartido === 0) {
            showToast('Ponele al menos una estrella al partido', 'error')
            return
        }

        const matchInfo = getMatchInfo()
        if (isMatchTooOld(matchInfo.fecha_partido)) {
            showToast('Este partido es muy antiguo para ser reseñado', 'error')
            return
        }

        // Check for existing log for this user/match
        if (matchInfo.partido_id) {
            const { data: existing } = await supabase
                .from('match_logs')
                .select('id')
                .eq('user_id', user.id)
                .eq('partido_id', String(matchInfo.partido_id))
                .maybeSingle()

            if (existing) {
                showToast('Ya reseñaste este partido', 'error')
                return
            }
        }

        setSubmitting(true)
        try {
            const matchInfo = getMatchInfo()
            const data: CreateMatchLogData = {
                ...matchInfo,
                match_type: matchType,
                rating_partido: ratingPartido,
                rating_arbitro: ratingArbitro || undefined,
                rating_atmosfera: ratingAtmosfera || undefined,
                rating_garra: ratingGarra || undefined,
                review_title: reviewTitle || undefined,
                review_text: reviewText || undefined,
                is_spoiler: isSpoiler,
                is_private: isPrivate,
                player_ratings: playerRatings
                    .filter(pr => pr.rating > 0)
                    .map(pr => ({
                        player_name: pr.name,
                        player_team: pr.team,
                        rating: pr.rating,
                        comment: pr.comment || undefined,
                    })),
                tags: selectedTags.length > 0 ? selectedTags : undefined,
                is_neutral: isNeutral || undefined,
                rating_dt: ratingDT || undefined,
                jugador_estrella: jugadorEstrella || undefined,
                jugador_villano: jugadorVillano || undefined,
                foto_url: fotoUrl || undefined,
                mood: mood || undefined,
            }

            await createMatchLog(data)
            showToast('¡Reseña publicada! ⚽', 'success')
            router.push('/feed')
        } catch {
            showToast('Error al publicar la reseña', 'error')
        } finally {
            setSubmitting(false)
        }
    }

    const handlePhotoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (!e.target.files || e.target.files.length === 0 || !user) return
        const file = e.target.files[0]

        setUploadingPhoto(true)
        try {
            const fileExt = file.name.split('.').pop()
            const fileName = `${user.id}-${Date.now()}.${fileExt}`
            const filePath = `matches/${fileName}`

            const { error: uploadError } = await supabase.storage
                .from('match_photos')
                .upload(filePath, file)

            if (uploadError) throw uploadError

            const { data } = supabase.storage.from('match_photos').getPublicUrl(filePath)
            setFotoUrl(data.publicUrl)
            showToast('✅ Foto subida con éxito', 'success')
        } catch (error) {
            console.error('Error uploading photo:', error)
            showToast('❌ Error al subir la foto', 'error')
        } finally {
            setUploadingPhoto(false)
            if (fileInputRef.current) fileInputRef.current.value = ''
        }
    }

    const matchInfo = getMatchInfo()
    const localName = matchInfo.equipo_local || 'Local'
    const visitanteName = matchInfo.equipo_visitante || 'Visitante'

    return (
        <div className="max-w-lg mx-auto">
            {/* Progress Bar */}
            <div className="flex items-center gap-1 mb-6">
                {STEPS.map((s, i) => (
                    <div key={i} className="flex-1 flex flex-col items-center gap-1">
                        <div className={`h-1.5 w-full transition-all duration-500 ${i <= step ? 'bg-[var(--foreground)]' : 'bg-[var(--card-border)]'
                            }`} style={{ borderRadius: 'var(--radius)' }} />
                        <span className={`text-[9px] font-black capitalize tracking-widest italic transition-colors ${i === step ? 'text-[var(--foreground)]' : 'text-[var(--text-muted)]'
                            }`}>
                            {s.title}
                        </span>
                    </div>
                ))}
            </div>

            {/* Step Content */}
            <AnimatePresence mode="wait">
                <motion.div
                    key={step}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.2 }}
                >
                    {/* Step 0: Select Match */}
                    {step === 0 && (
                        <div className="space-y-4">
                            <h2 className="text-lg font-bold">¿Qué partido viste?</h2>

                            {!manualMode ? (
                                <>
                                    <div className="relative">
                                        <input
                                            type="text"
                                            value={searchQuery}
                                            onChange={(e) => setSearchQuery(e.target.value)}
                                            placeholder="Buscar partido por equipo..."
                                            className="w-full px-4 py-3 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl
                               text-sm focus:outline-none focus:border-[#f59e0b]/50 transition-colors"
                                        />
                                        {searching && (
                                            <Loader2 size={16} className="absolute right-3 top-3.5 animate-spin text-[var(--text-muted)]" />
                                        )}
                                    </div>

                                    {/* Search Results */}
                                    {searchResults.length > 0 && (
                                        <div className="space-y-2 max-h-64 overflow-y-auto border-t border-[var(--card-border)] pt-2 border-dashed">
                                            {searchResults.map((p) => (
                                                <button
                                                    key={p.id}
                                                    type="button"
                                                    onClick={() => { setSelectedMatch(p); setSearchQuery(''); setSearchResults([]) }}
                                                    className={`w-full flex items-center gap-3 p-3 border transition-all text-left ${selectedMatch?.id === p.id
                                                        ? 'border-[var(--foreground)] bg-[var(--foreground)]/5'
                                                        : 'border-[var(--card-border)] bg-[var(--card-bg)] hover:border-[var(--text-muted)]'
                                                        }`}
                                                    style={{ borderRadius: 'var(--radius)' }}
                                                >
                                                    <TeamLogo src={p.logo_local} teamName={p.equipo_local} size={28} />
                                                    <div className="flex-1 min-w-0">
                                                        <div className="text-sm font-black capitalize italic tracking-tight truncate">
                                                            {p.equipo_local} vs {p.equipo_visitante}
                                                        </div>
                                                        <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-widest">
                                                            {p.liga} · {new Date(p.fecha_inicio).toLocaleDateString('es-AR')}
                                                            {p.goles_local != null && ` · ${p.goles_local}-${p.goles_visitante}`}
                                                        </div>
                                                    </div>
                                                    <TeamLogo src={p.logo_visitante} teamName={p.equipo_visitante} size={28} />
                                                </button>
                                            ))}
                                        </div>
                                    )}

                                    {/* Selected Match Display */}
                                    {selectedMatch && !searchQuery && (
                                        <div className="flex items-center gap-3 p-4 rounded-xl border border-[#f59e0b]/30 bg-[#f59e0b]/5">
                                            <TeamLogo src={selectedMatch.logo_local} teamName={selectedMatch.equipo_local} size={36} />
                                            <div className="flex-1 text-center">
                                                <div className="text-sm font-bold">{selectedMatch.equipo_local}</div>
                                                {selectedMatch.goles_local != null && (
                                                    <div className="text-lg font-bold text-[#f59e0b]">
                                                        {selectedMatch.goles_local} - {selectedMatch.goles_visitante}
                                                    </div>
                                                )}
                                                <div className="text-sm font-bold">{selectedMatch.equipo_visitante}</div>
                                                <div className="text-xs text-[var(--text-muted)] mt-1">{selectedMatch.liga}</div>
                                            </div>
                                            <TeamLogo src={selectedMatch.logo_visitante} teamName={selectedMatch.equipo_visitante} size={36} />
                                            <button type="button" onClick={() => setSelectedMatch(null)} className="p-1 hover:bg-[var(--hover-bg)] rounded-lg">
                                                <X size={16} />
                                            </button>
                                        </div>
                                    )}

                                    <button
                                        type="button"
                                        onClick={() => setManualMode(true)}
                                        className="w-full py-2.5 text-sm text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                                    >
                                        ¿No lo encontrás? <span className="underline">Cargarlo manualmente</span>
                                    </button>
                                </>
                            ) : (
                                <div className="space-y-3">
                                    <div className="grid grid-cols-2 gap-3">
                                        <input
                                            type="text"
                                            value={manualLocal}
                                            onChange={(e) => setManualLocal(e.target.value)}
                                            placeholder="Equipo local"
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                        <input
                                            type="text"
                                            value={manualVisitante}
                                            onChange={(e) => setManualVisitante(e.target.value)}
                                            placeholder="Equipo visitante"
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                    </div>
                                    <div className="grid grid-cols-2 gap-3">
                                        <input
                                            type="text"
                                            value={manualLiga}
                                            onChange={(e) => setManualLiga(e.target.value)}
                                            placeholder="Liga/Torneo (opcional)"
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                        <input
                                            type="date"
                                            value={manualFecha}
                                            onChange={(e) => setManualFecha(e.target.value)}
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                    </div>
                                    <div className="grid grid-cols-2 gap-3">
                                        <input
                                            type="number"
                                            value={manualGolesLocal}
                                            onChange={(e) => setManualGolesLocal(e.target.value)}
                                            placeholder="Goles local"
                                            min="0"
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                        <input
                                            type="number"
                                            value={manualGolesVisitante}
                                            onChange={(e) => setManualGolesVisitante(e.target.value)}
                                            placeholder="Goles visitante"
                                            min="0"
                                            className="px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                               focus:outline-none focus:border-[#f59e0b]/50"
                                        />
                                    </div>
                                    <button
                                        type="button"
                                        onClick={() => { setManualMode(false); setSelectedMatch(null) }}
                                        className="text-sm text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                                    >
                                        ← Volver a buscar
                                    </button>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Step 1: Match Type */}
                    {step === 1 && (
                        <div className="space-y-4">
                            <h2 className="text-lg font-bold">¿Cómo lo viste?</h2>
                            <div className="grid grid-cols-2 gap-3">
                                {MATCH_TYPES.map((type) => {
                                    const Icon = type.icon || MapPin
                                    const itemColor = type.color || '#16a34a'
                                    return (
                                        <button
                                            key={type.value}
                                            type="button"
                                            onClick={() => setMatchType(type.value)}
                                            className={`flex flex-col items-center gap-2 p-4 border-2 transition-all ${matchType === type.value
                                                ? 'border-[var(--foreground)] bg-[var(--foreground)] text-[var(--background)] scale-[1.02]'
                                                : 'border-[var(--card-border)] bg-[var(--card-bg)] hover:border-[var(--text-muted)]'
                                                }`}
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            <div className="w-12 h-12 flex items-center justify-center"
                                                style={{ backgroundColor: matchType === type.value ? 'var(--background)' : `${itemColor}15`, borderRadius: 'var(--radius)' }}>
                                                <Icon size={24} style={{ color: matchType === type.value ? 'var(--foreground)' : itemColor }} />
                                            </div>
                                            <span className="text-[11px] font-black capitalize tracking-widest">{type.label}</span>
                                        </button>
                                    )
                                })}
                            </div>

                            {/* Mood Selector */}
                            <div className="mt-6">
                                <h3 className="text-sm font-bold mb-3">¿Cómo te sentiste después?</h3>
                                <div className="grid grid-cols-3 gap-2">
                                    {MOODS.map(m => (
                                        <button
                                            key={m.value}
                                            type="button"
                                            onClick={() => setMood(mood === m.value ? '' : m.value)}
                                            className={`flex flex-col items-center gap-1 p-3 border-2 transition-all ${mood === m.value
                                                ? 'border-[var(--foreground)] bg-[var(--foreground)] text-[var(--background)] scale-[1.02]'
                                                : 'border-[var(--card-border)] bg-[var(--card-bg)] hover:border-[var(--text-muted)]'
                                            }`}
                                            style={{ borderRadius: 'var(--radius)' }}
                                        >
                                            <span className="text-2xl">{m.emoji}</span>
                                            <span className="text-[10px] font-black capitalize tracking-widest">{m.label}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Step 2: Ratings */}
                    {step === 2 && (
                        <div className="space-y-6">
                            <h2 className="text-lg font-bold">¿Qué te pareció?</h2>

                            {/* Main rating */}
                            <div className="p-5 bg-[var(--card-bg)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                                <div className="text-[10px] font-black capitalize tracking-widest text-[var(--text-muted)] mb-3 italic">Rating del partido</div>
                                <div className="flex justify-center">
                                    <StarRating
                                        value={ratingPartido}
                                        onChange={setRatingPartido}
                                        size="lg"
                                        showValue
                                    />
                                </div>
                            </div>

                            {/* Secondary ratings */}
                            <div className="space-y-4">
                                <SubRatings
                                    ratings={{ arbitro: ratingArbitro, atmosfera: ratingAtmosfera, garra: ratingGarra }}
                                    onChange={(field, val) => {
                                        if (field === 'arbitro') setRatingArbitro(val)
                                        if (field === 'atmosfera') setRatingAtmosfera(val)
                                        if (field === 'garra') setRatingGarra(val)
                                    }}
                                />
                                <div className="p-4 bg-[var(--card-bg)] border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                                    <StarRating
                                        value={ratingDT}
                                        onChange={setRatingDT}
                                        label="Director Técnico"
                                        showValue
                                        color="var(--foreground)"
                                    />
                                </div>
                            </div>

                            {/* Neutral Mode Toggle */}
                            <NeutralModeToggle enabled={isNeutral} onChange={setIsNeutral} />
                        </div>
                    )}

                    {/* Step 3: Player Ratings */}
                    {step === 3 && (
                        <div className="space-y-4">
                            <h2 className="text-lg font-bold">Rating de jugadores</h2>
                            <p className="text-sm text-[var(--text-muted)]">Opcional — agregá jugadores que se destacaron.</p>

                            {/* Add player */}
                            <div className="flex gap-2">
                                <input
                                    type="text"
                                    value={newPlayerName}
                                    onChange={(e) => setNewPlayerName(e.target.value)}
                                    placeholder="Nombre del jugador"
                                    className="flex-1 px-3 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                           focus:outline-none focus:border-[#f59e0b]/50"
                                    onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addPlayerRating())}
                                />
                                <select
                                    value={newPlayerTeam}
                                    onChange={(e) => setNewPlayerTeam(e.target.value as 'local' | 'visitante')}
                                    className="px-2 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-xs
                           focus:outline-none"
                                >
                                    <option value="local">{localName.slice(0, 12)}</option>
                                    <option value="visitante">{visitanteName.slice(0, 12)}</option>
                                </select>
                                <button
                                    type="button"
                                    onClick={addPlayerRating}
                                    disabled={!newPlayerName.trim()}
                                    className="px-4 bg-[var(--foreground)] text-[var(--background)] hover:opacity-90 disabled:opacity-30 transition-all font-black"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    <Plus size={18} />
                                </button>
                            </div>

                            {/* Player list */}
                            <div className="space-y-2 max-h-64 overflow-y-auto">
                                {playerRatings.map((pr, i) => (
                                    <motion.div
                                        key={i}
                                        initial={{ opacity: 0, y: -10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        className="flex items-center gap-3 p-3 rounded-xl bg-[var(--card-bg)] border border-[var(--card-border)]"
                                    >
                                        <div className="flex-1 min-w-0">
                                            <div className="text-sm font-medium truncate">{pr.name}</div>
                                            <div className="text-[10px] text-[var(--text-muted)]">
                                                {pr.team === 'local' ? localName : visitanteName}
                                            </div>
                                        </div>
                                        <StarRating
                                            value={pr.rating}
                                            onChange={(v) => updatePlayerRating(i, 'rating', v)}
                                            size="sm"
                                        />
                                        <button type="button" onClick={() => removePlayerRating(i)}
                                            className="p-1 text-[var(--text-muted)] hover:text-red-500 transition-colors">
                                            <X size={14} />
                                        </button>
                                    </motion.div>
                                ))}
                                {playerRatings.length === 0 && (
                                    <div className="text-center py-8 text-[var(--text-muted)] text-sm">
                                        <Users size={24} className="mx-auto mb-2 opacity-40" />
                                        Podés saltear este paso
                                    </div>
                                )}

                                {/* Estrella y Villano */}
                                <div className="mt-4 pt-4 border-t border-[var(--card-border)] space-y-3">
                                    <h3 className="text-sm font-bold flex items-center gap-1.5">⭐ Estrella y 😈 Villano</h3>
                                    <div className="grid grid-cols-2 gap-3">
                                        <div>
                                            <label className="text-[10px] text-[var(--text-muted)] font-medium mb-1 block">⭐ Estrella del partido</label>
                                            <input
                                                type="text"
                                                value={jugadorEstrella}
                                                onChange={(e) => setJugadorEstrella(e.target.value)}
                                                placeholder="Ej: Messi"
                                                className="w-full px-3 py-2 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                                               focus:outline-none focus:border-[#f59e0b]/50"
                                            />
                                        </div>
                                        <div>
                                            <label className="text-[10px] text-[var(--text-muted)] font-medium mb-1 block">😈 Villano del partido</label>
                                            <input
                                                type="text"
                                                value={jugadorVillano}
                                                onChange={(e) => setJugadorVillano(e.target.value)}
                                                placeholder="Ej: El Árbitro"
                                                className="w-full px-3 py-2 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                                               focus:outline-none focus:border-[#f59e0b]/50"
                                            />
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Step 4: Review */}
                    {step === 4 && (
                        <div className="space-y-4">
                            <h2 className="text-lg font-bold">Tu reseña</h2>

                            <input
                                type="text"
                                value={reviewTitle}
                                onChange={(e) => setReviewTitle(e.target.value)}
                                placeholder="Título (opcional)"
                                className="w-full px-4 py-3 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm font-medium
                         focus:outline-none focus:border-[#f59e0b]/50"
                            />

                            <div className="relative">
                                <textarea
                                    value={reviewText}
                                    onChange={(e) => setReviewText(e.target.value)}
                                    placeholder="¿Qué te pareció el partido? Contá lo que quieras..."
                                    rows={6}
                                    className="w-full px-4 py-3 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                           focus:outline-none focus:border-[#f59e0b]/50 resize-none"
                                />
                                <div className="absolute bottom-3 right-3 text-[10px] text-[var(--text-muted)]">
                                    {reviewText.length} caracteres
                                </div>
                            </div>

                            {/* Preview toggle */}
                            {reviewText && (
                                <button
                                    type="button"
                                    onClick={() => setShowPreview(!showPreview)}
                                    className="flex items-center gap-1.5 text-xs text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                                >
                                    {showPreview ? <EyeOff size={12} /> : <Eye size={12} />}
                                    {showPreview ? 'Ocultar preview' : 'Ver preview'}
                                </button>
                            )}
                            {showPreview && reviewText && (
                                <div className="p-4 rounded-xl bg-[var(--card-bg)] border border-[var(--card-border)] text-sm whitespace-pre-wrap">
                                    {reviewTitle && <h3 className="font-bold mb-2">{reviewTitle}</h3>}
                                    {reviewText}
                                </div>
                            )}

                            {/* Tags */}
                            <div>
                                <div className="flex items-center gap-1.5 mb-2">
                                    <Tag size={12} className="text-[var(--text-muted)]" />
                                    <span className="text-xs font-medium text-[var(--text-muted)]">Tags</span>
                                </div>
                                <div className="flex flex-wrap gap-1.5">
                                    {POPULAR_TAGS.map(tag => (
                                        <button
                                            key={tag}
                                            type="button"
                                            onClick={() => toggleTag(tag)}
                                            className={`px-2.5 py-1 rounded-full text-xs font-medium transition-all ${selectedTags.includes(tag)
                                                ? 'bg-[#f59e0b]/15 text-[#f59e0b] border border-[#f59e0b]/30'
                                                : 'bg-[var(--card-bg)] text-[var(--text-muted)] border border-[var(--card-border)] hover:border-[var(--text-muted)]'
                                                }`}
                                        >
                                            #{tag}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Photo URL & Giphy */}
                            <div>
                                <div className="flex items-center justify-between mb-2">
                                    <label className="flex items-center gap-1.5 text-xs font-medium text-[var(--text-muted)]">
                                        📸 Foto o Meme (opcional)
                                    </label>
                                    <button
                                        type="button"
                                        onClick={() => setShowGiphy(!showGiphy)}
                                        className="text-[10px] bg-indigo-500/10 text-indigo-400 px-2 py-1 rounded-md flex items-center gap-1 hover:bg-indigo-500/20 transition-colors font-medium border border-indigo-500/20"
                                    >
                                        <ImagePlus size={12} />
                                        Buscar un GIF
                                    </button>
                                </div>

                                {showGiphy && (
                                    <div className="mb-3">
                                        <GiphyPicker
                                            onClose={() => setShowGiphy(false)}
                                            onSelect={(url) => { setFotoUrl(url); setShowGiphy(false); }}
                                        />
                                    </div>
                                )}

                                {!showGiphy && (
                                    <div className="space-y-2">
                                        <div className="flex gap-2">
                                            <input
                                                type="url"
                                                value={fotoUrl}
                                                onChange={(e) => setFotoUrl(e.target.value)}
                                                placeholder="Pegar link de imagen, url de GIF..."
                                                className="flex-1 px-4 py-2.5 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-sm
                                                focus:outline-none focus:border-[#f59e0b]/50 placeholder:text-[var(--text-muted)]"
                                            />
                                            <button
                                                type="button"
                                                onClick={() => fileInputRef.current?.click()}
                                                disabled={uploadingPhoto}
                                                className="px-4 py-2 bg-[var(--foreground)] text-[var(--background)] hover:opacity-90 transition-colors disabled:opacity-50 flex items-center justify-center shrink-0 font-black"
                                                style={{ borderRadius: 'var(--radius)' }}
                                            >
                                                {uploadingPhoto ? <Loader2 size={16} className="animate-spin" /> : <ImagePlus size={18} />}
                                            </button>
                                            <input
                                                type="file"
                                                ref={fileInputRef}
                                                onChange={handlePhotoUpload}
                                                accept="image/*"
                                                className="hidden"
                                            />
                                        </div>
                                    </div>
                                )}

                                {fotoUrl && !showGiphy && (
                                    <div className="mt-2 rounded-xl overflow-hidden border border-[var(--card-border)] max-h-40 relative group">
                                        <img src={fotoUrl} alt="Preview" className="w-full h-full object-cover"
                                            onError={(e) => (e.currentTarget.style.display = 'none')}
                                        />
                                        <button
                                            type="button"
                                            onClick={() => setFotoUrl('')}
                                            className="absolute top-2 right-2 p-1.5 bg-black/50 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-opacity"
                                        >
                                            <X size={14} />
                                        </button>
                                    </div>
                                )}
                            </div>

                            {/* Privacy & Spoiler toggles */}
                            <div className="flex gap-3">
                                <button
                                    type="button"
                                    onClick={() => setIsPrivate(!isPrivate)}
                                    className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-xs font-medium transition-all ${isPrivate
                                        ? 'border-amber-500/30 bg-amber-500/5 text-amber-500'
                                        : 'border-[var(--card-border)] text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                        }`}
                                >
                                    {isPrivate ? <Lock size={14} /> : <Globe size={14} />}
                                    {isPrivate ? 'Privado' : 'Público'}
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setIsSpoiler(!isSpoiler)}
                                    className={`flex items-center gap-2 px-3 py-2 rounded-xl border text-xs font-medium transition-all ${isSpoiler
                                        ? 'border-red-500/30 bg-red-500/5 text-red-500'
                                        : 'border-[var(--card-border)] text-[var(--text-muted)] hover:text-[var(--foreground)]'
                                        }`}
                                >
                                    {isSpoiler ? <EyeOff size={14} /> : <Eye size={14} />}
                                    {isSpoiler ? 'Spoiler' : 'Sin spoiler'}
                                </button>
                            </div>
                        </div>
                    )}
                </motion.div>
            </AnimatePresence>

            {/* Navigation Buttons */}
            <div className="flex gap-3 mt-8">
                {step > 0 && (
                    <button
                        type="button"
                        onClick={() => setStep(step - 1)}
                        className="flex items-center gap-1 px-4 py-2.5 rounded-xl border border-[var(--card-border)]
                     text-sm font-medium hover:bg-[var(--hover-bg)] transition-colors"
                    >
                        <ChevronLeft size={16} />
                        Atrás
                    </button>
                )}
                <div className="flex-1" />
                {step < STEPS.length - 1 ? (
                    <button
                        type="button"
                        onClick={() => setStep(step + 1)}
                        disabled={!canGoNext()}
                        className="flex items-center gap-1 px-5 py-2.5 rounded-xl bg-[#f59e0b] text-white
                     text-sm font-semibold hover:bg-[#d97706] disabled:opacity-30 transition-all"
                    >
                        Siguiente
                        <ChevronRight size={16} />
                    </button>
                ) : (
                    <button
                        type="button"
                        onClick={handleSubmit}
                        disabled={submitting || ratingPartido === 0}
                        className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-[#f59e0b] text-white
                     text-sm font-semibold hover:bg-[#d97706] disabled:opacity-30 transition-all"
                    >
                        {submitting ? (
                            <><Loader2 size={16} className="animate-spin" /> Publicando...</>
                        ) : (
                            <><Check size={16} /> Publicar</>
                        )}
                    </button>
                )}
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { ExternalLink, Flame, Newspaper } from 'lucide-react'
import { GlassCard } from './ui/GlassCard'

interface NewsItem {
    title: string
    link: string
    pubDate: string
    thumbnail: string
    source: string
}

interface NewsFeedProps {
    userTeams: string[]
}

export function NewsFeed({ userTeams }: NewsFeedProps) {
    const [news, setNews] = useState<NewsItem[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState(false)

    useEffect(() => {
        const fetchNews = async () => {
            setLoading(true)
            setError(false)
            try {
                // Proxy CORS free para tycsports
                const res = await fetch('https://api.rss2json.com/v1/api.json?rss_url=https://www.tycsports.com/rss/futbol.xml')
                const data = await res.json()

                if (data.status === 'ok') {
                    // Filter by user teams if available, otherwise just show top news
                    let filtered = data.items

                    if (userTeams.length > 0) {
                        filtered = data.items.filter((item: any) =>
                            userTeams.some(team =>
                                item.title.toLowerCase().includes(team.toLowerCase()) ||
                                item.description.toLowerCase().includes(team.toLowerCase())
                            )
                        )
                        // If strict filter yields nothing, fallback to general news
                        if (filtered.length === 0) {
                            filtered = data.items
                        }
                    }

                    const mappedNews: NewsItem[] = filtered.map((item: any) => ({
                        title: item.title,
                        link: item.link,
                        pubDate: new Date(item.pubDate).toLocaleDateString('es-AR', { day: '2-digit', month: 'short' }),
                        thumbnail: item.enclosure?.link || item.thumbnail || '',
                        source: 'TyC Sports'
                    })).slice(0, 15)

                    setNews(mappedNews)
                } else {
                    throw new Error('API RSS Error')
                }
            } catch (err) {
                console.error("Error fetching news:", err)
                setError(true)
            } finally {
                setLoading(false)
            }
        }

        fetchNews()
    }, [userTeams])

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-5 mb-6" style={{ borderRadius: 'var(--radius)' }}>
                <div className="flex items-center gap-2 mb-4">
                    <Newspaper size={18} className="text-[var(--text-muted)]" />
                    <h2 className="text-sm font-black capitalize tracking-widest italic">Últimas Noticias</h2>
                </div>
                <div className="flex gap-4 overflow-x-auto snap-x snap-mandatory pb-4 hide-scrollbar">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="min-w-[260px] md:min-w-[300px] h-[120px] bg-[var(--background)] border border-[var(--card-border)] animate-pulse shrink-0 snap-start" style={{ borderRadius: 'var(--radius)' }} />
                    ))}
                </div>
            </div>
        )
    }

    // Don't show if broken
    if (error || news.length === 0) {
        return null 
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] mb-6 p-5" style={{ borderRadius: 'var(--radius)' }}>
            <div className="flex items-center gap-2 mb-4 border-b border-[var(--card-border)] pb-2 border-dashed">
                <Flame size={18} className="text-[#ff4d4d]" />
                <h2 className="text-sm font-black capitalize tracking-widest italic">
                    {userTeams.length > 0 ? 'Noticias para vos' : 'Últimas Noticias'}
                </h2>
            </div>

            <div className="flex gap-4 overflow-x-auto snap-x snap-mandatory pb-4 hide-scrollbar">
                {news.map((item, idx) => (
                    <motion.a
                        key={idx}
                        href={item.link}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="group relative min-w-[280px] md:min-w-[320px] h-[140px] overflow-hidden shrink-0 snap-center border border-[var(--card-border)]"
                        style={{ borderRadius: 'var(--radius)' }}
                        whileHover={{ y: -2 }}
                        whileTap={{ scale: 0.98 }}
                    >
                        {item.thumbnail ? (
                            <img src={item.thumbnail} alt={item.title} className="absolute inset-0 w-full h-full object-cover opacity-60 group-hover:opacity-40 transition-opacity" />
                        ) : (
                            <div className="absolute inset-0 bg-[var(--background)]" />
                        )}
                        <div className="absolute inset-0 bg-[var(--background)]/80" />

                        <div className="absolute inset-x-0 bottom-0 p-4">
                            <div className="flex justify-between items-start gap-2 mb-2">
                                <span className="text-[8px] font-black text-[var(--background)] bg-[var(--foreground)] capitalize tracking-widest px-2 py-0.5">
                                    {item.source}
                                </span>
                                <span className="text-[8px] text-[var(--text-muted)] font-black capitalize">
                                    {item.pubDate}
                                </span>
                            </div>
                            <h3 className="text-xs font-bold text-[var(--foreground)] leading-tight line-clamp-2 capitalize">
                                {item.title}
                            </h3>
                        </div>
                    </motion.a>
                ))}

                <div className="min-w-[150px] flex items-center justify-center shrink-0 snap-center">
                    <a href="https://www.tycsports.com/futbol.html" target="_blank" rel="noopener noreferrer" className="flex flex-col items-center gap-2 text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors">
                        <div className="w-10 h-10 border border-dashed border-[var(--card-border)] flex items-center justify-center bg-[var(--background)] hover:bg-[var(--hover-bg)]" style={{ borderRadius: 'var(--radius)' }}>
                            <ExternalLink size={16} />
                        </div>
                        <span className="text-[10px] font-black capitalize">Ver más</span>
                    </a>
                </div>
            </div>
        </div>
    )
}

'use client'

import { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { ExternalLink, Flame, Newspaper, Search, Filter } from 'lucide-react'
import { useAuth } from '@/contexts/AuthContext'
import { useLanguage } from '@/contexts/LanguageContext'
import { fetchTyCNewsAction } from '@/app/actions/news'

interface NewsItem {
    title: string
    link: string
    pubDate: string
    thumbnail: string
    source: string
    description: string
}

export function NewsTab() {
    const { user } = useAuth()
    const { t } = useLanguage()

    // Asumimos que los equipos favoritos del usuario están en su metadata
    const userTeams = user?.user_metadata?.favorite_teams || []

    const [news, setNews] = useState<NewsItem[]>([])
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState(false)
    const [errorMessage, setErrorMessage] = useState('')
    const [filterQuery, setFilterQuery] = useState('')
    const [activeFilter, setActiveFilter] = useState<'all' | 'my_teams'>('all')

    useEffect(() => {
        const fetchNews = async () => {
            setLoading(true)
            setError(false)
            setErrorMessage('')
            try {
                const data = await fetchTyCNewsAction()
                if (data && data.length > 0) {
                    const mappedNews: NewsItem[] = data.map((item: any) => ({
                        title: item.title,
                        link: item.link,
                        description: item.description,
                        pubDate: new Date(item.pubDate || new Date()).toLocaleDateString('es-AR', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' }),
                        thumbnail: item.thumbnail,
                        source: 'TyC Sports'
                    }))
                    setNews(mappedNews)
                } else {
                    throw new Error('La fuente de noticias no devolvió artículos válidos.')
                }
            } catch (err: any) {
                console.error("Error fetching news:", err)
                setError(true)
                setErrorMessage(err.message || 'Error de conexión')
            } finally {
                setLoading(false)
            }
        }

        fetchNews()
    }, [])

    const filteredNews = news.filter((item) => {
        // 1. Filtrar por búsqueda manual
        const matchesQuery = item.title.toLowerCase().includes(filterQuery.toLowerCase()) || 
                             item.description.toLowerCase().includes(filterQuery.toLowerCase())

        // 2. Filtrar por equipos favoritos si el toggle está activo
        let matchesTeams = true
        if (activeFilter === 'my_teams' && userTeams.length > 0) {
            matchesTeams = userTeams.some((team: string) => 
                item.title.toLowerCase().includes(team.toLowerCase()) || 
                item.description.toLowerCase().includes(team.toLowerCase())
            )
        }

        return matchesQuery && matchesTeams
    })

    return (
        <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header / Search Controls */}
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-4 rounded-xl shadow-sm flex flex-col md:flex-row gap-3 items-center justify-between">
                <div className="relative w-full md:max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" size={16} />
                    <input 
                        type="text" 
                        placeholder="Buscar noticias, equipos, jugadores..."
                        value={filterQuery}
                        onChange={(e) => setFilterQuery(e.target.value)}
                        className="w-full bg-[var(--background)] border border-[var(--card-border)] rounded-lg pl-10 pr-4 py-2 text-xs font-bold text-[var(--foreground)] placeholder:text-[var(--text-muted)] focus:outline-none focus:border-[var(--accent)]"
                    />
                </div>

                {userTeams.length > 0 && (
                    <div className="flex bg-[var(--background)] p-1 rounded-lg border border-[var(--card-border)] w-full md:w-auto">
                        <button 
                            onClick={() => setActiveFilter('all')}
                            className={`flex-1 md:px-4 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-md transition-all ${activeFilter === 'all' ? 'bg-[var(--foreground)] text-[var(--background)] shadow-sm' : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'}`}
                        >
                            Todo
                        </button>
                        <button 
                            onClick={() => setActiveFilter('my_teams')}
                            className={`flex-1 md:px-4 py-1.5 text-[10px] font-black uppercase tracking-widest rounded-md transition-all flex items-center justify-center gap-1.5 ${activeFilter === 'my_teams' ? 'bg-[var(--accent-green)] text-white shadow-sm' : 'text-[var(--text-muted)] hover:text-[var(--foreground)]'}`}
                        >
                            <Flame size={12} /> Mi Equipo
                        </button>
                    </div>
                )}
            </div>

            {/* Content Feed */}
            {loading ? (
                <div className="space-y-4">
                    {[1, 2, 3, 4].map(i => (
                        <div key={i} className="h-32 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-xl animate-pulse" />
                    ))}
                </div>
            ) : error ? (
                <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className="text-center py-12 bg-[var(--card-bg)] border border-red-500/20 rounded-xl">
                    <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Newspaper size={32} className="text-red-500/70" />
                    </div>
                    <p className="text-sm font-black text-[var(--foreground)] uppercase tracking-widest leading-tight mb-2">No pudimos cargar las noticias</p>
                    <p className="text-xs text-[var(--text-muted)] font-medium max-w-xs mx-auto mb-6">{errorMessage || 'Parece que el servidor de origen (TyC Sports) no está respondiendo. Intentá de nuevo en un rato.'}</p>
                    <button onClick={() => window.location.reload()} className="px-6 py-2.5 bg-[var(--background)] border border-[var(--card-border)] text-[10px] font-black tracking-widest uppercase rounded-full hover:bg-[var(--foreground)] hover:text-[var(--background)] transition-colors shadow-sm">
                        Reintentar Conexión
                    </button>
                </motion.div>
            ) : filteredNews.length === 0 ? (
                <div className="text-center py-12 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-xl border-dashed">
                    <Filter size={48} className="mx-auto text-[var(--text-muted)] mb-3 opacity-50" />
                    <p className="text-xs font-bold text-[var(--text-muted)] uppercase tracking-widest">No hay noticias para ese filtro</p>
                    <button onClick={() => {setFilterQuery(''); setActiveFilter('all')}} className="mt-4 text-[10px] font-black text-[var(--accent)] hover:underline">Limpiar Filtros</button>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {filteredNews.map((item, idx) => (
                        <motion.a
                            key={idx}
                            href={item.link}
                            target="_blank"
                            rel="noopener noreferrer"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: idx * 0.05 }}
                            className="group flex flex-col bg-[var(--card-bg)] border border-[var(--card-border)] rounded-xl overflow-hidden hover:border-[var(--accent)] hover:shadow-lg transition-all"
                        >
                            {/* Img Header */}
                            <div className="relative h-48 w-full bg-[var(--background)] overflow-hidden">
                                {item.thumbnail ? (
                                    <img 
                                        src={item.thumbnail} 
                                        alt={item.title} 
                                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" 
                                    />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center opacity-10">
                                        <Newspaper size={48} />
                                    </div>
                                )}
                                <div className="absolute top-3 left-3 px-2 py-1 bg-[var(--foreground)] text-[var(--background)] text-[9px] font-black uppercase tracking-widest rounded shadow-sm">
                                    {item.source}
                                </div>
                            </div>

                            {/* Body */}
                            <div className="p-4 flex flex-col flex-1">
                                <h3 className="text-sm font-black text-[var(--foreground)] leading-snug mb-2 line-clamp-2 capitalize">
                                    {item.title}
                                </h3>
                                <p className="text-xs font-medium text-[var(--text-muted)] line-clamp-2 mb-4 flex-1">
                                    {item.description}
                                </p>

                                <div className="flex items-center justify-between border-t border-[var(--card-border)] pt-3 mt-auto">
                                    <span className="text-[10px] font-bold text-[var(--text-muted)] tracking-tight">
                                        {item.pubDate}
                                    </span>
                                    <span className="text-[10px] font-black text-[var(--accent)] flex items-center gap-1 group-hover:translate-x-1 transition-transform">
                                        Leer más <ExternalLink size={12} />
                                    </span>
                                </div>
                            </div>
                        </motion.a>
                    ))}
                </div>
            )}
        </div>
    )
}

// src/components/NotificationSettings.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { useAuth } from '@/contexts/AuthContext'
import { usePushNotifications } from '@/hooks/usePushNotifications'
import { supabase } from '@/lib/supabase'

interface NotificationPrefs {
    partidoInicio: boolean
    golFavorito: boolean
    resultadoProde: boolean
    nuevosSeguidores: boolean
    insignias: boolean
}

export function NotificationSettings() {
    const { user } = useAuth()
    const [prefs, setPrefs] = useState<NotificationPrefs>({
        partidoInicio: true,
        golFavorito: true,
        resultadoProde: true,
        nuevosSeguidores: true,
        insignias: true
    })
    const { isSupported, isOptedIn, subscribeToPush, loading } = usePushNotifications()
    const [permissionState, setPermissionState] = useState<NotificationPermission>('default')

    useEffect(() => {
        if (typeof window !== 'undefined' && 'Notification' in window) {
            setPermissionState(Notification.permission)
        }
    }, [])

    useEffect(() => {
        if (user) loadPrefs()
    }, [user])

    const loadPrefs = async () => {
        if (!user) return
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('notification_prefs')
                .eq('id', user.id)
                .single()

            if (data?.notification_prefs) {
                setPrefs({ ...prefs, ...data.notification_prefs })
            }
        } catch (err: any) {
            console.error('Error loading prefs:', err)
        }
    }

    const savePrefs = async (newPrefs: NotificationPrefs) => {
        setPrefs(newPrefs)
        if (!user) return

        const { error } = await supabase
            .from('profiles')
            .update({ notification_prefs: newPrefs })
            .eq('id', user.id)

        if (error) console.error('Error saving prefs:', error)
    }

    const togglePref = async (key: keyof NotificationPrefs) => {
        const newPrefs = { ...prefs, [key]: !prefs[key] }
        await savePrefs(newPrefs)
    }

    const handleSubscribe = async () => {
        await subscribeToPush()
        setPermissionState(Notification.permission)
    }

    if (!isSupported) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-6 mt-4" style={{ borderRadius: 'var(--radius)' }}>
                <div className="text-center">
                    <span className="text-3xl mb-4 block">🔕</span>
                    <h3 className="text-[10px] font-black capitalize tracking-widest mb-2 text-[var(--foreground)]">Notificaciones no soportadas</h3>
                    <p className="text-[9px] font-bold text-[var(--text-muted)] capitalize">
                        Tu navegador o dispositivo no las soporta.
                    </p>
                </div>
            </div>
        )
    }

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] mt-4 overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
            {/* Header */}
            <div className="px-5 py-3 bg-[var(--background)] border-b border-[var(--card-border)] border-dashed">
                <h3 className="text-[10px] font-black capitalize tracking-widest flex items-center gap-2 text-[var(--foreground)]">
                    <span>🔔</span> Notificaciones
                </h3>
            </div>

            <div className="p-5 space-y-4">
                {/* Estado del permiso */}
                {permissionState === 'denied' ? (
                    <div className="bg-red-500/5 border border-red-500/20 p-4 text-center" style={{ borderRadius: 'var(--radius)' }}>
                        <p className="text-[10px] mb-2 text-red-600 font-black capitalize">
                            🚫 Notificaciones bloqueadas
                        </p>
                        <p className="text-[9px] text-[var(--text-muted)] font-bold capitalize">
                            Habilitalas en la configuración de tu navegador.
                        </p>
                    </div>
                ) : !isOptedIn ? (
                    <div className="bg-[var(--background)] border border-[var(--card-border)] p-5 text-center relative overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                        <p className="text-[10px] mb-3 font-black text-[var(--foreground)] capitalize relative z-10">
                            Activá alertas para no perderte nada 🏆
                        </p>
                        <button
                            onClick={handleSubscribe}
                            disabled={loading}
                            className="bg-[var(--foreground)] text-[var(--background)] px-5 py-2 font-black text-[10px] capitalize tracking-widest
                                        hover:bg-[var(--foreground)] transition-all disabled:opacity-50 relative z-10 w-full"
                            style={{ borderRadius: 'var(--radius)' }}
                        >
                            {loading ? 'Activando...' : '¡Activar ahora!'}
                        </button>
                    </div>
                ) : (
                    <>
                        {/* Preferencias */}
                        <div className="space-y-2">
                            <ToggleOption
                                icon="⚽"
                                label="Inicio de partido"
                                description="Al arrancar un partido pronosticado"
                                enabled={prefs.partidoInicio}
                                onToggle={() => togglePref('partidoInicio')}
                            />
                            <ToggleOption
                                icon="❤️"
                                label="Goles en vivo"
                                description="Instantánea cuando hay goles"
                                enabled={prefs.golFavorito}
                                onToggle={() => togglePref('golFavorito')}
                            />
                            <ToggleOption
                                icon="👤"
                                label="Seguidores"
                                description="Cuando alguien te sigue"
                                enabled={prefs.nuevosSeguidores}
                                onToggle={() => togglePref('nuevosSeguidores')}
                            />
                            <ToggleOption
                                icon="🎖️"
                                label="Insignias"
                                description="Al desbloquear medallas"
                                enabled={prefs.insignias}
                                onToggle={() => togglePref('insignias')}
                            />
                            <ToggleOption
                                icon="🎯"
                                label="Prode"
                                description="Saber puntos al finalizar"
                                enabled={prefs.resultadoProde}
                                onToggle={() => togglePref('resultadoProde')}
                            />
                        </div>

                        {/* Estado activo */}
                        <div className="pt-3 border-t border-[var(--card-border)] border-dashed">
                            <p className="text-[9px] text-[#16a34a] flex items-center gap-2 font-black capitalize">
                                <span className="w-1.5 h-1.5 bg-[#16a34a] rounded-full"></span>
                                Notificaciones activas
                            </p>
                        </div>
                    </>
                )}
            </div>
        </div>
    )
}

function ToggleOption({
    icon,
    label,
    description,
    enabled,
    onToggle
}: {
    icon: string
