// src/components/ProdeStats.tsx
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { motion } from 'framer-motion'

interface Stats {
    puntos_totales: number
    partidos_jugados: number
    aciertos_exactos: number
    aciertos_ganador_diferencia: number
    aciertos_ganador: number
    posicion: number
}

export function ProdeStats() {
    const { user } = useAuth()
    const [stats, setStats] = useState<Stats | null>(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (user) fetchStats()
    }, [user])

    const fetchStats = async () => {
        try {
            // Obtener stats del usuario
            const { data: rankingData, error } = await supabase
                .from('ranking_prode')
                .select('*')
                .eq('user_id', user?.id)
                .single()

            if (error && error.code !== 'PGRST116') throw error // PGRST116 = no rows

            // Obtener posición
            let posicion = 0
            if (rankingData) {
                const { count } = await supabase
                    .from('ranking_prode')
                    .select('*', { count: 'exact', head: true })
                    .gt('puntos_totales', rankingData.puntos_totales)

                posicion = (count || 0) + 1
            }

            setStats(rankingData ? { ...rankingData, posicion } : null)
        } catch (err: any) {
            console.error('Error fetching stats:', err)
        } finally {
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-6 animate-pulse" style={{ borderRadius: 'var(--radius)' }}>
                <div className="h-4 bg-[var(--background)] w-1/2 mb-4" style={{ borderRadius: 'var(--radius)' }}></div>
                <div className="h-8 bg-[var(--background)] w-1/3" style={{ borderRadius: 'var(--radius)' }}></div>
            </div>
        )
    }

    if (!stats) {
        return (
            <div className="bg-[var(--card-bg)] border border-[var(--card-border)] p-8 rounded-3xl shadow-sm text-center">
                <span className="text-5xl mb-4 block">🎯</span>
                <h3 className="text-xl font-bold mb-2 tracking-tight">¡EMPEZÁ A PRONOSTICAR!</h3>
                <p className="text-sm text-[var(--text-muted)] font-medium max-w-[200px] mx-auto">
                    Predecí los resultados y sumá puntos en el ranking global.
                </p>
            </div>
        )
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-[var(--card-bg)] border border-[var(--card-border)] p-6 rounded-3xl shadow-sm"
        >
            <div className="flex items-center justify-between mb-6">
                <h3 className="text-xs font-bold text-[var(--text-muted)] capitalize tracking-tight flex items-center gap-2">
                    📊 Estadísticas
                </h3>
                {stats.posicion > 0 && (
                    <div className="flex items-center gap-1.5 bg-[var(--accent-green)]/10 text-[var(--accent-green)] px-3 py-1 rounded-full border border-[var(--accent-green)]/20 shadow-sm">
                        <span className="text-[10px] capitalize font-bold tracking-tight">Pos #{stats.posicion}</span>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div className="text-center">
                    <div className="text-4xl font-bold text-[var(--foreground)] tabular-nums tracking-tighter">{stats.puntos_totales}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Puntos</div>
                </div>
                <div className="text-center">
                    <div className="text-4xl font-bold tracking-tighter">{stats.partidos_jugados}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Partidos</div>
                </div>
            </div>

            <div className="mt-6 pt-6 border-t border-[var(--card-border)] grid grid-cols-3 gap-2 text-center">
                <div>
                    <div className="text-xl font-bold text-[var(--accent-green)]">{stats.aciertos_exactos}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Exactos</div>
                </div>
                <div>
                    <div className="text-xl font-bold text-blue-500">{stats.aciertos_ganador_diferencia}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Gan+Dif</div>
                </div>
                <div>
                    <div className="text-xl font-bold text-[var(--foreground)]">{stats.aciertos_ganador}</div>
                    <div className="text-[10px] text-[var(--text-muted)] font-bold capitalize tracking-tight">Ganador</div>
                </div>
            </div>
        </motion.div>
    )
}

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import { motion, AnimatePresence } from 'framer-motion'
import { useRouter } from 'next/navigation'

interface SearchBarProps {
    value: string
    onChange: (value: string) => void
    placeholder?: string
}

export function SearchBar({ value, onChange, placeholder = 'Buscar hincha o equipo...' }: SearchBarProps) {
    const [isFocused, setIsFocused] = useState(false)
    const [suggestions, setSuggestions] = useState<any[]>([])
    const [loading, setLoading] = useState(false)
    const router = useRouter()

    useEffect(() => {
        const timer = setTimeout(() => {
            if (value.length >= 2) {
                fetchSuggestions(value)
            } else {
                setSuggestions([])
            }
        }, 200)

        return () => clearTimeout(timer)
    }, [value])

    const fetchSuggestions = async (query: string) => {
        setLoading(true)
        const { data } = await supabase
            .from('profiles')
            .select('id, username, avatar_url')
            .ilike('username', `%${query}%`)
            .limit(5)

        setSuggestions(data || [])
        setLoading(false)
    }

    return (
        <div className="relative w-full max-w-md">
            <div className={`
        relative flex items-center gap-3 px-4 py-3 rounded-xl
        bg-[var(--card-bg)] border transition-all duration-200
        ${isFocused
                    ? 'border-[var(--accent)] shadow-lg shadow-[var(--accent)]/10'
                    : 'border-[var(--card-border)] hover:border-[var(--hover-bg)]'
                }
      `}>
                {/* Search Icon */}
                <span className="text-xl">🔍</span>

                {/* Input */}
                <input
                    type="text"
                    value={value}
                    onChange={(e) => onChange(e.target.value)}
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => setIsFocused(false)}
                    placeholder={placeholder}
                    className="flex-1 bg-transparent text-[var(--foreground)] placeholder-[var(--text-muted)] 
                     outline-none text-sm font-medium"
                />

                {/* Clear Button */}
                {value && (
                    <button
                        onClick={() => onChange('')}
                        className="text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                        aria-label="Limpiar búsqueda"
                    >
                        <span className="text-lg">✕</span>
                    </button>
                )}
            </div>

            {/* Suggestions Autocomplete */}
            <AnimatePresence>
                {isFocused && (suggestions.length > 0 || loading) && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="absolute top-full mt-2 left-0 right-0 bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl shadow-2xl z-50 overflow-hidden"
                    >
                        {loading ? (
                            <div className="p-4 text-center text-xs text-[var(--text-muted)] animate-pulse">
                                Buscando...
                            </div>
                        ) : (
                            <div className="py-2">
                                {suggestions.map(s => (
                                    <button
                                        key={s.id}
                                        onMouseDown={() => router.push(`/perfil/${s.id}`)}
                                        className="w-full flex items-center gap-3 px-4 py-3 hover:bg-[var(--hover-bg)] transition-colors text-left"
                                    >
                                        <div className="w-8 h-8 rounded-full bg-[var(--hover-bg)] overflow-hidden flex items-center justify-center text-xs font-bold">
                                            {s.avatar_url ? <img src={s.avatar_url} className="w-full h-full object-cover" /> : s.username[0]}
                                        </div>
                                        <span className="text-sm font-medium">{s.username}</span>
                                    </button>
                                ))}
                            </div>
                        )}
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    )
}

// src/components/TeamForm.tsx
'use client'

import { useState, useEffect } from 'react'
import { supabase } from '@/lib/supabase'

interface TeamFormProps {
    equipo: string
    compact?: boolean
}

type FormResult = 'V' | 'E' | 'D'

export function TeamForm({ equipo, compact = false }: TeamFormProps) {
    const [form, setForm] = useState<FormResult[]>([])
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        fetchForm()
    }, [equipo])

    const fetchForm = async () => {
        try {
            // Buscar últimos 5 partidos finalizados de este equipo
            const { data, error } = await supabase
                .from('partidos')
                .select('*')
                .or(`equipo_local.eq.${equipo},equipo_visitante.eq.${equipo}`)
                .eq('estado', 'FINALIZADO')
                .order('fecha_inicio', { ascending: false })
                .limit(5)

            if (error) throw error

            const results: FormResult[] = (data || []).map(partido => {
                const esLocal = partido.equipo_local === equipo
                const golesEquipo = esLocal ? partido.goles_local : partido.goles_visitante
                const golesRival = esLocal ? partido.goles_visitante : partido.goles_local

                if (golesEquipo > golesRival) return 'V'
                if (golesEquipo < golesRival) return 'D'
                return 'E'
            })

            // Invertir para mostrar más antiguo primero
            setForm(results.reverse())
        } catch (error) {
            console.error('Error fetching form:', error)
        } finally {
            setLoading(false)
        }
    }

    const getColor = (result: FormResult) => {
        switch (result) {
            case 'V': return 'bg-[#16a34a] text-white'
            case 'E': return 'bg-[#6b7280] text-white'
            case 'D': return 'bg-[#dc2626] text-white'
        }
    }

    if (loading || form.length === 0) return null

    return (
        <div className={`flex gap-0.5 ${compact ? '' : 'justify-center'}`}>
            {form.map((result, idx) => (
                <span
                    key={idx}
                    className={`${getColor(result)} ${compact ? 'w-4 h-4 text-[8px]' : 'w-5 h-5 text-[9px]'} 
                               rounded-sm flex items-center justify-center font-black`}
                    title={result === 'V' ? 'Victoria' : result === 'E' ? 'Empate' : 'Derrota'}
                >
                    {result}
                </span>
            ))}
        </div>
    )
}

// src/components/TeamLogo.tsx
'use client'

import { useState, useEffect } from 'react'
import Image from 'next/image'
import { getShieldForTeam } from '@/lib/shields'

interface TeamLogoProps {
    src?: string
    teamName: string
    size?: number
    className?: string
}

// Generar color basado en nombre del equipo
const stringToColor = (str: string) => {
    let hash = 0
    for (let i = 0; i < str.length; i++) {
        hash = str.charCodeAt(i) + ((hash << 5) - hash)
    }
    const hue = Math.abs(hash % 360)
    return `hsl(${hue}, 70%, 45%)`
}

// Obtener iniciales del equipo
const getInitials = (name: string) => {
    const words = name.split(' ')
    if (words.length >= 2) {
        return (words[0][0] + words[1][0]).toUpperCase()
    }
    return name.substring(0, 2).toUpperCase()
}

export function TeamLogo({ src, teamName, size = 24, className = '' }: TeamLogoProps) {
    const [hasError, setHasError] = useState(false)
    const [isLoading, setIsLoading] = useState(true)

    // Only recalculate on mount or prop change
    const [finalSrc, setFinalSrc] = useState<string | undefined>(undefined)

    useEffect(() => {
        // Evaluate the safe shield URL using our map
        const safeShield = getShieldForTeam(teamName, src)
        setFinalSrc(safeShield)
        setHasError(false)
        setIsLoading(true)
    }, [src, teamName])

    const initials = getInitials(teamName)
    const bgColor = stringToColor(teamName)

    // Si no hay src o hubo error, mostrar fallback
    if (!finalSrc || hasError) {
        return (
            <div
                className={`flex items-center justify-center rounded-full font-bold text-white shadow-inner ${className}`}
                style={{
                    width: size,
                    height: size,
                    backgroundColor: bgColor,
                    fontSize: size * 0.4
                }}
            >
                {initials}
            </div>
        )
    }

    return (
        <div className={`relative ${className}`} style={{ width: size, height: size }}>
            {isLoading && (
                <div
                    className="absolute inset-0 rounded-full bg-[var(--card-border)] animate-pulse"
                />
            )}
            <Image
                src={finalSrc}
                alt={teamName}
                fill
                className="object-contain"
                sizes={`${size}px`}
                onLoad={() => setIsLoading(false)}
                onError={() => {
                    setHasError(true)
                    setIsLoading(false)
                }}
                unoptimized // External shield API URLs can be slow to optimize
            />
        </div>
    )
}

// src/components/TopPartidos.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Plus, X, Search, Trophy, ChevronDown, ChevronUp } from 'lucide-react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/contexts/AuthContext'
import { TeamLogo } from './TeamLogo'
import type { Partido } from '@/types'

interface FavMatch {
    id: string
    user_id: string
    partido_id?: string
    equipo_local: string
    equipo_visitante: string
    logo_local?: string
    logo_visitante?: string
    goles_local?: number
    goles_visitante?: number
    liga?: string
    fecha?: string
    position: number // 1-4
    motivo?: string  // why it's memorable
}

interface TopPartidosProps {
    userId: string
    editable?: boolean
}

export function TopPartidos({ userId, editable = false }: TopPartidosProps) {
    const { user } = useAuth()
    const [favorites, setFavorites] = useState<FavMatch[]>([])
    const [loading, setLoading] = useState(true)
    const [adding, setAdding] = useState(false)
    const [searchQuery, setSearchQuery] = useState('')
    const [searchResults, setSearchResults] = useState<Partido[]>([])
    const [searching, setSearching] = useState(false)
    const [expanded, setExpanded] = useState(false)

    const isOwner = user?.id === userId

    useEffect(() => {
        fetchFavorites()
    }, [userId])

    const fetchFavorites = async () => {
        try {
            const { data } = await supabase
                .from('partidos_favoritos')
                .select('*')
                .eq('user_id', userId)
                .order('position', { ascending: true })
                .limit(4)

            setFavorites(data || [])
        } catch {
            console.log('Favoritos no disponibles')
        } finally {
            setLoading(false)
        }
    }

    useEffect(() => {
        if (!searchQuery || searchQuery.length < 2) {
            setSearchResults([])
            return
        }

        const timeout = setTimeout(async () => {
            setSearching(true)
            try {
                const { data } = await supabase
                    .from('partidos')
                    .select('*')
                    .or(`equipo_local.ilike.%${searchQuery}%,equipo_visitante.ilike.%${searchQuery}%`)
                    .order('fecha_inicio', { ascending: false })
                    .limit(8)

                setSearchResults(data || [])
            } catch {
                setSearchResults([])
            } finally {
                setSearching(false)
            }
        }, 300)

        return () => clearTimeout(timeout)
    }, [searchQuery])

    const addFavorite = async (partido: Partido) => {
        if (!user || favorites.length >= 4) return

        const newFav: Partial<FavMatch> = {
            user_id: user.id,
            partido_id: String(partido.id),
            equipo_local: partido.equipo_local,
            equipo_visitante: partido.equipo_visitante,
            logo_local: partido.logo_local,
            logo_visitante: partido.logo_visitante,
            goles_local: partido.goles_local,
            goles_visitante: partido.goles_visitante,
            liga: partido.liga,
            fecha: partido.fecha_inicio,
            position: favorites.length + 1,
        }

        const { data, error } = await supabase
            .from('partidos_favoritos')
            .insert(newFav)
            .select()
            .single()

        if (!error && data) {
            setFavorites(prev => [...prev, data])
            setAdding(false)
            setSearchQuery('')
            setSearchResults([])
        }
    }

    const removeFavorite = async (favId: string) => {
        await supabase.from('partidos_favoritos').delete().eq('id', favId)
        setFavorites(prev => prev.filter(f => f.id !== favId))
    }

    if (loading) return null

    return (
        <div className="bg-[var(--card-bg)] border border-[var(--card-border)] rounded-2xl p-5">
            <div className="flex items-center justify-between mb-3">
                <h3 className="text-sm font-bold flex items-center gap-2">
                    <Trophy size={14} className="text-[#f59e0b]" />
                    Top Partidos
                    <span className="text-xs font-normal text-[var(--text-muted)]">{favorites.length}/4</span>
                </h3>
                {favorites.length > 0 && (
                    <button
                        onClick={() => setExpanded(!expanded)}
                        className="text-xs text-[var(--text-muted)] hover:text-[var(--foreground)] transition-colors"
                    >
                        {expanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                    </button>
                )}
            </div>

            {favorites.length === 0 && !editable && (
                <p className="text-xs text-[var(--text-muted)]">Aún no tiene partidos favoritos</p>
            )}

            {/* Favorite matches grid */}
            <div className={`space-y-2 ${!expanded && favorites.length > 2 ? 'max-h-32 overflow-hidden' : ''}`}>
                <AnimatePresence>
                    {favorites.map((fav, i) => (
                        <motion.div
                            key={fav.id}
                            initial={{ opacity: 0, scale: 0.95 }}
                            animate={{ opacity: 1, scale: 1 }}
                            exit={{ opacity: 0, scale: 0.95 }}
                            className="flex items-center gap-2.5 p-2.5 rounded-xl bg-[var(--background)] border border-[var(--card-border)] group"
                        >
                            <span className="text-[10px] font-black text-[#f59e0b] w-5 text-center">#{i + 1}</span>
                            <TeamLogo src={fav.logo_local} teamName={fav.equipo_local} size={18} />
                            <div className="flex-1 min-w-0">
                                <div className="text-[11px] font-semibold truncate">
                                    {fav.equipo_local} vs {fav.equipo_visitante}
                                </div>
                                <div className="text-[9px] text-[var(--text-muted)]">
                                    {fav.goles_local != null && `${fav.goles_local}-${fav.goles_visitante} · `}
                                    {fav.liga}
                                </div>
                            </div>
                            <TeamLogo src={fav.logo_visitante} teamName={fav.equipo_visitante} size={18} />
                            {editable && isOwner && (
                                <button
                                    onClick={() => removeFavorite(fav.id)}
                                    className="p-1 text-[var(--text-muted)] hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                                >
                                    <X size={12} />
                                </button>
                            )}
                        </motion.div>
                    ))}
                </AnimatePresence>
            </div>

            {/* Add button */}
            {editable && isOwner && favorites.length < 4 && (
                <div className="mt-3">
                    {!adding ? (
                        <button
                            onClick={() => setAdding(true)}
                            className="w-full flex items-center justify-center gap-1.5 py-2 rounded-xl border-2 border-dashed border-[var(--card-border)]
                       text-xs text-[var(--text-muted)] hover:border-[#f59e0b]/30 hover:text-[#f59e0b] transition-all"
                        >
                            <Plus size={14} /> Agregar partido memorable
                        </button>
                    ) : (
                        <div className="space-y-2">
                            <div className="relative">
                                <Search size={14} className="absolute left-3 top-2.5 text-[var(--text-muted)]" />
                                <input
                                    type="text"
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    placeholder="Buscar partido..."
                                    autoFocus
                                    className="w-full pl-9 pr-8 py-2 bg-[var(--input-bg)] border border-[var(--card-border)] rounded-xl text-xs
                           focus:outline-none focus:border-[#f59e0b]/50"
                                />
                                <button onClick={() => { setAdding(false); setSearchQuery('') }}
                                    className="absolute right-2 top-2 text-[var(--text-muted)]">
                                    <X size={14} />
                                </button>
                            </div>

                            {searchResults.length > 0 && (
                                <div className="space-y-1 max-h-40 overflow-y-auto">
                                    {searchResults.map(p => (
                                        <button
                                            key={p.id}
                                            onClick={() => addFavorite(p)}
                                            className="w-full flex items-center gap-2 p-2 rounded-lg text-left text-xs
                               hover:bg-[var(--hover-bg)] transition-colors"
                                        >
                                            <TeamLogo src={p.logo_local} teamName={p.equipo_local} size={16} />
                                            <span className="flex-1 truncate">{p.equipo_local} vs {p.equipo_visitante}</span>
                                            {p.goles_local != null && (
                                                <span className="text-[var(--text-muted)]">{p.goles_local}-{p.goles_visitante}</span>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            )}
        </div>
    )
}

'use client'

import { Target, CheckCircle2, Zap, Flame, Trophy } from 'lucide-react'
import { motion } from 'framer-motion'
import { useAuth } from '@/contexts/AuthContext'
import { useWeeklyChallenges } from '@/hooks/useWeeklyChallenges'

function PenLineIcon(props: any) {
    return (
        <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20h9"></path><path d="M16.5 3.5a2.12 2.12 0 0 1 3 3L7 19l-4 1 1-4 Z"></path></svg>
    )
}

export function WeeklyChallenges() {
    const { user } = useAuth()
    const { challenges, loading, completedCount, totalXP } = useWeeklyChallenges()

    if (loading) {
        return (
            <div className="space-y-4">
                {[1, 2, 3].map(i => (
                    <div key={i} className="h-24 bg-[var(--card-border)]/10 animate-pulse rounded-2xl" />
                ))}
            </div>
        )
    }

    const getIcon = (id: string) => {
        if (id.includes('c1')) return Flame
        if (id.includes('c2')) return PenLineIcon
        return Target
    }

    return (
        <div className="bg-[var(--card-bg)] rounded-xl border border-[var(--card-border)] overflow-hidden">
            {/* Header */}
            <div className="px-5 py-4 border-b border-[var(--card-border)] bg-[var(--background)]/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="p-1.5 bg-[#f59e0b]/10 rounded-lg text-[#f59e0b]">
                        <Trophy size={18} />
                    </div>
                    <h3 className="font-black tracking-wide text-[var(--foreground)]">DESAFÍOS SEMANALES</h3>
                </div>
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-[var(--accent)]/10 rounded-full text-[var(--accent)] font-bold text-xs border border-[var(--accent)]/20">
                    <Zap size={12} className="fill-[var(--accent)]" />
                    +{totalXP} XP
                </div>
            </div>

            {/* Progress Recap */}
            <div className="px-5 py-4 flex items-center gap-4 bg-gradient-to-r from-[var(--hover-bg)] to-transparent">
                <div className="relative w-14 h-14 flex items-center justify-center shrink-0">
                    <svg className="w-full h-full transform -rotate-90">
                        <circle cx="28" cy="28" r="26" stroke="currentColor" strokeWidth="4" fill="none" className="text-[var(--card-border)]" />
                        <circle
                            cx="28" cy="28" r="26" stroke="currentColor" strokeWidth="4" fill="none"
                            strokeDasharray="163"
                            strokeDashoffset={163 - (163 * (completedCount || 0)) / (challenges?.length || 1)}
                            className="text-[#f59e0b] transition-all duration-1000"
                            strokeLinecap="round"
                        />
                    </svg>
                    <div className="absolute inset-0 flex items-center justify-center flex-col">
                        <span className="text-sm font-black">{completedCount}/{challenges?.length}</span>
                    </div>
                </div>
                <div>
                    <h4 className="font-bold text-sm">Progreso de la Semana</h4>
                    <div className="text-xs mt-1">
                        {completedCount === challenges?.length && challenges?.length > 0
                            ? <span className="text-[var(--text-muted)]">Completaste todos los desafíos de la semana.</span>
                            : user && completedCount === 0 && challenges?.some(c => c.current === 0)
                                ? (
                                    <div className="mt-2 text-left">
                                        <p className="text-[var(--text-muted)] mb-2">Todavía no completaste desafíos esta semana. Empezá ahora: rateá un partido o hacé un prode para desbloquear tu primer badge.</p>
                                        <a href="/" className="inline-block px-3 py-1.5 bg-[var(--accent)] text-white rounded-lg font-bold text-[10px] hover:opacity-90 transition-colors">
                                            Ir a partidos recientes →
                                        </a>
                                    </div>
                                )
                                : <span className="text-[var(--text-muted)]">Ganá XP extra para subir de nivel más rápido.</span>}
                    </div>
                </div>
            </div>

            {/* Quests List */}
            <div className="p-2 space-y-1">
                {challenges?.map((challenge, idx) => {
                    const isCompleted = challenge.current >= challenge.target
                    const progressPercent = Math.min((challenge.current / challenge.target) * 100, 100)
                    const Icon = getIcon(challenge.id)

                    return (
                        <motion.div
                            key={challenge.id}
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: idx * 0.1 }}
                            className={`p-3 flex items-center gap-4 transition-all border border-dashed
                ${isCompleted ? 'bg-[var(--foreground)] text-[var(--background)] border-[var(--foreground)]' : 'bg-transparent border-[var(--card-border)]'}
              `}
                            style={{ borderRadius: 'var(--radius)' }}
                        >
                            {/* Icon */}
                            <div className={`w-10 h-10 flex items-center justify-center shrink-0
                ${isCompleted ? 'bg-[var(--background)] text-[var(--foreground)]' : 'bg-[var(--hover-bg)] text-[var(--text-muted)]'}
              `} style={{ borderRadius: 'var(--radius)' }}>
                                {isCompleted ? <CheckCircle2 size={18} className="font-black" /> : <Icon size={18} />}
                            </div>

                            {/* Text */}
                            <div className="flex-1 min-w-0">
                                <h5 className={`text-[11px] font-black capitalize tracking-tight truncate ${isCompleted ? 'opacity-90 line-through' : ''}`}>
                                    {challenge.title}
                                </h5>
                                <p className={`text-[9px] capitalize font-bold truncate mb-1.5 ${isCompleted ? 'opacity-70' : 'text-[var(--text-muted)]'}`}>{challenge.description}</p>

                                {/* Progress Bar */}
                                <div className="flex items-center gap-2">
                                    <div className="flex-1 h-1.5 bg-[var(--background)] border border-[var(--card-border)] overflow-hidden">
                                        <motion.div
                                            initial={{ width: 0 }}
                                            animate={{ width: `${progressPercent}%` }}
                                            transition={{ duration: 1, delay: 0.2 }}
                                            className={`h-full ${isCompleted ? 'bg-[var(--background)]' : 'bg-[#f59e0b]'}`}
                                        />
                                    </div>
                                    <span className={`text-[9px] font-black tabular-nums whitespace-nowrap capitalize ${isCompleted ? 'opacity-90' : 'text-[var(--text-muted)]'}`}>
                                        {challenge.current} / {challenge.target}
                                    </span>
                                </div>
                            </div>

                            {/* Reward Badge */}
                            <div className={`px-2 py-1 text-[9px] font-black border shrink-0 capitalize tracking-widest
                 ${isCompleted
                                    ? 'bg-[var(--background)] text-[var(--foreground)] border-[var(--background)] opacity-80'
                                    : 'bg-[var(--background)] text-[#f59e0b] border-[#f59e0b]/30'
                                }
              `} style={{ borderRadius: 'var(--radius)' }}>
                                {challenge.xpReward} XP
                            </div>
                        </motion.div>
                    )
                })}
            </div>
        </div>
    )
}

