                                                 <div className="col-span-full py-10 text-center bg-[var(--card-bg)] rounded-3xl border border-dashed border-[var(--card-border)] opacity-50">
                                                     <p className="text-xs font-bold italic">Aún no hay votos para los premios</p>
                                                 </div>
                                             )}
                                          </div>
                                    </div>
                                )}
                            </motion.div>
                        </AnimatePresence>
                    )}
                </div>
            </div>

            {/* Individual 1-10 Vote Modal */}
            <AnimatePresence>
                {votandoA && (
                    <VotarModal
                        jugador={votandoA}
                        onVotar={handleVotar}
                        onClose={() => setVotandoA(null)}
                    />
                )}
            </AnimatePresence>

            {/* Quick 1-10 Vote Modal */}
            <AnimatePresence>
                {showRapida && (
                    <VotacionRapida
                        jugadores={jugadores}
                        onVotarTodos={handleVotarTodos}
                        onClose={() => setShowRapida(false)}
                    />
                )}
            </AnimatePresence>

            {/* Modal agregar jugador (Lineup) */}
            <AnimatePresence>
                {equipoAgregando && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[70] flex items-center justify-center p-4"
                        onClick={() => setEquipoAgregando(null)}
                    >
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            exit={{ scale: 0.9, opacity: 0 }}
                            className="bg-[var(--card-bg)] rounded-3xl p-6 w-full max-w-sm border border-[var(--card-border)] shadow-2xl"
                            onClick={e => e.stopPropagation()}
                        >
                            <h4 className="text-xl font-black mb-1 italic">➕ Agregar Jugador</h4>
                            <p className="text-xs text-[var(--text-muted)] mb-6 uppercase tracking-widest font-bold">
                                Equipo {equipoAgregando === 'azul' ? '🔵 Azul' : '🔴 Rojo'}
                            </p>

                            <div className="space-y-4">
                                <div>
                                    <label className="text-[10px] font-black uppercase tracking-widest text-[var(--text-muted)] mb-2 block">Seleccionar Miembro</label>
                                    <div className="max-h-40 overflow-y-auto border border-[var(--card-border)] rounded-2xl bg-[var(--background)] p-2 space-y-1">
                                        {miembros.map(m => (
                                            <button
                                                key={m.user_id}
                                                onClick={() => {
                                                    setNuevoNombre(m.profile?.username || 'Usuario');
                                                    setSelectedUserId(m.user_id);
                                                }}
                                                className={`w-full text-left p-3 rounded-xl text-xs flex items-center gap-3 transition-all ${
                                                    selectedUserId === m.user_id 
                                                    ? 'bg-[#16a34a] text-white font-bold' 
                                                    : 'hover:bg-[var(--hover-bg)]'
                                                }`}
                                            >
                                                <div className="w-6 h-6 rounded-full bg-white/20 flex items-center justify-center text-[10px]">
                                                    {m.profile?.username?.[0].toUpperCase()}
                                                </div>
                                                {m.profile?.username}
                                            </button>
                                        ))}
                                    </div>
                                </div>

                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <UserPlus size={16} className="text-[var(--text-muted)]" />
                                    </div>
                                    <input
                                        type="text"
                                        value={nuevoNombre}
                                        onChange={e => {
                                            setNuevoNombre(e.target.value);
                                            setSelectedUserId(null);
                                        }}
                                        onKeyDown={e => e.key === 'Enter' && handleAgregarJugador()}
                                        placeholder="O nombre de invitado..."
                                        className="w-full bg-[var(--input-bg)] border border-[var(--card-border)] rounded-2xl p-4 pl-10 text-sm focus:outline-none focus:ring-2 focus:ring-[#16a34a]/50 transition-all"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3 mt-8">
                                <button
                                    onClick={() => { setEquipoAgregando(null); setNuevoNombre(''); setSelectedUserId(null); setOrdenAgregando(null) }}
                                    className="flex-1 py-4 rounded-2xl text-[var(--text-muted)] font-black uppercase tracking-widest text-xs hover:bg-[var(--hover-bg)] transition-all"
                                >Cancelar</button>
                                <button
                                    onClick={handleAgregarJugador}
                                    disabled={!nuevoNombre.trim() || guardando}
                                    className="flex-1 py-4 rounded-2xl font-black text-white bg-[#16a34a] disabled:opacity-40 uppercase tracking-widest text-xs shadow-lg shadow-[#16a34a]/20 transition-all"
                                >{guardando ? '⏳' : 'Agregar'}</button>
                            </div>
                        </motion.div>
                    </motion.div>
                )}
            </AnimatePresence>
        </motion.div>
    )
}

// src/components/grupos/ResultadosPartidoAmigo.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import { DetalleJugadorAmigo } from './DetalleJugadorAmigo'
import type { PartidoAmigo, JugadorPartidoAmigo } from '@/types'

interface ResultadosProps {
    partido: PartidoAmigo
    grupoId: string
    onClose: () => void
}

export function ResultadosPartidoAmigo({ partido, grupoId, onClose }: ResultadosProps) {
    const { fetchJugadoresConVotos } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()
    const [jugadores, setJugadores] = useState<JugadorPartidoAmigo[]>([])
    const [loading, setLoading] = useState(true)
    const [jugadorDetalle, setJugadorDetalle] = useState<JugadorPartidoAmigo | null>(null)

    useEffect(() => {
        loadResultados()
    }, [partido.id])

    const loadResultados = async () => {
        try {
            const data = await fetchJugadoresConVotos(partido.id)
            setJugadores(data)
        } catch {
            showToast('Error cargando resultados', 'error')
        } finally {
            setLoading(false)
        }
    }

    const sorted = [...jugadores].sort((a, b) => (b.promedio || 0) - (a.promedio || 0))
    const mvp = sorted[0]
    const top3 = sorted.slice(0, 3)
    const azules = jugadores.filter(j => j.equipo === 'azul').sort((a, b) => (b.promedio || 0) - (a.promedio || 0))
    const rojos = jugadores.filter(j => j.equipo === 'rojo').sort((a, b) => (b.promedio || 0) - (a.promedio || 0))

    const promedioEquipo = (equipo: JugadorPartidoAmigo[]) => {
        const conVotos = equipo.filter(j => (j.promedio || 0) > 0)
        if (conVotos.length === 0) return 0
        return Math.round(conVotos.reduce((sum, j) => sum + (j.promedio || 0), 0) / conVotos.length * 10) / 10
    }

    const fechaDisplay = new Date(partido.fecha + 'T00:00:00').toLocaleDateString('es-AR', {
        weekday: 'short', day: 'numeric', month: 'short'
    })

    const resultado = partido.resultado_azul !== undefined && partido.resultado_rojo !== undefined
        ? `Azul ${partido.resultado_azul}-${partido.resultado_rojo} Rojo`
        : null

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="fixed inset-0 bg-[var(--background)] z-[60] overflow-y-auto"
        >
            {/* Header */}
            <div className="bg-gradient-to-b from-[#3b82f6] to-[#2563eb] text-white pt-10 pb-12 px-6 rounded-b-[3rem] shadow-2xl">
                <div className="max-w-lg mx-auto">
                    <button onClick={onClose} className="bg-white/20 p-2 rounded-full mb-6 backdrop-blur-md hover:bg-white/30 transition-all">← Volver</button>
                    <h1 className="text-3xl font-black italic tracking-tighter capitalize mb-2">📊 Estadísticas</h1>
                    <p className="text-white/80 text-sm font-bold capitalize tracking-widest bg-black/20 inline-block px-3 py-1 rounded-full backdrop-blur-sm">
                        {fechaDisplay} • {partido.cancha || 'Partido Amigo'}
                    </p>
                    {resultado && (
                        <div className="mt-8 flex items-center justify-center gap-6 text-4xl font-black italic">
                            <div className="flex flex-col items-center">
                                <span className="text-xs capitalize tracking-[0.3em] font-black text-white/60 mb-2">AZUL</span>
                                <span>{partido.resultado_azul}</span>
                            </div>
                            <div className="text-white/30 text-2xl">VS</div>
                            <div className="flex flex-col items-center">
                                <span className="text-xs capitalize tracking-[0.3em] font-black text-white/60 mb-2">ROJO</span>
                                <span>{partido.resultado_rojo}</span>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {loading ? (
                <div className="text-center py-20 font-black italic capitalize tracking-widest text-[var(--text-muted)] animate-pulse">Cargando resultados...</div>
            ) : (
                <div className="max-w-lg mx-auto px-4 -mt-6 pb-20 space-y-6">
                    {/* MVP */}
                    {mvp && mvp.promedio! > 0 && (
                        <motion.div
                            initial={{ scale: 0.9, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            transition={{ delay: 0.2, type: 'spring' }}
                            className="bg-gradient-to-br from-amber-400 to-amber-600 rounded-[2.5rem] p-8 text-center shadow-2xl relative overflow-hidden group shadow-amber-500/30"
                        >
                            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-16 translate-x-16" />
                            <p className="text-[10px] text-white/80 capitalize font-black tracking-[0.4em] mb-4">MEMBER OF THE MATCH</p>
                            <div className="relative inline-block mb-4">
                                <div className="absolute inset-0 bg-white/20 blur-xl rounded-full" />
                                <div className="text-5xl relative">👑</div>
                            </div>
                            <h2 className="text-3xl font-black text-white italic tracking-tighter capitalize">{mvp.nombre}</h2>
                            <p className="text-4xl font-black text-white mt-2 drop-shadow-lg">⭐ {mvp.promedio}</p>
                            <p className="text-[10px] text-white/80 font-bold capitalize mt-4">{mvp.total_votos} VOTOS EN TOTAL</p>
                        </motion.div>
                    )}

                    {/* Team Results */}
                    <TeamResults
                        equipo="azul"
                        color="#3b82f6"
                        emoji="🔵"
                        jugadores={azules}
                        promedio={promedioEquipo(azules)}
                        onClickJugador={setJugadorDetalle}
                    />

                    <TeamResults
                        equipo="rojo"
                        color="#ef4444"
                        emoji="🔴"
                        jugadores={rojos}
                        promedio={promedioEquipo(rojos)}
                        onClickJugador={setJugadorDetalle}
                    />
                </div>
            )}

            {jugadorDetalle && (
                <DetalleJugadorAmigo
                    jugador={jugadorDetalle}
                    grupoId={grupoId}
                    onClose={() => setJugadorDetalle(null)}
                />
            )}
        </motion.div>
    )
}

function TeamResults({ equipo, color, emoji, jugadores, promedio, onClickJugador }: {
    equipo: string
    color: string
    emoji: string
    jugadores: JugadorPartidoAmigo[]
    promedio: number
    onClickJugador: (j: JugadorPartidoAmigo) => void
}) {
    return (
        <div className="bg-[var(--card-bg)] rounded-[2rem] border border-[var(--card-border)] overflow-hidden shadow-xl">
            <div className="p-5 border-b border-[var(--card-border)] bg-[var(--background)]/50" style={{ borderLeftColor: color, borderLeftWidth: 6 }}>
                <div className="flex justify-between items-end">
                    <div>
                        <h3 className="text-xs font-black capitalize tracking-[0.2em] mb-1" style={{ color }}>
                            {emoji} EQUIPO {equipo.toUpperCase()}
                        </h3>
                        <p className="text-2xl font-black italic tracking-tighter">ESTADÍSTICAS</p>
                    </div>
                    <div className="text-right">
                        <span className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest">PROM EQUIPO</span>
                        <p className="text-xl font-black" style={{ color }}>{promedio}</p>
                    </div>
                </div>
            </div>
            <div>
                {jugadores.map((j, i) => (
                    <button
                        key={j.id}
                        onClick={() => onClickJugador(j)}
                        className={`w-full flex items-center gap-4 p-5 border-b border-[var(--card-border)] last:border-0 hover:bg-[var(--hover-bg)] transition-all text-left ${i === 0 ? 'bg-amber-400/5' : ''}`}
                    >
                        <span className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-black ${i === 0 ? 'bg-amber-400 text-amber-900 shadow-md' : 'bg-[var(--background)] text-[var(--text-muted)]'}`}>
                            {i + 1}
                        </span>
                        <div className="flex-1 min-w-0">
                            <span className="font-bold text-sm block">
                                {i === 0 && '👑 '}{j.nombre}
                            </span>
                            <div className="w-full h-1.5 bg-[var(--background)] rounded-full mt-2 overflow-hidden shadow-inner">
                                <motion.div
                                    initial={{ width: 0 }}
                                    animate={{ width: `${((j.promedio || 0) / 10) * 100}%` }}
                                    transition={{ duration: 0.8 }}
                                    className="h-full rounded-full"
                                    style={{ backgroundColor: color }}
                                />
                            </div>
                        </div>
                        <div className="text-right">
                            <span className="text-sm font-black italic" style={{ color }}>{j.promedio || '-'}</span>
                            <p className="text-[8px] text-[var(--text-muted)] font-bold capitalize">{j.total_votos} V</p>
                        </div>
                    </button>
                ))}
            </div>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { supabase } from '@/lib/supabase'

interface TablaEstadisticasProps {
    grupoId: string
    miembros: any[]
}

interface EstadisticaJugador {
    userId: string
    nombre: string
    foto?: string
    pj: number
    goles: number
    asistencias: number
    promedio: number
    mvps: number
}

export function TablaEstadisticas({ grupoId, miembros }: TablaEstadisticasProps) {
    const [stats, setStats] = useState<EstadisticaJugador[]>([])
    const [loading, setLoading] = useState(true)
    const [orden, setOrden] = useState<'goles' | 'asistencias' | 'promedio' | 'pj'>('goles')

    useEffect(() => {
        fetchStats()
    }, [grupoId])

    const fetchStats = async () => {
        setLoading(true)
        try {
            const { data: partidos } = await supabase
                .from('partidos_amigos')
                .select('id')
                .eq('grupo_id', grupoId)
                .eq('estado', 'finalizado')

            if (!partidos || partidos.length === 0) {
                setStats([])
                setLoading(false)
                return
            }

            const partidoIds = partidos.map(p => p.id)

            const { data: jugadoresHistorial } = await supabase
                .from('jugadores_partido_amigo')
                .select('user_id, goles, asistencias, nombre')
                .in('partido_amigo_id', partidoIds)
                .not('user_id', 'is', null)

            const { data: votos } = await supabase
                .from('votos_partido_amigo')
                .select('jugador_id, nota, jugadores_partido_amigo!inner(user_id)')
                .in('partido_amigo_id', partidoIds)

            const statsMap: Record<string, EstadisticaJugador> = {}

            miembros.forEach(m => {
                if (m.user_id) {
                    statsMap[m.user_id] = {
                        userId: m.user_id,
                        nombre: m.profile?.username || 'Usuario',
                        foto: m.profile?.avatar_url,
                        pj: 0,
                        goles: 0,
                        asistencias: 0,
                        promedio: 0,
                        mvps: 0
                    }
                }
            })

            jugadoresHistorial?.forEach((j: any) => {
                const uid = j.user_id
                if (!statsMap[uid]) return
                statsMap[uid].pj += 1
                statsMap[uid].goles += (j.goles || 0)
                statsMap[uid].asistencias += (j.asistencias || 0)
            })

            const notasSum: Record<string, number> = {}
            const notasCount: Record<string, number> = {}

            votos?.forEach((v: any) => {
                const uid = v.jugadores_partido_amigo?.user_id
                if (!uid || !statsMap[uid]) return
                notasSum[uid] = (notasSum[uid] || 0) + v.nota
                notasCount[uid] = (notasCount[uid] || 0) + 1
            })

            Object.values(statsMap).forEach(s => {
                if (notasCount[s.userId]) {
                    s.promedio = Number((notasSum[s.userId] / notasCount[s.userId]).toFixed(1))
                }
            })

            setStats(Object.values(statsMap))
        } catch (error) {
            console.error('Error stats', error)
        } finally {
            setLoading(false)
        }
    }

    const sortedStats = [...stats].sort((a, b) => b[orden] - a[orden])

    if (loading) return <div className="text-center py-20 animate-pulse text-[var(--text-muted)] font-bold italic capitalize tracking-widest">Calculando estadísticas...</div>

    if (stats.length === 0) return (
        <div className="text-center py-20 text-[var(--text-muted)] bg-[var(--card-bg)] rounded-2xl border border-[var(--card-border)]">
            <p className="text-4xl mb-4">📉</p>
            <p className="font-bold italic">Aún no hay estadísticas. ¡Jueguen partidos para generar datos!</p>
        </div>
    )

    return (
        <div className="space-y-6">
            <div className="flex gap-2 justify-center pb-2 overflow-x-auto no-scrollbar px-2">
                <FilterButton active={orden === 'goles'} onClick={() => setOrden('goles')} label="⚽ Goles" />
                <FilterButton active={orden === 'asistencias'} onClick={() => setOrden('asistencias')} label="👟 Asistencias" />
                <FilterButton active={orden === 'promedio'} onClick={() => setOrden('promedio')} label="⭐ Promedio" />
                <FilterButton active={orden === 'pj'} onClick={() => setOrden('pj')} label="📅 PJ" />
            </div>

            <div className="bg-[var(--card-bg)] rounded-3xl border border-[var(--card-border)] overflow-hidden shadow-xl">
                <table className="w-full text-sm">
                    <thead className="bg-[#10b981]/10 text-[#10b981]">
                        <tr>
                            <th className="p-4 text-left font-black capitalize italic text-xs">Jugador</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">PJ</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">⚽</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">👟</th>
                            <th className="p-4 text-center font-black capitalize italic text-xs">⭐</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-[var(--card-border)]">
                        {sortedStats.map((s, i) => (
                            <tr key={s.userId} className="hover:bg-[var(--hover-bg)] transition-colors">
                                <td className="p-4 flex items-center gap-3">
                                    <span className="text-[10px] font-black w-4 text-[var(--text-muted)]">#{i + 1}</span>
                                    <div className="w-10 h-10 rounded-full bg-[var(--background)] overflow-hidden border-2 border-[var(--card-border)] flex items-center justify-center shrink-0 shadow-sm">
                                        {s.foto ? <img src={s.foto} alt={s.nombre} className="w-full h-full object-cover" /> : '👤'}
                                    </div>
                                    <span className="font-bold truncate max-w-[120px]">{s.nombre}</span>
                                </td>
                                <td className={`p-4 text-center text-xs ${orden === 'pj' ? 'font-black text-[var(--foreground)]' : 'font-medium text-[var(--text-muted)]'}`}>{s.pj}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'goles' ? 'font-black text-[#10b981]' : 'font-medium text-[var(--text-muted)]'}`}>{s.goles}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'asistencias' ? 'font-black text-blue-400' : 'font-medium text-[var(--text-muted)]'}`}>{s.asistencias}</td>
                                <td className={`p-4 text-center text-xs ${orden === 'promedio' ? 'font-black text-yellow-400' : 'font-medium text-[var(--text-muted)]'}`}>{s.promedio || '-'}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    )
}

function FilterButton({ active, onClick, label }: { active: boolean, onClick: () => void, label: string }) {
    return (
        <button
            onClick={onClick}
            className={`px-4 py-2 rounded-full text-xs font-black capitalize tracking-wider transition-all shadow-sm shrink-0
                ${active ? 'bg-[#10b981] text-white shadow-emerald-500/20' : 'bg-[var(--card-bg)] border border-[var(--card-border)] text-[var(--text-muted)] hover:bg-[var(--hover-bg)]'}`}
        >
            {label}
        </button>
    )
}

// src/components/grupos/VotarJugadores.tsx
'use client'

import { useState, useEffect } from 'react'
import { motion } from 'framer-motion'
import { usePartidosAmigos } from '@/hooks/usePartidosAmigos'
import { useToast } from '@/contexts/ToastContext'
import { VotarModal } from './VotarModal'
import { VotacionRapida } from './VotacionRapida'
import type { PartidoAmigo, JugadorPartidoAmigo } from '@/types'

interface VotarJugadoresProps {
    partido: PartidoAmigo
    grupoId: string
    onClose: () => void
}

export function VotarJugadores({ partido, grupoId, onClose }: VotarJugadoresProps) {
    const { fetchJugadoresConVotos, votarJugador } = usePartidosAmigos(grupoId)
    const { showToast } = useToast()
    const [jugadores, setJugadores] = useState<JugadorPartidoAmigo[]>([])
    const [loading, setLoading] = useState(true)
    const [votandoA, setVotandoA] = useState<JugadorPartidoAmigo | null>(null)
    const [showRapida, setShowRapida] = useState(false)

    useEffect(() => {
        loadJugadores()
    }, [partido.id])

    const loadJugadores = async () => {
        try {
            const data = await fetchJugadoresConVotos(partido.id)
            setJugadores(data)
        } catch {
            showToast('Error cargando jugadores', 'error')
        } finally {
            setLoading(false)
        }
    }

    const handleVotar = async (nota: number, comentario?: string) => {
        if (!votandoA) return
        try {
            await votarJugador(partido.id, votandoA.id, nota, comentario)
            showToast(`Voto guardado para ${votandoA.nombre} ⭐`, 'success')
            await loadJugadores()
        } catch {
            showToast('Error al votar', 'error')
        }
    }

    const handleVotarTodos = async (votos: { jugadorId: string; nota: number }[]) => {
        try {
            for (const v of votos) {
                await votarJugador(partido.id, v.jugadorId, v.nota)
            }
            showToast(`${votos.length} votos guardados ⚡`, 'success')
            await loadJugadores()
        } catch {
            showToast('Error al guardar votos', 'error')
        }
    }

    const azules = jugadores.filter(j => j.equipo === 'azul')
    const rojos = jugadores.filter(j => j.equipo === 'rojo')
    const votados = jugadores.filter(j => j.mi_voto).length
    const total = jugadores.length
    const progreso = total > 0 ? Math.round((votados / total) * 100) : 0

    const fechaDisplay = new Date(partido.fecha + 'T00:00:00').toLocaleDateString('es-AR', {
        weekday: 'short', day: 'numeric', month: 'short'
    })

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-[var(--background)] z-[60] overflow-y-auto"
        >
            {/* Header */}
            <div className="bg-[#16a34a] text-white pt-10 pb-6 px-6 border-b border-black/10">
                <div className="max-w-lg mx-auto">
                    <button onClick={onClose} className="bg-black/20 p-2 mb-3 font-black capitalize tracking-widest text-[10px] hover:bg-black/30 transition-all" style={{ borderRadius: 'var(--radius)' }}>← Volver</button>
                    <h1 className="text-2xl font-black capitalize italic tracking-tighter">🗳️ Votar Jugadores</h1>
                    <p className="text-white/80 text-[10px] font-bold capitalize tracking-widest leading-none mt-1">{fechaDisplay} - {partido.cancha || 'Sin cancha'}</p>
                </div>
            </div>

            <div className="max-w-lg mx-auto px-4 -mt-3 pb-28 space-y-4">
                {/* Progress */}
                <div className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)]" style={{ borderRadius: 'var(--radius)' }}>
                    <div className="flex justify-between text-[10px] font-black capitalize tracking-widest mb-2">
                        <span>📊 Tu Progreso</span>
                        <span className="text-[#16a34a]">{votados}/{total} votados</span>
                    </div>
                    <div className="w-full h-3 bg-[var(--background)] border border-[var(--card-border)] overflow-hidden" style={{ borderRadius: 'var(--radius)' }}>
                        <motion.div
                            initial={{ width: 0 }}
                            animate={{ width: `${progreso}%` }}
                            className="h-full bg-[#16a34a]"
                        />
                    </div>
                    <p className="text-right text-[10px] font-black tabular-nums text-[var(--text-muted)] mt-1">{progreso}%</p>
                </div>

                {loading ? (
                    <div className="text-center py-10 text-[var(--text-muted)]">⏳ Cargando jugadores...</div>
                ) : (
                    <>
                        {/* Equipo Azul */}
                        <TeamVoteSection
                            equipo="azul"
                            color="#3b82f6"
                            emoji="🔵"
                            jugadores={azules}
                            onVotar={setVotandoA}
                        />

                        {/* Equipo Rojo */}
                        <TeamVoteSection
                            equipo="rojo"
                            color="#ef4444"
                            emoji="🔴"
                            jugadores={rojos}
                            onVotar={setVotandoA}
                        />

                        {/* Quick vote CTA */}
                        {votados < total && (
                            <div className="bg-[var(--card-bg)] border border-[#d97706]/30 p-4 text-center" style={{ borderRadius: 'var(--radius)' }}>
                                <p className="text-[10px] font-black capitalize tracking-widest mb-3">⚠️ Te faltan <span className="text-[#d97706]">{total - votados}</span> jugadores</p>
                                <button
                                    onClick={() => setShowRapida(true)}
                                    className="w-full bg-[#d97706] text-white px-6 py-3 font-black capitalize tracking-widest italic text-sm hover:brightness-110 transition-all"
                                    style={{ borderRadius: 'var(--radius)' }}
                                >
                                    ⚡ Votar Todos
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>

            {/* Individual vote modal */}
            {votandoA && (
                <VotarModal
                    jugador={votandoA}
                    onVotar={handleVotar}
                    onClose={() => setVotandoA(null)}
                />
            )}

            {/* Quick vote modal */}
            {showRapida && (
                <VotacionRapida
                    jugadores={jugadores}
                    onVotarTodos={handleVotarTodos}
                    onClose={() => setShowRapida(false)}
                />
            )}
        </motion.div>
    )
}

function TeamVoteSection({ equipo, color, emoji, jugadores, onVotar }: {
    equipo: 'azul' | 'rojo'
    color: string
    emoji: string
    jugadores: JugadorPartidoAmigo[]
    onVotar: (j: JugadorPartidoAmigo) => void
}) {
    return (
        <div>
            <h3 className="font-black text-sm mb-2" style={{ color }}>
                {emoji} EQUIPO {equipo.toUpperCase()}
            </h3>
            <div className="space-y-2">
                {jugadores.map((j, i) => (
                    <motion.div
                        key={j.id}
                        initial={{ x: -20, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        transition={{ delay: i * 0.05 }}
                        className="bg-[var(--card-bg)] p-4 border border-[var(--card-border)]"
                        style={{ borderRadius: 'var(--radius)' }}
                    >
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="font-bold">👤 {j.nombre}</p>
                                {j.mi_voto ? (
                                    <div className="mt-1">
                                        <span className="text-xs">
                                            {Array.from({ length: 10 }, (_, i) => (
                                                <span key={i} className={i < j.mi_voto!.nota ? 'opacity-100' : 'opacity-20'}>⭐</span>
                                            ))}
                                            {' '}{j.mi_voto.nota}/10
                                        </span>
                                        {j.mi_voto.comentario && (
                                            <p className="text-xs text-[var(--text-muted)] mt-0.5">💬 &ldquo;{j.mi_voto.comentario}&rdquo;</p>
                                        )}
                                        <p className="text-[10px] text-[#16a34a] font-black capitalize tracking-widest mt-0.5">✅ Ya votaste</p>
                                    </div>
                                ) : (
                                    <p className="text-[10px] text-[var(--text-muted)] font-black capitalize tracking-widest mt-1">
                                        {'○'.repeat(10)} Sin votar
                                    </p>
                                )}
                            </div>
                            <button
                                onClick={() => onVotar(j)}
                                className={`px-4 py-2 text-xs font-black capitalize tracking-widest transition-all ${j.mi_voto
                                    ? 'bg-[var(--hover-bg)] text-[var(--text-muted)] border border-[var(--card-border)]'
                                    : 'bg-[#16a34a] text-white'
                                    }`}
                                style={{ borderRadius: 'var(--radius)' }}
                            >
                                {j.mi_voto ? 'Editar' : 'Votar →'}
                            </button>
                        </div>
                    </motion.div>
                ))}
            </div>
        </div>
    )
}

